const QUESTIONS = JSON.parse(`[{"id": "mf3_01", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ½ of 20?", "o": ["5", "8", "10", "15"], "a": "10", "e": "Half means divide by 2. 20 ÷ 2 = 10"}, {"id": "mf3_02", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¼ of 16?", "o": ["2", "4", "6", "8"], "a": "4", "e": "Quarter means divide by 4. 16 ÷ 4 = 4"}, {"id": "mf3_03", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¾ of 12?", "o": ["3", "6", "8", "9"], "a": "9", "e": "¾ of 12: first find ¼ = 3, then × 3 = 9"}, {"id": "mf3_04", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction is equivalent to ½?", "o": ["1/3", "2/3", "2/4", "3/4"], "a": "2/4", "e": "2/4 = 1/2 because both numerator and denominator are doubled"}, {"id": "mf3_05", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ⅓ of 15?", "o": ["3", "4", "5", "6"], "a": "5", "e": "Third means divide by 3. 15 ÷ 3 = 5"}, {"id": "mf3_06", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ⅔ of 12?", "o": ["4", "6", "8", "10"], "a": "8", "e": "⅔ of 12: first ⅓ = 4, then × 2 = 8"}, {"id": "mf3_07", "s": "maths", "t": "Fractions", "l": 3, "q": "Which is larger: ½ or ⅓?", "o": ["½", "⅓", "They are equal", "Cannot tell"], "a": "½", "e": "½ = 0.5, ⅓ ≈ 0.33. So ½ is larger."}, {"id": "mf3_08", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¼ of 24?", "o": ["4", "5", "6", "8"], "a": "6", "e": "24 ÷ 4 = 6"}, {"id": "mf3_09", "s": "maths", "t": "Fractions", "l": 3, "q": "What fraction of 10 is 5?", "o": ["1/5", "1/4", "1/3", "1/2"], "a": "1/2", "e": "5 out of 10 = 5/10 = 1/2"}, {"id": "mf3_10", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¾ of 20?", "o": ["10", "12", "15", "18"], "a": "15", "e": "¾ of 20: ¼ = 5, × 3 = 15"}, {"id": "mf3_11", "s": "maths", "t": "Fractions", "l": 3, "q": "½ as a percentage is…", "o": ["25%", "50%", "75%", "100%"], "a": "50%", "e": "½ = 50 out of 100 = 50%"}, {"id": "mf3_12", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ⅕ of 25?", "o": ["4", "5", "6", "7"], "a": "5", "e": "25 ÷ 5 = 5"}, {"id": "mf3_13", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction equals 2/4?", "o": ["1/3", "1/2", "2/3", "3/4"], "a": "1/2", "e": "2/4 simplifies to 1/2 (divide both by 2)"}, {"id": "mf3_14", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ⅖ of 20?", "o": ["4", "6", "8", "10"], "a": "8", "e": "⅕ of 20 = 4, × 2 = 8"}, {"id": "mf3_15", "s": "maths", "t": "Fractions", "l": 3, "q": "What is 1/10 of 50?", "o": ["5", "10", "15", "20"], "a": "5", "e": "50 ÷ 10 = 5"}, {"id": "mf3_16", "s": "maths", "t": "Fractions", "l": 3, "q": "Which is the smallest: ¼, ½ or ⅓?", "o": ["¼", "½", "⅓", "They are equal"], "a": "¼", "e": "¼ = 0.25, ⅓ ≈ 0.33, ½ = 0.5. So ¼ is smallest."}, {"id": "mf3_17", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ⅗ of 10?", "o": ["3", "5", "6", "8"], "a": "6", "e": "⅕ of 10 = 2, × 3 = 6"}, {"id": "mf3_18", "s": "maths", "t": "Fractions", "l": 3, "q": "What fraction of 20 is 10?", "o": ["¼", "⅓", "½", "¾"], "a": "½", "e": "10/20 = 1/2"}, {"id": "mf3_19", "s": "maths", "t": "Fractions", "l": 3, "q": "½ + ¼ = ?", "o": ["2/6", "½", "¾", "1"], "a": "¾", "e": "½ = 2/4, so 2/4 + 1/4 = 3/4"}, {"id": "mf3_20", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¼ of 100?", "o": ["10", "20", "25", "40"], "a": "25", "e": "100 ÷ 4 = 25"}, {"id": "mf4_01", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 3/8 + 1/4?", "o": ["4/12", "1/2", "5/8", "7/8"], "a": "5/8", "e": "1/4 = 2/8, so 3/8 + 2/8 = 5/8"}, {"id": "mf4_02", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 5/6 − 1/3?", "o": ["4/3", "4/6", "1/2", "2/3"], "a": "1/2", "e": "1/3 = 2/6, so 5/6 − 2/6 = 3/6 = 1/2"}, {"id": "mf4_03", "s": "maths", "t": "Fractions", "l": 4, "q": "Simplify 18/24.", "o": ["3/4", "6/8", "9/12", "2/3"], "a": "3/4", "e": "18/24: divide both by 6 → 3/4"}, {"id": "mf4_04", "s": "maths", "t": "Fractions", "l": 4, "q": "Convert 11/4 to a mixed number.", "o": ["2¼", "2¾", "3¼", "1¾"], "a": "2¾", "e": "11 ÷ 4 = 2 remainder 3, so 2¾"}, {"id": "mf4_05", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 2/3 × 9?", "o": ["3", "6", "9", "18"], "a": "6", "e": "2/3 × 9 = (2 × 9) ÷ 3 = 18 ÷ 3 = 6"}, {"id": "mf4_06", "s": "maths", "t": "Fractions", "l": 4, "q": "Which is greatest: 3/4, 7/10, or 5/8?", "o": ["3/4", "7/10", "5/8", "They are equal"], "a": "3/4", "e": "3/4=0.75, 7/10=0.70, 5/8=0.625. So 3/4 is greatest."}, {"id": "mf4_07", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 4/5 of 35?", "o": ["20", "24", "28", "32"], "a": "28", "e": "1/5 of 35 = 7, × 4 = 28"}, {"id": "mf4_08", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 1¾ + 2½?", "o": ["3¼", "4", "4¼", "4½"], "a": "4¼", "e": "1¾ + 2½ = 1 3/4 + 2 2/4 = 3 5/4 = 4 1/4"}, {"id": "mf4_09", "s": "maths", "t": "Fractions", "l": 4, "q": "Convert 3⅖ to an improper fraction.", "o": ["15/5", "17/5", "16/5", "18/5"], "a": "17/5", "e": "3 × 5 = 15, + 2 = 17 → 17/5"}, {"id": "mf4_10", "s": "maths", "t": "Fractions", "l": 4, "q": "3/4 − 1/6 = ?", "o": ["2/3", "7/12", "1/2", "5/12"], "a": "7/12", "e": "Common denominator 12: 9/12 − 2/12 = 7/12"}, {"id": "mf4_11", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 5/6 of 24?", "o": ["15", "18", "20", "22"], "a": "20", "e": "1/6 of 24 = 4, × 5 = 20"}, {"id": "mf4_12", "s": "maths", "t": "Fractions", "l": 4, "q": "Simplify 36/48.", "o": ["3/4", "2/3", "6/8", "9/12"], "a": "3/4", "e": "36/48: divide both by 12 → 3/4"}, {"id": "mf4_13", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 7/10 + 1/4?", "o": ["8/14", "9/20", "19/20", "4/5"], "a": "19/20", "e": "Common denominator 20: 14/20 + 5/20 = 19/20"}, {"id": "mf4_14", "s": "maths", "t": "Fractions", "l": 4, "q": "2/3 + 3/4 = ?", "o": ["5/7", "5/12", "17/12", "1½"], "a": "17/12", "e": "Common denominator 12: 8/12 + 9/12 = 17/12"}, {"id": "mf4_15", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 3/5 ÷ 3?", "o": ["9/5", "1/5", "3/15", "1/3"], "a": "1/5", "e": "Dividing a fraction by 3: 3/5 ÷ 3 = 3/15 = 1/5"}, {"id": "mf4_16", "s": "maths", "t": "Fractions", "l": 4, "q": "A recipe needs 2/3 cup sugar for 8 biscuits. How much for 24 biscuits?", "o": ["1 cup", "1½ cups", "2 cups", "2½ cups"], "a": "2 cups", "e": "24 is 3× more than 8, so 2/3 × 3 = 2 cups"}, {"id": "mf4_17", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 1⅔ × 6?", "o": ["7", "8", "10", "12"], "a": "10", "e": "1⅔ = 5/3. 5/3 × 6 = 30/3 = 10"}, {"id": "mf4_18", "s": "maths", "t": "Fractions", "l": 4, "q": "Which fraction is between 1/2 and 3/4?", "o": ["1/3", "2/5", "5/8", "7/8"], "a": "5/8", "e": "5/8 = 0.625, which is between 0.5 and 0.75"}, {"id": "mf4_19", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 5/8 as a decimal?", "o": ["0.58", "0.625", "0.65", "0.8"], "a": "0.625", "e": "5 ÷ 8 = 0.625"}, {"id": "mf4_20", "s": "maths", "t": "Fractions", "l": 4, "q": "Jake ate 3/8 of a pizza. Mia ate 1/4. What fraction is left?", "o": ["3/8", "4/8", "3/4", "5/8"], "a": "3/8", "e": "3/8 + 2/8 = 5/8 eaten. 8/8 − 5/8 = 3/8 left"}, {"id": "mmd3_01", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "6 × 7 = ?", "o": ["36", "42", "48", "54"], "a": "42", "e": "6 × 7 = 42"}, {"id": "mmd3_02", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "8 × 9 = ?", "o": ["63", "64", "72", "81"], "a": "72", "e": "8 × 9 = 72"}, {"id": "mmd3_03", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "48 ÷ 6 = ?", "o": ["6", "7", "8", "9"], "a": "8", "e": "48 ÷ 6 = 8"}, {"id": "mmd3_04", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "7 × 8 = ?", "o": ["48", "54", "56", "63"], "a": "56", "e": "7 × 8 = 56"}, {"id": "mmd3_05", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "63 ÷ 7 = ?", "o": ["7", "8", "9", "10"], "a": "9", "e": "63 ÷ 7 = 9"}, {"id": "mmd3_06", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "9 × 6 = ?", "o": ["45", "48", "54", "56"], "a": "54", "e": "9 × 6 = 54"}, {"id": "mmd3_07", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "56 ÷ 8 = ?", "o": ["5", "6", "7", "8"], "a": "7", "e": "56 ÷ 8 = 7"}, {"id": "mmd3_08", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "12 × 7 = ?", "o": ["74", "80", "84", "96"], "a": "84", "e": "12 × 7 = 84"}, {"id": "mmd3_09", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "72 ÷ 9 = ?", "o": ["6", "7", "8", "9"], "a": "8", "e": "72 ÷ 9 = 8"}, {"id": "mmd3_10", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "11 × 8 = ?", "o": ["80", "84", "88", "96"], "a": "88", "e": "11 × 8 = 88"}, {"id": "mmd3_11", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "144 ÷ 12 = ?", "o": ["10", "11", "12", "13"], "a": "12", "e": "144 ÷ 12 = 12"}, {"id": "mmd3_12", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "9 × 9 = ?", "o": ["72", "81", "90", "99"], "a": "81", "e": "9 × 9 = 81"}, {"id": "mmd3_13", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "A baker makes 9 cakes per day. How many in 6 days?", "o": ["45", "54", "56", "63"], "a": "54", "e": "9 × 6 = 54"}, {"id": "mmd3_14", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "6 × 12 = ?", "o": ["62", "70", "72", "84"], "a": "72", "e": "6 × 12 = 72"}, {"id": "mmd3_15", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "96 ÷ 8 = ?", "o": ["10", "11", "12", "13"], "a": "12", "e": "96 ÷ 8 = 12 because 8 × 12 = 96"}, {"id": "mmd3_16", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "7 rows of 9 chairs — how many total?", "o": ["54", "56", "62", "63"], "a": "63", "e": "7 × 9 = 63"}, {"id": "mmd3_17", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "7 × 11 = ?", "o": ["70", "74", "77", "84"], "a": "77", "e": "7 × 11 = 77"}, {"id": "mmd3_18", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "84 ÷ 7 = ?", "o": ["10", "11", "12", "14"], "a": "12", "e": "84 ÷ 7 = 12"}, {"id": "mmd3_19", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "108 ÷ 9 = ?", "o": ["10", "11", "12", "13"], "a": "12", "e": "108 ÷ 9 = 12"}, {"id": "mmd3_20", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "8 × 12 = ?", "o": ["88", "92", "96", "104"], "a": "96", "e": "8 × 12 = 96"}, {"id": "mmd4_01", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "24 × 15 = ?", "o": ["300", "340", "360", "380"], "a": "360", "e": "24 × 15 = 24 × 10 + 24 × 5 = 240 + 120 = 360"}, {"id": "mmd4_02", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "342 ÷ 6 = ?", "o": ["54", "57", "58", "62"], "a": "57", "e": "342 ÷ 6: 6 × 57 = 342"}, {"id": "mmd4_03", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is the remainder when 125 ÷ 8?", "o": ["3", "4", "5", "6"], "a": "5", "e": "8 × 15 = 120, 125 − 120 = 5 remainder"}, {"id": "mmd4_04", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "37 × 12 = ?", "o": ["404", "434", "444", "454"], "a": "444", "e": "37 × 12 = 37 × 10 + 37 × 2 = 370 + 74 = 444"}, {"id": "mmd4_05", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "256 ÷ 16 = ?", "o": ["14", "15", "16", "17"], "a": "16", "e": "16 × 16 = 256"}, {"id": "mmd4_06", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "How many factors does 36 have?", "o": ["7", "8", "9", "10"], "a": "9", "e": "Factors of 36: 1,2,3,4,6,9,12,18,36 — that's 9 factors"}, {"id": "mmd4_07", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is the LCM of 4 and 6?", "o": ["8", "10", "12", "24"], "a": "12", "e": "Multiples of 4: 4,8,12… Multiples of 6: 6,12… LCM = 12"}, {"id": "mmd4_08", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "504 ÷ 7 = ?", "o": ["62", "70", "72", "74"], "a": "72", "e": "7 × 72 = 504"}, {"id": "mmd4_09", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "3.5 × 6 = ?", "o": ["18", "20", "21", "24"], "a": "21", "e": "3.5 × 6 = 3 × 6 + 0.5 × 6 = 18 + 3 = 21"}, {"id": "mmd4_10", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "625 ÷ 25 = ?", "o": ["20", "23", "25", "30"], "a": "25", "e": "25 × 25 = 625"}, {"id": "mmd4_11", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "48 × 25 = ?", "o": ["1,000", "1,100", "1,200", "1,400"], "a": "1,200", "e": "48 × 25 = 48 × 100 ÷ 4 = 4800 ÷ 4 = 1,200"}, {"id": "mmd4_12", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is 5² × 4?", "o": ["40", "80", "100", "120"], "a": "100", "e": "5² = 25, 25 × 4 = 100"}, {"id": "mmd4_13", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "432 ÷ 9 = ?", "o": ["44", "46", "48", "52"], "a": "48", "e": "9 × 48 = 432"}, {"id": "mmd4_14", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "How many 15s in 225?", "o": ["13", "14", "15", "16"], "a": "15", "e": "225 ÷ 15 = 15 (15 × 15 = 225)"}, {"id": "mmd4_15", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "28 × 35 = ?", "o": ["840", "900", "960", "980"], "a": "980", "e": "28 × 35 = 28 × 30 + 28 × 5 = 840 + 140 = 980"}, {"id": "mmd4_16", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "84 ÷ 3 + 6 × 4 = ?", "o": ["40", "48", "52", "56"], "a": "52", "e": "BODMAS: 84 ÷ 3 = 28, 6 × 4 = 24, 28 + 24 = 52"}, {"id": "mmd4_17", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "4 × 13 × 5 = ?", "o": ["200", "240", "260", "280"], "a": "260", "e": "4 × 5 = 20, 20 × 13 = 260"}, {"id": "mmd4_18", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is the HCF of 24 and 36?", "o": ["4", "6", "8", "12"], "a": "12", "e": "Factors of 24: 1,2,3,4,6,8,12,24. Factors of 36: 1,2,3,4,6,9,12,18,36. HCF = 12"}, {"id": "mmd4_19", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "576 ÷ 24 = ?", "o": ["22", "24", "26", "28"], "a": "24", "e": "24 × 24 = 576"}, {"id": "mmd4_20", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "A box holds 18 oranges. How many boxes for 270 oranges?", "o": ["13", "14", "15", "16"], "a": "15", "e": "270 ÷ 18 = 15"}, {"id": "mpv3_01", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the value of the digit 7 in 473?", "o": ["7", "70", "700", "7000"], "a": "70", "e": "In 473, the 7 is in the tens column = 70"}, {"id": "mpv3_02", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 346 rounded to the nearest 10?", "o": ["300", "340", "350", "400"], "a": "350", "e": "346: the units digit is 6 (≥5), so round up to 350"}, {"id": "mpv3_03", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which is the largest: 526, 562, 256, 625?", "o": ["526", "562", "256", "625"], "a": "625", "e": "Comparing hundreds: 6 > 5 > 2, so 625 is largest"}, {"id": "mpv3_04", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 580 rounded to the nearest 100?", "o": ["500", "550", "600", "700"], "a": "600", "e": "580: tens digit is 8 (≥5), round up to 600"}, {"id": "mpv3_05", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What number is 100 more than 750?", "o": ["760", "800", "850", "950"], "a": "850", "e": "750 + 100 = 850"}, {"id": "mpv3_06", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Write seven hundred and sixty-three in digits.", "o": ["367", "637", "673", "763"], "a": "763", "e": "Seven hundred = 700, sixty = 60, three = 3 → 763"}, {"id": "mpv3_07", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the value of the 5 in 2,504?", "o": ["5", "50", "500", "5000"], "a": "500", "e": "In 2,504 the digit 5 is in the hundreds column = 500"}, {"id": "mpv3_08", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Order smallest first: 842, 248, 428, 824", "o": ["248,428,824,842", "248,428,842,824", "428,248,824,842", "248,824,428,842"], "a": "248,428,824,842", "e": "Compare hundreds: 2<4<8, then 824<842"}, {"id": "mpv3_09", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is -3 + 5?", "o": ["-8", "-2", "2", "8"], "a": "2", "e": "Start at -3, move 5 right = 2"}, {"id": "mpv3_10", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which temperature is colder: -4°C or -7°C?", "o": ["-4°C", "-7°C", "They are equal", "Cannot tell"], "a": "-7°C", "e": "On a number line, -7 is further left (colder) than -4"}, {"id": "mpv3_11", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 1,000 less than 4,567?", "o": ["3,456", "3,567", "4,467", "4,557"], "a": "3,567", "e": "4,567 − 1,000 = 3,567"}, {"id": "mpv3_12", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Round 3,748 to the nearest 100.", "o": ["3,600", "3,700", "3,800", "4,000"], "a": "3,700", "e": "3,748: tens digit is 4 (< 5), round down to 3,700"}, {"id": "mpv3_13", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "How many tens are there in 350?", "o": ["3", "5", "35", "350"], "a": "35", "e": "350 ÷ 10 = 35 tens"}, {"id": "mpv3_14", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 10 × 10?", "o": ["20", "100", "1,000", "10,000"], "a": "100", "e": "10 × 10 = 100"}, {"id": "mpv3_15", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which of these is an even number?", "o": ["137", "249", "362", "475"], "a": "362", "e": "Even numbers end in 0,2,4,6,8. Only 362 ends in 2."}, {"id": "mpv4_01", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 3.45 rounded to 1 decimal place?", "o": ["3.4", "3.5", "3.6", "4.0"], "a": "3.5", "e": "3.45 — the hundredths digit is 5, so round up: 3.5"}, {"id": "mpv4_02", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is the value of the digit 7 in 3.718?", "o": ["7", "7 tenths", "7 hundredths", "7 thousandths"], "a": "7 tenths", "e": "In 3.718, the 7 is in the tenths column = 7 tenths"}, {"id": "mpv4_03", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 5.2 × 100?", "o": ["52", "520", "5,200", "0.052"], "a": "520", "e": "Multiply by 100: move decimal 2 places right → 520"}, {"id": "mpv4_04", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Which is smallest: 4.09, 4.9, 4.19, 4.019?", "o": ["4.09", "4.9", "4.19", "4.019"], "a": "4.019", "e": "4.019 < 4.09 < 4.19 < 4.9"}, {"id": "mpv4_05", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 10³?", "o": ["30", "300", "1,000", "10,000"], "a": "1,000", "e": "10³ = 10 × 10 × 10 = 1,000"}, {"id": "mpv4_06", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 7.5 ÷ 100?", "o": ["0.075", "0.75", "75", "750"], "a": "0.075", "e": "Divide by 100: move decimal 2 places left → 0.075"}, {"id": "mpv4_07", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 1,000 more than 47,832?", "o": ["47,932", "48,732", "48,832", "57,832"], "a": "48,832", "e": "47,832 + 1,000 = 48,832"}, {"id": "mpv4_08", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What digit is in the thousandths place in 5.2637?", "o": ["2", "6", "3", "7"], "a": "3", "e": "5.2637 — tenths:2, hundredths:6, thousandths:3"}, {"id": "mpv4_09", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Which is smaller: 0.302 or 0.32?", "o": ["0.302", "0.32", "They are equal", "Cannot tell"], "a": "0.302", "e": "0.302 = 0.302, 0.32 = 0.320. So 0.302 < 0.320"}, {"id": "mpv4_10", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Round 4.847 to 2 decimal places.", "o": ["4.84", "4.85", "4.9", "5.0"], "a": "4.85", "e": "4.847 — third decimal is 7 (≥5), round up: 4.85"}, {"id": "mpv4_11", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is the value of 6 in 562,841?", "o": ["6,000", "60,000", "600,000", "6,000,000"], "a": "60,000", "e": "In 562,841: the 6 is in the ten-thousands column = 60,000"}, {"id": "mpv4_12", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "0.5 + 0.25 + 0.125 = ?", "o": ["0.750", "0.825", "0.875", "0.900"], "a": "0.875", "e": "0.500 + 0.250 + 0.125 = 0.875"}, {"id": "mpv4_13", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What comes next: 2.5, 3.0, 3.5, ___?", "o": ["3.8", "4.0", "4.5", "5.0"], "a": "4.0", "e": "The sequence adds 0.5 each time. 3.5 + 0.5 = 4.0"}, {"id": "mpv4_14", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Which is greatest: 4.099, 4.1, 4.09, 4.0999?", "o": ["4.099", "4.1", "4.09", "4.0999"], "a": "4.1", "e": "4.1 = 4.1000, which is largest of all four"}, {"id": "mpv4_15", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 9.25 − 3.8?", "o": ["5.35", "5.45", "6.15", "6.45"], "a": "5.45", "e": "9.25 − 3.80 = 5.45"}, {"id": "mpv4_16", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Write 40,000 + 3,000 + 70 + 8 as a single number.", "o": ["4,378", "43,078", "43,780", "430,078"], "a": "43,078", "e": "40,000 + 3,000 = 43,000 + 70 = 43,070 + 8 = 43,078"}, {"id": "mpv4_17", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 0.08 × 10?", "o": ["0.008", "0.08", "0.8", "8"], "a": "0.8", "e": "0.08 × 10: move decimal one place right → 0.8"}, {"id": "mpv4_18", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Round 67,455 to the nearest 1,000.", "o": ["67,000", "67,400", "67,500", "68,000"], "a": "67,000", "e": "67,455: hundreds digit is 4 (< 5), round down → 67,000"}, {"id": "mpv4_19", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is the product of 0.4 × 0.3?", "o": ["0.07", "0.12", "1.2", "12"], "a": "0.12", "e": "4 × 3 = 12; both have 1 decimal place each → 0.12"}, {"id": "mpv4_20", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "A number has 4 in the millions place. What is the smallest it could be?", "o": ["400,000", "4,000,000", "4,000,001", "4,999,999"], "a": "4,000,000", "e": "The smallest number with 4 in the millions column is 4,000,000"}, {"id": "mas3_01", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "345 + 267 = ?", "o": ["502", "602", "612", "622"], "a": "612", "e": "345 + 267 = 612"}, {"id": "mas3_02", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "500 − 237 = ?", "o": ["263", "273", "283", "363"], "a": "263", "e": "500 − 237 = 263"}, {"id": "mas3_03", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "628 + 145 = ?", "o": ["763", "773", "783", "793"], "a": "773", "e": "628 + 145 = 773"}, {"id": "mas3_04", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A shop has 432 apples. 178 are sold. How many left?", "o": ["244", "254", "264", "274"], "a": "254", "e": "432 − 178 = 254"}, {"id": "mas3_05", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "867 − 349 = ?", "o": ["418", "508", "518", "528"], "a": "518", "e": "867 − 349 = 518"}, {"id": "mas3_06", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 999 + 1?", "o": ["1,000", "1,009", "1,099", "1,999"], "a": "1,000", "e": "999 + 1 = 1,000"}, {"id": "mas3_07", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "274 + 358 = ?", "o": ["522", "622", "632", "642"], "a": "632", "e": "274 + 358 = 632"}, {"id": "mas3_08", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "700 − 456 = ?", "o": ["234", "244", "254", "264"], "a": "244", "e": "700 − 456 = 244"}, {"id": "mas3_09", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "453 + 229 = ?", "o": ["672", "682", "692", "782"], "a": "682", "e": "453 + 229 = 682"}, {"id": "mas3_10", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "1,000 − 375 = ?", "o": ["525", "625", "635", "725"], "a": "625", "e": "1,000 − 375 = 625"}, {"id": "mdc3_01", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.5 + 0.5?", "o": ["0.1", "0.55", "1.0", "5.5"], "a": "1.0", "e": "0.5 + 0.5 = 1.0"}, {"id": "mdc3_02", "s": "maths", "t": "Decimals", "l": 3, "q": "Which is larger: 0.7 or 0.3?", "o": ["0.7", "0.3", "They are equal", "Cannot tell"], "a": "0.7", "e": "7 tenths > 3 tenths"}, {"id": "mdc3_03", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 1.5 + 2.5?", "o": ["3.0", "3.5", "4.0", "4.5"], "a": "4.0", "e": "1.5 + 2.5 = 4.0"}, {"id": "mdc3_04", "s": "maths", "t": "Decimals", "l": 3, "q": "Write 0.25 as a fraction.", "o": ["1/2", "1/4", "1/5", "1/8"], "a": "1/4", "e": "0.25 = 25/100 = 1/4"}, {"id": "mdc3_05", "s": "maths", "t": "Decimals", "l": 3, "q": "Order smallest first: 0.6, 0.1, 0.4", "o": ["0.6,0.4,0.1", "0.1,0.4,0.6", "0.4,0.1,0.6", "0.1,0.6,0.4"], "a": "0.1,0.4,0.6", "e": "0.1 < 0.4 < 0.6"}, {"id": "mdc3_06", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 2.4 + 1.6?", "o": ["3.0", "3.8", "4.0", "4.2"], "a": "4.0", "e": "2.4 + 1.6 = 4.0"}, {"id": "mdc3_07", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.1 as a percentage?", "o": ["1%", "10%", "100%", "0.1%"], "a": "10%", "e": "0.1 = 1/10 = 10%"}, {"id": "mdc3_08", "s": "maths", "t": "Decimals", "l": 3, "q": "A pencil is 15.5 cm. Round to the nearest cm.", "o": ["15 cm", "16 cm", "15.5 cm", "20 cm"], "a": "16 cm", "e": "15.5 → round up to 16 cm"}, {"id": "mpc3_01", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 50% of 80?", "o": ["20", "30", "40", "50"], "a": "40", "e": "50% = half. 80 ÷ 2 = 40"}, {"id": "mpc3_02", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 25% of 40?", "o": ["5", "8", "10", "15"], "a": "10", "e": "25% = quarter. 40 ÷ 4 = 10"}, {"id": "mpc3_03", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 10% of 70?", "o": ["7", "17", "70", "700"], "a": "7", "e": "10%: divide by 10. 70 ÷ 10 = 7"}, {"id": "mpc3_04", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 100% of 55?", "o": ["5", "50", "55", "100"], "a": "55", "e": "100% of any number = the number itself"}, {"id": "mpc3_05", "s": "maths", "t": "Percentages", "l": 3, "q": "30 pupils, 60% are girls. How many girls?", "o": ["6", "12", "18", "20"], "a": "18", "e": "10% of 30 = 3, × 6 = 18"}, {"id": "mpc3_06", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 10% of 250?", "o": ["2.5", "25", "250", "2,500"], "a": "25", "e": "250 ÷ 10 = 25"}, {"id": "mpc3_07", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 50% of 130?", "o": ["13", "50", "65", "130"], "a": "65", "e": "130 ÷ 2 = 65"}, {"id": "mpc3_08", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage is 3 out of 10?", "o": ["3%", "10%", "30%", "33%"], "a": "30%", "e": "3/10 = 30/100 = 30%"}, {"id": "mgs3_01", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many sides does a hexagon have?", "o": ["4", "5", "6", "7"], "a": "6", "e": "Hexagon = 6 sides"}, {"id": "mgs3_02", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a 3-sided shape?", "o": ["Square", "Rectangle", "Triangle", "Pentagon"], "a": "Triangle", "e": "Triangle = 3 sides"}, {"id": "mgs3_03", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many faces does a cube have?", "o": ["4", "5", "6", "8"], "a": "6", "e": "A cube has 6 square faces"}, {"id": "mgs3_04", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is a quadrilateral?", "o": ["3-sided", "4-sided", "5-sided", "6-sided"], "a": "4-sided", "e": "Quadrilateral = 4 sides"}, {"id": "mgs3_05", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many lines of symmetry does a square have?", "o": ["1", "2", "3", "4"], "a": "4", "e": "A square has 4 lines of symmetry"}, {"id": "mgs3_06", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many vertices does a cuboid have?", "o": ["4", "6", "8", "12"], "a": "8", "e": "A cuboid has 8 vertices"}, {"id": "mgs3_07", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "5 faces, 5 vertices, 8 edges — which shape?", "o": ["Cube", "Triangular prism", "Square-based pyramid", "Cylinder"], "a": "Square-based pyramid", "e": "Square-based pyramid: 1 square + 4 triangular faces"}, {"id": "mgs3_08", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "An equilateral triangle has…", "o": ["All sides different", "2 equal sides", "All sides equal", "No equal sides"], "a": "All sides equal", "e": "Equilateral = all sides and angles equal"}, {"id": "mang3_01", "s": "maths", "t": "Angles", "l": 3, "q": "How many degrees in a right angle?", "o": ["45°", "90°", "180°", "360°"], "a": "90°", "e": "A right angle = 90°"}, {"id": "mang3_02", "s": "maths", "t": "Angles", "l": 3, "q": "An angle less than 90° is called…", "o": ["Acute", "Right", "Obtuse", "Reflex"], "a": "Acute", "e": "Acute angles are less than 90°"}, {"id": "mang3_03", "s": "maths", "t": "Angles", "l": 3, "q": "An angle between 90° and 180° is called…", "o": ["Acute", "Right", "Obtuse", "Straight"], "a": "Obtuse", "e": "Obtuse angles are between 90° and 180°"}, {"id": "mang3_04", "s": "maths", "t": "Angles", "l": 3, "q": "Angles in a triangle add up to…", "o": ["90°", "180°", "270°", "360°"], "a": "180°", "e": "All three angles in any triangle sum to 180°"}, {"id": "mang3_05", "s": "maths", "t": "Angles", "l": 3, "q": "Angles on a straight line add up to…", "o": ["90°", "180°", "270°", "360°"], "a": "180°", "e": "Angles on a straight line = 180°"}, {"id": "mang3_06", "s": "maths", "t": "Angles", "l": 3, "q": "A triangle has angles 60° and 80°. What is the third?", "o": ["30°", "40°", "50°", "60°"], "a": "40°", "e": "180 − 60 − 80 = 40°"}, {"id": "mang3_07", "s": "maths", "t": "Angles", "l": 3, "q": "How many degrees in a full turn?", "o": ["90°", "180°", "270°", "360°"], "a": "360°", "e": "A full rotation = 360°"}, {"id": "mang3_08", "s": "maths", "t": "Angles", "l": 3, "q": "One angle on a straight line is 110°. What is the other?", "o": ["60°", "70°", "80°", "90°"], "a": "70°", "e": "180 − 110 = 70°"}, {"id": "mmu3_01", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many centimetres in 1 metre?", "o": ["10", "100", "1,000", "10,000"], "a": "100", "e": "1 m = 100 cm"}, {"id": "mmu3_02", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many grams in 1 kilogram?", "o": ["10", "100", "1,000", "10,000"], "a": "1,000", "e": "1 kg = 1,000 g"}, {"id": "mmu3_03", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many millilitres in 1 litre?", "o": ["10", "100", "1,000", "10,000"], "a": "1,000", "e": "1 litre = 1,000 ml"}, {"id": "mmu3_04", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Convert 2.5 kg to grams.", "o": ["25 g", "250 g", "2,500 g", "25,000 g"], "a": "2,500 g", "e": "2.5 × 1,000 = 2,500 g"}, {"id": "mmu3_05", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Film starts 3:15 pm, lasts 90 min. When does it end?", "o": ["4:00 pm", "4:30 pm", "4:45 pm", "5:00 pm"], "a": "4:45 pm", "e": "3:15 + 45 min = 4:00, + 45 more = 4:45 pm"}, {"id": "mmu3_06", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many minutes in 2 hours?", "o": ["60", "90", "100", "120"], "a": "120", "e": "2 × 60 = 120 minutes"}, {"id": "mmu3_07", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Convert 350 cm to metres.", "o": ["0.35 m", "3.5 m", "35 m", "3,500 m"], "a": "3.5 m", "e": "350 ÷ 100 = 3.5 m"}, {"id": "mmu3_08", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Which is heavier: 1.5 kg or 1,450 g?", "o": ["1.5 kg", "1,450 g", "They are equal", "Cannot tell"], "a": "1.5 kg", "e": "1.5 kg = 1,500 g > 1,450 g"}, {"id": "mpa3_01", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Perimeter of a rectangle 6 cm × 4 cm?", "o": ["10 cm", "20 cm", "24 cm", "48 cm"], "a": "20 cm", "e": "Perimeter = 2(6+4) = 20 cm"}, {"id": "mpa3_02", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Area of a rectangle 5 cm × 3 cm?", "o": ["8 cm²", "15 cm²", "16 cm²", "30 cm²"], "a": "15 cm²", "e": "Area = 5 × 3 = 15 cm²"}, {"id": "mpa3_03", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A square has 7 cm sides. What is its perimeter?", "o": ["14 cm", "21 cm", "28 cm", "49 cm"], "a": "28 cm", "e": "4 × 7 = 28 cm"}, {"id": "mpa3_04", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Area of a square with 8 cm sides?", "o": ["32 cm²", "48 cm²", "64 cm²", "16 cm²"], "a": "64 cm²", "e": "8 × 8 = 64 cm²"}, {"id": "mpa3_05", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Rectangle: area 24 cm², width 4 cm. What is the length?", "o": ["4 cm", "6 cm", "8 cm", "20 cm"], "a": "6 cm", "e": "Length = 24 ÷ 4 = 6 cm"}, {"id": "mpa3_06", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Perimeter of a square with 9 cm sides?", "o": ["18 cm", "27 cm", "36 cm", "81 cm"], "a": "36 cm", "e": "4 × 9 = 36 cm"}, {"id": "mds3_01", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Mean of 2, 4, 6, 8?", "o": ["4", "5", "6", "20"], "a": "5", "e": "(2+4+6+8) ÷ 4 = 20 ÷ 4 = 5"}, {"id": "mds3_02", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Bar chart: Mon=5, Tue=8, Wed=3. Total?", "o": ["13", "14", "16", "18"], "a": "16", "e": "5 + 8 + 3 = 16"}, {"id": "mds3_03", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Mode of 3, 5, 3, 7, 5, 3?", "o": ["3", "5", "7", "4.3"], "a": "3", "e": "Mode = most frequent. 3 appears 3 times."}, {"id": "mds3_04", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Median of 1, 3, 5, 7, 9?", "o": ["3", "5", "7", "9"], "a": "5", "e": "Middle value of 5 numbers = 3rd = 5"}, {"id": "mds3_05", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Pictogram: each symbol = 4, there are 5 symbols. Total?", "o": ["5", "9", "20", "25"], "a": "20", "e": "5 × 4 = 20"}, {"id": "mds3_06", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Range of 4, 7, 2, 9, 1?", "o": ["5", "7", "8", "9"], "a": "8", "e": "Range = 9 − 1 = 8"}, {"id": "mps3_01", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Tom has £5.00, buys a pen for £1.75. Change?", "o": ["£2.75", "£3.00", "£3.25", "£3.75"], "a": "£3.25", "e": "£5.00 − £1.75 = £3.25"}, {"id": "mps3_02", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Box holds 6 eggs. How many boxes for 42 eggs?", "o": ["6", "7", "8", "9"], "a": "7", "e": "42 ÷ 6 = 7"}, {"id": "mps3_03", "s": "maths", "t": "Problem Solving", "l": 3, "q": "24 children in 4 equal groups. How many per group?", "o": ["4", "5", "6", "8"], "a": "6", "e": "24 ÷ 4 = 6"}, {"id": "mps3_04", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Car travels 60 km/h for 3 hours. How far?", "o": ["63 km", "120 km", "180 km", "200 km"], "a": "180 km", "e": "60 × 3 = 180 km"}, {"id": "mps3_05", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Sara has 3× as many stickers as Priya. Priya has 12. Sara has…?", "o": ["9", "24", "36", "48"], "a": "36", "e": "3 × 12 = 36"}, {"id": "mps3_06", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Next in sequence: 4, 8, 12, 16, ___?", "o": ["18", "19", "20", "24"], "a": "20", "e": "Adds 4 each time. 16 + 4 = 20"}, {"id": "ev3_01", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"enormous\\" mean?", "o": ["Tiny", "Beautiful", "Very large", "Dangerous"], "a": "Very large", "e": "\\"Enormous\\" means extremely large"}, {"id": "ev3_02", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"ancient\\" mean?", "o": ["Modern", "Very old", "Broken", "Hidden"], "a": "Very old", "e": "\\"Ancient\\" means belonging to the very distant past"}, {"id": "ev3_03", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"timid\\" mean?", "o": ["Brave", "Clever", "Shy and nervous", "Loud"], "a": "Shy and nervous", "e": "\\"Timid\\" means lacking confidence, easily frightened"}, {"id": "ev3_04", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"transparent\\" mean?", "o": ["Colourful", "See-through", "Heavy", "Invisible"], "a": "See-through", "e": "\\"Transparent\\" means able to be seen through"}, {"id": "ev3_05", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"reluctant\\" mean?", "o": ["Excited", "Unhappy", "Unwilling", "Confused"], "a": "Unwilling", "e": "\\"Reluctant\\" means not wanting to do something"}, {"id": "ev3_06", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"summit\\" mean?", "o": ["Valley", "River", "Top of a mountain", "Bottom"], "a": "Top of a mountain", "e": "\\"Summit\\" = the highest point"}, {"id": "ev3_07", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"villain\\" mean?", "o": ["Hero", "Bad character", "Side character", "King"], "a": "Bad character", "e": "A villain is an evil or wicked character"}, {"id": "ev3_08", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"predict\\" mean?", "o": ["To look back", "To say what will happen", "To explain", "To describe"], "a": "To say what will happen", "e": "\\"Predict\\" = say what you think will happen"}, {"id": "ev3_09", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"magnificent\\" mean?", "o": ["Ordinary", "Very impressive", "Small", "Frightening"], "a": "Very impressive", "e": "\\"Magnificent\\" = impressively beautiful or grand"}, {"id": "ev3_10", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"exhausted\\" mean?", "o": ["Happy", "Bored", "Very tired", "Angry"], "a": "Very tired", "e": "\\"Exhausted\\" = extremely tired"}, {"id": "ev3_11", "s": "english", "t": "Vocabulary", "l": 3, "q": "\\"The detective ___ the clues carefully.\\" Best word?", "o": ["ignored", "lost", "examined", "dropped"], "a": "examined", "e": "\\"Examined\\" = looked at carefully, fits a detective"}, {"id": "ev3_12", "s": "english", "t": "Vocabulary", "l": 3, "q": "Synonym for \\"happy\\"?", "o": ["Sad", "Angry", "Joyful", "Tired"], "a": "Joyful", "e": "Happy = joyful (same meaning)"}, {"id": "ev3_13", "s": "english", "t": "Vocabulary", "l": 3, "q": "Antonym for \\"cold\\"?", "o": ["Warm", "Icy", "Freezing", "Cool"], "a": "Warm", "e": "Cold ↔ warm are opposites"}, {"id": "ev3_14", "s": "english", "t": "Vocabulary", "l": 3, "q": "Synonym for \\"fast\\"?", "o": ["Slow", "Quick", "Lazy", "Heavy"], "a": "Quick", "e": "Fast and quick both mean rapid"}, {"id": "ev3_15", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does \\"cunning\\" mean?", "o": ["Clumsy", "Clever at tricking", "Generous", "Boring"], "a": "Clever at tricking", "e": "\\"Cunning\\" = craftily clever"}, {"id": "ep3_01", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses a capital letter correctly?", "o": ["the dog barked.", "The dog barked.", "the Dog Barked.", "THE dog barked."], "a": "The dog barked.", "e": "Sentences begin with a capital letter"}, {"id": "ep3_02", "s": "english", "t": "Punctuation", "l": 3, "q": "Where does the apostrophe go: 'The cats toy' (one cat)?", "o": ["cat's toy", "cats' toy", "cats toy", "cat toy"], "a": "cat's toy", "e": "One cat owns the toy: cat's (apostrophe before s)"}, {"id": "ep3_03", "s": "english", "t": "Punctuation", "l": 3, "q": "Correct contraction of \\"do not\\"?", "o": ["don't", "do'nt", "dont'", "d'ont"], "a": "don't", "e": "don't: apostrophe replaces the missing 'o'"}, {"id": "ep3_04", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence needs an exclamation mark?", "o": ["What is your name", "Please sit down", "Watch out", "The sky is blue"], "a": "Watch out", "e": "\\"Watch out\\" shows urgency — needs !"}, {"id": "ep3_05", "s": "english", "t": "Punctuation", "l": 3, "q": "Which is punctuated correctly?", "o": ["I like dogs cats and rabbits.", "I like dogs, cats, and rabbits.", "I, like dogs cats and rabbits.", "I like, dogs, cats and rabbits."], "a": "I like dogs, cats, and rabbits.", "e": "Commas separate items in a list"}, {"id": "ep3_06", "s": "english", "t": "Punctuation", "l": 3, "q": "What punctuation ends a question?", "o": ["Full stop", "Exclamation mark", "Question mark", "Comma"], "a": "Question mark", "e": "Questions end with ?"}, {"id": "ep3_07", "s": "english", "t": "Punctuation", "l": 3, "q": "\\"The dog wagged ___ tail.\\" its or it's?", "o": ["it's", "its", "its'", "it is"], "a": "its", "e": "\\"its\\" = possessive. \\"it's\\" = it is"}, {"id": "ep3_08", "s": "english", "t": "Punctuation", "l": 3, "q": "Where does a comma go: \\"After breakfast she went to school\\"?", "o": ["After", "breakfast", "she", "to"], "a": "After \\"breakfast\\"", "e": "Comma after introductory clause: \\"After breakfast, she...\\""}, {"id": "ep3_09", "s": "english", "t": "Punctuation", "l": 3, "q": "\\"The girls dresses\\" — two girls. Correct form?", "o": ["The girl's dresses", "The girls' dresses", "The girls dresses", "The girls's dresses"], "a": "The girls' dresses", "e": "Multiple girls → girls' (apostrophe after s)"}, {"id": "ep3_10", "s": "english", "t": "Punctuation", "l": 3, "q": "What is wrong: \\"The cat sat on it's mat\\"?", "o": ["it's should be its", "Wrong capital", "Missing full stop", "Nothing is wrong"], "a": "it's should be its", "e": "\\"its\\" (possessive) not \\"it's\\" (it is)"}, {"id": "ep3_11", "s": "english", "t": "Punctuation", "l": 3, "q": "Which uses speech marks correctly?", "o": ["I am hungry,", "said Tom.", "I am hungry", "I am hungry, said Tom"], "a": "\\"I am hungry,\\" said Tom.", "e": "Speech marks enclose spoken words; punctuation goes inside"}, {"id": "ep3_12", "s": "english", "t": "Punctuation", "l": 3, "q": "Which word needs a capital? \\"my favourite subject is science.\\"", "o": ["favourite", "subject", "science", "my"], "a": "my", "e": "\\"My\\" starts the sentence — needs a capital"}, {"id": "ep3_13", "s": "english", "t": "Punctuation", "l": 3, "q": "What does a comma do in a list?", "o": ["Ends the sentence", "Separates items", "Adds excitement", "Shows ownership"], "a": "Separates items", "e": "Commas separate items in a list"}, {"id": "ep3_14", "s": "english", "t": "Punctuation", "l": 3, "q": "Correct sentence?", "o": ["I went to london last summer.", "I went to London last summer.", "i went to london last summer.", "I went to london Last summer."], "a": "I went to London last summer.", "e": "London is a proper noun — always capitalised"}, {"id": "ep3_15", "s": "english", "t": "Punctuation", "l": 3, "q": "Contraction of \\"I am\\"?", "o": ["I'm", "Im'", "I'am", "Iam"], "a": "I'm", "e": "I'm: apostrophe replaces 'a' in 'am'"}, {"id": "eg3_01", "s": "english", "t": "Grammar", "l": 3, "q": "What is a noun?", "o": ["An action word", "A describing word", "A naming word", "A joining word"], "a": "A naming word", "e": "A noun names a person, place, thing or idea"}, {"id": "eg3_02", "s": "english", "t": "Grammar", "l": 3, "q": "What is a verb?", "o": ["A naming word", "An action word", "A describing word", "A connecting word"], "a": "An action word", "e": "A verb expresses an action or state"}, {"id": "eg3_03", "s": "english", "t": "Grammar", "l": 3, "q": "What is an adjective?", "o": ["A naming word", "An action word", "A word that describes a noun", "A joining word"], "a": "A word that describes a noun", "e": "Adjectives describe nouns"}, {"id": "eg3_04", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is an adjective in \\"The tall tree swayed\\"?", "o": ["The", "tall", "tree", "swayed"], "a": "tall", "e": "\\"Tall\\" describes the tree = adjective"}, {"id": "eg3_05", "s": "english", "t": "Grammar", "l": 3, "q": "Tense of \\"She walked to school\\"?", "o": ["Present", "Future", "Past", "Conditional"], "a": "Past", "e": "\\"Walked\\" is past tense"}, {"id": "eg3_06", "s": "english", "t": "Grammar", "l": 3, "q": "What is an adverb?", "o": ["Describes a noun", "Describes a verb", "Names a thing", "Joins sentences"], "a": "Describes a verb", "e": "An adverb modifies a verb (e.g. ran quickly)"}, {"id": "eg3_07", "s": "english", "t": "Grammar", "l": 3, "q": "Which is a proper noun?", "o": ["city", "school", "London", "teacher"], "a": "London", "e": "A proper noun is a specific name — always capitalised"}, {"id": "eg3_08", "s": "english", "t": "Grammar", "l": 3, "q": "\\"There are ___ biscuits left.\\" fewer or less?", "o": ["fewer", "less", "lesser", "fewest"], "a": "fewer", "e": "Use \\"fewer\\" for countable things"}, {"id": "eg3_09", "s": "english", "t": "Grammar", "l": 3, "q": "What is a conjunction?", "o": ["A naming word", "An action word", "A word that joins clauses", "A describing word"], "a": "A word that joins clauses", "e": "Conjunctions join clauses (and, but, because)"}, {"id": "eg3_10", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence is present tense?", "o": ["She ran fast.", "She will run fast.", "She runs fast.", "She had run fast."], "a": "She runs fast.", "e": "\\"Runs\\" is present tense"}, {"id": "eg3_11", "s": "english", "t": "Grammar", "l": 3, "q": "Identify the adverb: \\"The boy shouted loudly\\"", "o": ["The", "boy", "shouted", "loudly"], "a": "loudly", "e": "\\"Loudly\\" describes how = adverb"}, {"id": "eg3_12", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is a pronoun in \\"She left her bag at home\\"?", "o": ["left", "bag", "home", "She"], "a": "She", "e": "\\"She\\" is a pronoun replacing a person's name"}, {"id": "es3_01", "s": "english", "t": "Spelling", "l": 3, "q": "Which is spelled correctly?", "o": ["recieve", "receive", "receve", "receeve"], "a": "receive", "e": "i before e except after c → receive"}, {"id": "es3_02", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["necessary", "nessecary", "necesary", "neccessary"], "a": "necessary", "e": "One c, two s: necessary"}, {"id": "es3_03", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["beleive", "believe", "belive", "beleeve"], "a": "believe", "e": "believe: never beLIEve a lie"}, {"id": "es3_04", "s": "english", "t": "Spelling", "l": 3, "q": "Which is spelled correctly?", "o": ["separate", "seperate", "separete", "seperete"], "a": "separate", "e": "sep-a-rate: there's \\"a rat\\" in sepaRate"}, {"id": "es3_05", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["wierd", "wired", "weird", "werid"], "a": "weird", "e": "weird: exception to i-before-e rule"}, {"id": "es3_06", "s": "english", "t": "Spelling", "l": 3, "q": "Which is spelled correctly?", "o": ["accomodate", "accommodate", "acommodate", "acomodate"], "a": "accommodate", "e": "Accommodate: double c AND double m"}, {"id": "es3_07", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["occured", "occurred", "ocurred", "occured"], "a": "occurred", "e": "occurred: double c and double r"}, {"id": "es3_08", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["definately", "definetly", "definitely", "definitly"], "a": "definitely", "e": "definitely: there is \\"finite\\" inside it"}, {"id": "es3_09", "s": "english", "t": "Spelling", "l": 3, "q": "Which is spelled correctly?", "o": ["environment", "enviroment", "enviornment", "enviorment"], "a": "environment", "e": "en-vi-ron-ment"}, {"id": "es3_10", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["grammer", "gramar", "grammar", "gramer"], "a": "grammar", "e": "grammar ends in -ar not -er"}, {"id": "evr3_01", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Odd one out: apple, banana, carrot, grape", "o": ["apple", "banana", "carrot", "grape"], "a": "carrot", "e": "Apple, banana, grape are fruits. Carrot is a vegetable."}, {"id": "evr3_02", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "\\"Dog\\" is to \\"puppy\\" as \\"cat\\" is to…", "o": ["kitten", "kitty", "cub", "foal"], "a": "kitten", "e": "A puppy is a young dog; a kitten is a young cat"}, {"id": "evr3_03", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Odd one out: red, blue, circle, green", "o": ["red", "blue", "circle", "green"], "a": "circle", "e": "Red, blue, green are colours. Circle is a shape."}, {"id": "evr3_04", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "\\"Hot\\" is to \\"cold\\" as \\"day\\" is to…", "o": ["sun", "morning", "night", "week"], "a": "night", "e": "Hot/cold are opposites; day/night are opposites"}, {"id": "evr3_05", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What comes next: BIG, BIGGER, ___?", "o": ["BIGGEST", "BIGGESTEST", "MORE BIG", "MOST BIG"], "a": "BIGGEST", "e": "big → bigger → biggest (superlative)"}, {"id": "evr3_06", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Word meaning both \\"flat\\" and \\"even\\"?", "o": ["bumpy", "level", "high", "curved"], "a": "level", "e": "\\"Level\\" means both flat and even"}, {"id": "evr3_07", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "\\"Pen\\" is to \\"write\\" as \\"brush\\" is to…", "o": ["clean", "paint", "cut", "build"], "a": "paint", "e": "A pen writes; a brush paints"}, {"id": "evr3_08", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Odd one out: swimming, running, reading, cycling", "o": ["swimming", "running", "reading", "cycling"], "a": "reading", "e": "Swimming, running, cycling are physical exercise. Reading is not."}, {"id": "evr3_09", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "\\"Slow\\" is to \\"fast\\" as \\"cold\\" is to…", "o": ["icy", "cool", "hot", "warm"], "a": "hot", "e": "Slow/fast are opposites; cold/hot are opposites"}, {"id": "evr3_10", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What comes next: Monday, Tuesday, Wednesday, ___?", "o": ["Friday", "Thursday", "Saturday", "Sunday"], "a": "Thursday", "e": "Mon, Tue, Wed, Thu, Fri, Sat, Sun"}, {"id": "esa3_01", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Synonym for \\"big\\"?", "o": ["tiny", "small", "large", "narrow"], "a": "large", "e": "Big = large (same meaning)"}, {"id": "esa3_02", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Antonym for \\"brave\\"?", "o": ["bold", "courageous", "fearless", "cowardly"], "a": "cowardly", "e": "Brave ↔ cowardly (opposites)"}, {"id": "esa3_03", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Synonym for \\"begin\\"?", "o": ["finish", "end", "start", "stop"], "a": "start", "e": "Begin and start mean the same thing"}, {"id": "esa3_04", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Antonym for \\"noisy\\"?", "o": ["loud", "rowdy", "quiet", "busy"], "a": "quiet", "e": "Noisy ↔ quiet (opposites)"}, {"id": "esa3_05", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Synonym for \\"smart\\"?", "o": ["slow", "dull", "clever", "lazy"], "a": "clever", "e": "Smart and clever both mean intelligent"}, {"id": "esa3_06", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Antonym for \\"ancient\\"?", "o": ["old", "historic", "modern", "aged"], "a": "modern", "e": "Ancient ↔ modern (opposites)"}, {"id": "esa3_07", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Synonym for \\"frightened\\"?", "o": ["happy", "scared", "angry", "surprised"], "a": "scared", "e": "Frightened and scared both mean afraid"}, {"id": "esa3_08", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Antonym for \\"arrive\\"?", "o": ["come", "appear", "enter", "depart"], "a": "depart", "e": "Arrive ↔ depart (opposites)"}, {"id": "ess3_01", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which is a complete sentence?", "o": ["Running fast.", "The big dog.", "The cat sat on the mat.", "Because it rained."], "a": "The cat sat on the mat.", "e": "A complete sentence has a subject and a verb"}, {"id": "ess3_02", "s": "english", "t": "Sentence Structure", "l": 3, "q": "\\"I like football ___ I hate rain.\\" Which word makes it compound?", "o": ["because", "although", "but", "if"], "a": "but", "e": "Compound sentences use coordinating conjunctions (and, but, or, so)"}, {"id": "ess3_03", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which is a complex sentence?", "o": ["The dog ran.", "She sang and danced.", "Although it was cold, she swam.", "I ate fish."], "a": "Although it was cold, she swam.", "e": "Complex = main clause + subordinate clause"}, {"id": "ess3_04", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What type of sentence is \\"Please sit down\\"?", "o": ["Statement", "Question", "Exclamation", "Command"], "a": "Command", "e": "Commands (imperatives) tell someone to do something"}, {"id": "ess3_05", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What type is \\"The sun is shining\\"?", "o": ["Statement", "Question", "Command", "Exclamation"], "a": "Statement", "e": "A statement gives information and ends with a full stop"}, {"id": "ess3_06", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Subordinating conjunction in \\"She cried because she was sad\\"?", "o": ["She", "cried", "because", "sad"], "a": "because", "e": "\\"Because\\" introduces the reason clause"}, {"id": "erc3_01", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "\\"The old woman shuffled slowly along the icy path.\\" What does shuffled suggest?", "o": ["She was in a hurry", "She moved with short unsteady steps", "She was dancing", "She was running"], "a": "She moved with short unsteady steps", "e": "\\"Shuffle\\" = slow, dragging steps"}, {"id": "erc3_02", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "\\"The children's faces fell when they saw the cancelled sign.\\" What does this mean?", "o": ["Faces dropped off", "They looked down", "They became disappointed", "They were surprised"], "a": "They became disappointed", "e": "\\"Faces fell\\" = idiom meaning they became disappointed"}, {"id": "erc3_03", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "In a story, the \\"setting\\" is…", "o": ["What happens", "Who is in it", "Where and when it takes place", "Why characters act as they do"], "a": "Where and when it takes place", "e": "Setting = the time and place of the story"}, {"id": "erc3_04", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "\\"Despite the rain, Maya smiled.\\" What does despite mean?", "o": ["Because of", "In addition to", "Even though", "Thanks to"], "a": "Even though", "e": "\\"Despite\\" = even though / in spite of"}, {"id": "erc3_05", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is \\"inference\\" in reading?", "o": ["Finding stated facts", "Reading between the lines", "Copying sentences", "Summarising"], "a": "Reading between the lines", "e": "Inference = working out what is not directly stated"}, {"id": "erc3_06", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Read: The puppy wagged its tail and jumped up excitedly. How does the puppy feel?", "o": ["Happy", "Scared", "Tired", "Hungry"], "a": "Happy", "e": "Wagging tail and jumping show excitement and happiness."}, {"id": "erc3_07", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Read: The sky turned dark and thunder began to rumble. What will probably happen next?", "o": ["It will rain", "The sun will shine", "It will get hotter", "Birds will sing"], "a": "It will rain", "e": "Dark skies and thunder signal rain is coming."}, {"id": "erc3_08", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Read: She tiptoed past her parents room without making a sound. What does tiptoed suggest?", "o": ["She was being quiet", "She was in a hurry", "She was dancing", "She was sleepy"], "a": "She was being quiet", "e": "Tiptoeing means walking softly to avoid noise."}, {"id": "erc3_09", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Read: The old house creaked and groaned in the wind. What atmosphere does this create?", "o": ["Spooky", "Cheerful", "Peaceful", "Exciting"], "a": "Spooky", "e": "Creaking and groaning create an eerie atmosphere."}, {"id": "erc3_10", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Read: Tom smiled and opened the envelope carefully. What does carefully suggest?", "o": ["He cared about the contents", "He was bored", "He was angry", "He was in a rush"], "a": "He cared about the contents", "e": "Taking care suggests the letter mattered to him."}, {"id": "ess3_07", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence is a question?", "o": ["Have you seen my bag?", "I have seen your bag.", "Look for your bag.", "What a big bag!"], "a": "Have you seen my bag?", "e": "Questions end with a question mark."}, {"id": "ess3_08", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Choose the sentence that uses a conjunction correctly.", "o": ["I was tired but I kept going", "I was tired but", "I kept going but", "But I was tired"], "a": "I was tired but I kept going", "e": "A conjunction joins two complete clauses."}, {"id": "ess3_09", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence has a subordinate clause?", "o": ["After the rain stopped, we played outside", "We played outside", "The rain stopped", "We played and laughed"], "a": "After the rain stopped, we played outside", "e": "After the rain stopped depends on the main clause."}, {"id": "ess3_10", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Identify the adjective in: The tall boy ran quickly.", "o": ["tall", "boy", "ran", "quickly"], "a": "tall", "e": "Adjectives describe nouns. Tall describes boy."}, {"id": "mds3_07", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A pictogram shows 3 symbols for cats. Each symbol = 4 cats. How many cats?", "o": ["12", "3", "4", "9"], "a": "12", "e": "Multiply 3 symbols by 4 cats each."}, {"id": "mds3_08", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the mode of: 2, 4, 4, 5, 6, 6, 6, 8?", "o": ["6", "4", "5", "8"], "a": "6", "e": "The mode is the number that appears most often."}, {"id": "mds3_09", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "5 children scored: 6, 8, 7, 9, 10. What is the mean score?", "o": ["8", "7", "9", "10"], "a": "8", "e": "Add all scores (40) and divide by 5."}, {"id": "mds3_10", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A spinner has 4 equal sections: red, blue, green, yellow. Probability of blue?", "o": ["1/4", "1/2", "1/3", "1/8"], "a": "1/4", "e": "One blue section out of four equal sections."}, {"id": "mpa3_07", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle is 9cm long and 4cm wide. What is the perimeter?", "o": ["26cm", "36cm", "13cm", "18cm"], "a": "26cm", "e": "Perimeter = 2 × (9 + 4) = 2 × 13 = 26cm."}, {"id": "mpa3_08", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A square has sides of 7cm. What is its area?", "o": ["49cm²", "28cm²", "14cm²", "21cm²"], "a": "49cm²", "e": "Area = side × side = 7 × 7 = 49."}, {"id": "mpa3_09", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A room is 5m by 3m. How many 1m² tiles are needed to cover the floor?", "o": ["15", "8", "16", "10"], "a": "15", "e": "Area = 5 × 3 = 15 square metres."}, {"id": "mpa3_10", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A triangle has a base of 6cm and height of 4cm. What is its area?", "o": ["12cm²", "24cm²", "10cm²", "8cm²"], "a": "12cm²", "e": "Area = ½ × 6 × 4 = 12cm²."}, {"id": "mps3_07", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A shop sells pens for 35p each. How much do 8 pens cost?", "o": ["£2.80", "£2.40", "£3.50", "£2.00"], "a": "£2.80", "e": "35 × 8 = 280p = £2.80."}, {"id": "mps3_08", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A journey takes 2 hours 15 minutes. If you leave at 10:30, when do you arrive?", "o": ["12:45", "12:30", "12:15", "13:00"], "a": "12:45", "e": "10:30 + 2h15m = 12:45."}, {"id": "mps3_09", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Share 36 sweets equally between 4 children. How many each?", "o": ["9", "8", "12", "6"], "a": "9", "e": "36 ÷ 4 = 9."}, {"id": "mps3_10", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A bag of apples costs £1.20. How many bags can you buy with £6.00?", "o": ["5", "4", "6", "3"], "a": "5", "e": "600 ÷ 120 = 5 bags."}, {"id": "mas4_01", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A stadium has 45,670 seats. 38,895 are filled. How many are empty?", "o": ["6,775", "7,225", "6,875", "7,775"], "a": "6,775", "e": "Subtract 38,895 from 45,670."}, {"id": "mas4_02", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "What is 30,000 minus the sum of 12,456 and 9,784?", "o": ["7,760", "8,240", "22,240", "7,660"], "a": "7,760", "e": "Add the two numbers first, then subtract from 30,000."}, {"id": "mas4_03", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "5,400 minus X equals 2,750. What is X?", "o": ["2,650", "3,650", "2,750", "8,150"], "a": "2,650", "e": "Subtract 2,750 from 5,400."}, {"id": "mas4_04", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A diver is 12m below sea level and rises 5m. What is their new depth?", "o": ["-17m", "-7m", "7m", "-5m"], "a": "-7m", "e": "Add 5 to -12."}, {"id": "mas4_05", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A bank account has £450. A cheque for £525 is paid out. What is the balance?", "o": ["-£75", "£75", "-£125", "£0"], "a": "-£75", "e": "Subtract 525 from 450 giving a negative balance."}, {"id": "mas4_06", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Find the difference between the largest and smallest 5-digit numbers using digits 1,3,5,7,9.", "o": ["82,962", "84,192", "83,952", "86,420"], "a": "82,962", "e": "Subtract 13,579 from 97,531."}, {"id": "mas4_07", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A plane flies at 35,000ft, drops 12,450ft then rises 3,200ft. What is its height?", "o": ["25,750ft", "22,550ft", "25,850ft", "24,350ft"], "a": "25,750ft", "e": "Subtract the drop then add the rise."}, {"id": "mas4_08", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "What number is 15,000 less than 1,000,000?", "o": ["985,000", "850,000", "995,000", "975,000"], "a": "985,000", "e": "Subtract 15,000 from one million."}, {"id": "mas4_09", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "X + 14,350 = 20,000. Find X.", "o": ["5,650", "6,650", "5,750", "4,650"], "a": "5,650", "e": "Subtract 14,350 from 20,000."}, {"id": "mas4_10", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Three items cost £12.50, £15.75 and £4.20. Change from £40?", "o": ["£7.55", "£8.55", "£6.55", "£9.45"], "a": "£7.55", "e": "Sum the items and subtract from 40."}, {"id": "man4_01", "s": "maths", "t": "Angles", "l": 4, "q": "A triangle has angles of 45° and 75°. What is the third angle?", "o": ["60°", "50°", "70°", "80°"], "a": "60°", "e": "Angles in a triangle sum to 180°."}, {"id": "man4_02", "s": "maths", "t": "Angles", "l": 4, "q": "One angle on a straight line is 112°. What is the other angle?", "o": ["68°", "78°", "58°", "180°"], "a": "68°", "e": "Angles on a straight line sum to 180°."}, {"id": "man4_03", "s": "maths", "t": "Angles", "l": 4, "q": "An isosceles triangle has a top angle of 40°. What are the two base angles?", "o": ["70° each", "40° each", "60° each", "50° each"], "a": "70° each", "e": "Base angles are equal. (180-40)÷2=70."}, {"id": "man4_04", "s": "maths", "t": "Angles", "l": 4, "q": "A quadrilateral has angles 90°, 90° and 110°. What is the fourth angle?", "o": ["70°", "80°", "90°", "100°"], "a": "70°", "e": "Angles in a quadrilateral sum to 360°."}, {"id": "man4_05", "s": "maths", "t": "Angles", "l": 4, "q": "What is the interior angle of a regular hexagon?", "o": ["120°", "100°", "90°", "135°"], "a": "120°", "e": "Total sum 720° divided by 6 sides."}, {"id": "man4_06", "s": "maths", "t": "Angles", "l": 4, "q": "Two lines intersect. One angle is 55°. What is the vertically opposite angle?", "o": ["55°", "125°", "35°", "180°"], "a": "55°", "e": "Vertically opposite angles are always equal."}, {"id": "man4_07", "s": "maths", "t": "Angles", "l": 4, "q": "The exterior angle of a regular polygon is 40°. How many sides does it have?", "o": ["9", "8", "10", "12"], "a": "9", "e": "360 ÷ 40 = 9."}, {"id": "man4_08", "s": "maths", "t": "Angles", "l": 4, "q": "An angle is 3/5 of a right angle. How many degrees is it?", "o": ["54°", "60°", "45°", "30°"], "a": "54°", "e": "90 × 3/5 = 54."}, {"id": "man4_09", "s": "maths", "t": "Angles", "l": 4, "q": "A clock shows 3:00. What is the angle between the hands?", "o": ["90°", "45°", "180°", "120°"], "a": "90°", "e": "The hands are 1/4 of the way around 360°."}, {"id": "man4_10", "s": "maths", "t": "Angles", "l": 4, "q": "A reflex angle is between which two values?", "o": ["180° and 360°", "90° and 180°", "0° and 90°", "270° and 360°"], "a": "180° and 360°", "e": "Reflex angles are greater than 180° but less than 360°."}, {"id": "mds4_01", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Find the mean of 12, 15, 18 and 23.", "o": ["17", "18", "16", "19"], "a": "17", "e": "Add all numbers and divide by 4."}, {"id": "mds4_02", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A pie chart shows 25% of 120 people like apples. How many people is that?", "o": ["30", "25", "40", "60"], "a": "30", "e": "25% = one quarter of 120."}, {"id": "mds4_03", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "What is the range of: -5, 2, 8, 14, -2?", "o": ["19", "9", "14", "11"], "a": "19", "e": "Highest (14) minus lowest (-5) = 19."}, {"id": "mds4_04", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A bag has 20 marbles, 5 are red. Probability of picking red?", "o": ["1/4", "1/5", "1/2", "1/6"], "a": "1/4", "e": "5/20 simplifies to 1/4."}, {"id": "mds4_05", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Find the median of: 3, 11, 7, 9, 5.", "o": ["7", "11", "5", "9"], "a": "7", "e": "Order the numbers and find the middle: 3,5,7,9,11."}, {"id": "mds4_06", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "The mean of four numbers is 10. Three are 8, 12 and 11. Find the fourth.", "o": ["9", "10", "7", "11"], "a": "9", "e": "Total must be 40. 40 - 8 - 12 - 11 = 9."}, {"id": "mds4_07", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "In a survey of 200 people, 15% said No. How many said Yes?", "o": ["170", "30", "185", "150"], "a": "170", "e": "85% said Yes. 0.85 × 200 = 170."}, {"id": "mds4_08", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "What is the mode of: 4, 5, 5, 6, 7, 8, 8, 8?", "o": ["8", "5", "6", "4"], "a": "8", "e": "The mode is the most frequent value."}, {"id": "mds4_09", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A bar chart scale is 1cm = 2 children. A bar is 10cm high. How many children?", "o": ["20", "10", "40", "5"], "a": "20", "e": "Multiply bar height by the scale factor."}, {"id": "mds4_10", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A fair die is rolled. What is the probability of a prime number?", "o": ["1/2", "1/3", "2/3", "1/6"], "a": "1/2", "e": "Primes on a die: 2, 3, 5. That is 3/6 = 1/2."}, {"id": "mdc4_01", "s": "maths", "t": "Decimals", "l": 4, "q": "Multiply 3.4 by 2.5.", "o": ["8.5", "8.4", "7.5", "9.5"], "a": "8.5", "e": "34 × 25 = 850, then place decimal point."}, {"id": "mdc4_02", "s": "maths", "t": "Decimals", "l": 4, "q": "Divide 14.4 by 1.2.", "o": ["12", "1.2", "144", "120"], "a": "12", "e": "144 ÷ 12 = 12 after moving the decimal point."}, {"id": "mdc4_03", "s": "maths", "t": "Decimals", "l": 4, "q": "Order from smallest to largest: 0.304, 0.34, 0.034, 0.3.", "o": ["0.034, 0.3, 0.304, 0.34", "0.3, 0.034, 0.304, 0.34", "0.034, 0.304, 0.3, 0.34", "0.34, 0.304, 0.3, 0.034"], "a": "0.034, 0.3, 0.304, 0.34", "e": "Compare digit by digit from tenths."}, {"id": "mdc4_04", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 0.625 as a fraction in its simplest form?", "o": ["5/8", "3/4", "6/10", "5/6"], "a": "5/8", "e": "625/1000 simplifies to 5/8."}, {"id": "mdc4_05", "s": "maths", "t": "Decimals", "l": 4, "q": "Subtract 4.56 from 10.", "o": ["5.44", "6.44", "5.54", "4.44"], "a": "5.44", "e": "10.00 − 4.56 = 5.44."}, {"id": "mdc4_06", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 7/20 as a decimal?", "o": ["0.35", "0.7", "0.14", "0.3"], "a": "0.35", "e": "7 ÷ 20 = 0.35."}, {"id": "mdc4_07", "s": "maths", "t": "Decimals", "l": 4, "q": "A 2.5m ribbon is cut into 4 equal pieces. How long is each?", "o": ["0.625m", "0.5m", "0.75m", "0.65m"], "a": "0.625m", "e": "2.5 ÷ 4 = 0.625."}, {"id": "mdc4_08", "s": "maths", "t": "Decimals", "l": 4, "q": "Round 14.567 to two decimal places.", "o": ["14.57", "14.56", "14.60", "15.00"], "a": "14.57", "e": "The third decimal is 7, so round up."}, {"id": "mdc4_09", "s": "maths", "t": "Decimals", "l": 4, "q": "Find the value of 0.2 × 0.2 × 0.2.", "o": ["0.008", "0.08", "0.8", "0.0008"], "a": "0.008", "e": "2×2×2=8, then move decimal 3 places."}, {"id": "mdc4_10", "s": "maths", "t": "Decimals", "l": 4, "q": "Add 0.05 + 0.5 + 5.005.", "o": ["5.555", "5.105", "5.06", "6.05"], "a": "5.555", "e": "Align decimals carefully: 0.050+0.500+5.005."}, {"id": "mgs4_01", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "How many vertices does a triangular prism have?", "o": ["6", "5", "9", "4"], "a": "6", "e": "Two triangular faces each with 3 vertices = 6."}, {"id": "mgs4_02", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Point A is at (-2, 3). It is reflected in the x-axis. New coordinates?", "o": ["(-2,-3)", "(2,3)", "(2,-3)", "(3,-2)"], "a": "(-2,-3)", "e": "Reflection in x-axis flips the y-coordinate sign."}, {"id": "mgs4_03", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A shape is translated 3 left and 4 up from (1,1). New position?", "o": ["(-2,5)", "(4,5)", "(-2,-3)", "(4,-3)"], "a": "(-2,5)", "e": "Subtract 3 from x and add 4 to y."}, {"id": "mgs4_04", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "How many edges does a square-based pyramid have?", "o": ["8", "5", "4", "12"], "a": "8", "e": "4 on the base plus 4 rising to the apex."}, {"id": "mgs4_05", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "What 3D shape does a net of 6 equal squares make?", "o": ["Cube", "Cuboid", "Pyramid", "Prism"], "a": "Cube", "e": "A cube has six identical square faces."}, {"id": "mgs4_06", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Which is a property of a rhombus?", "o": ["Diagonals bisect at 90°", "All angles are 90°", "No parallel sides", "Only two equal sides"], "a": "Diagonals bisect at 90°", "e": "Rhombus diagonals cross at right angles."}, {"id": "mgs4_07", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A regular octagon has how many lines of symmetry?", "o": ["8", "4", "0", "16"], "a": "8", "e": "A regular polygon has lines of symmetry equal to its number of sides."}, {"id": "mgs4_08", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "What is the sum of interior angles in a pentagon?", "o": ["540°", "360°", "720°", "180°"], "a": "540°", "e": "Formula: (n-2) × 180 = 3 × 180 = 540."}, {"id": "mgs4_09", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A 3D shape has 1 curved face and 0 edges. What is it?", "o": ["Sphere", "Cone", "Cylinder", "Hemisphere"], "a": "Sphere", "e": "A sphere is one continuous curved surface."}, {"id": "mgs4_10", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A circle has a radius of 5cm. What is the diameter?", "o": ["10cm", "25cm", "5cm", "15cm"], "a": "10cm", "e": "Diameter = 2 × radius."}, {"id": "mmu4_01", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "How many millilitres are in 2.4 litres?", "o": ["2,400", "240", "24,000", "24"], "a": "2,400", "e": "Multiply litres by 1,000."}, {"id": "mmu4_02", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Convert 5.5 kilometres to metres.", "o": ["5,500", "550", "55,000", "55"], "a": "5,500", "e": "Multiply km by 1,000."}, {"id": "mmu4_03", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A film starts at 22:45 and lasts 130 minutes. What time does it end?", "o": ["00:55", "01:15", "23:55", "00:45"], "a": "00:55", "e": "22:45 + 2h10m = 00:55."}, {"id": "mmu4_04", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "How many grams are in 3.05 kilograms?", "o": ["3,050", "3,500", "305", "30,500"], "a": "3,050", "e": "Multiply kilograms by 1,000."}, {"id": "mmu4_05", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A scale shows 450g. How much more to make 1.2kg?", "o": ["750g", "650g", "850g", "550g"], "a": "750g", "e": "1,200 − 450 = 750g."}, {"id": "mmu4_06", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "What is 45mm in centimetres?", "o": ["4.5cm", "450cm", "0.45cm", "45cm"], "a": "4.5cm", "e": "Divide millimetres by 10."}, {"id": "mmu4_07", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A bottle holds 75cl. How many 150ml glasses can it fill?", "o": ["5", "2", "10", "4"], "a": "5", "e": "75cl = 750ml. 750 ÷ 150 = 5."}, {"id": "mmu4_08", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "How many seconds are in 12 minutes?", "o": ["720", "600", "1,200", "60"], "a": "720", "e": "12 × 60 = 720."}, {"id": "mmu4_09", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A race is 5,000m. A runner has done 3.2km. How far to go?", "o": ["1.8km", "2.8km", "1,200m", "1.5km"], "a": "1.8km", "e": "5km − 3.2km = 1.8km."}, {"id": "mmu4_10", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Which is heavier: 2,500g or 2.2kg?", "o": ["2,500g", "2.2kg", "Equal", "Neither"], "a": "2,500g", "e": "2.2kg = 2,200g, so 2,500g is heavier."}, {"id": "mpc4_01", "s": "maths", "t": "Percentages", "l": 4, "q": "Find 15% of 120.", "o": ["18", "12", "20", "15"], "a": "18", "e": "10% = 12, 5% = 6. Total = 18."}, {"id": "mpc4_02", "s": "maths", "t": "Percentages", "l": 4, "q": "A coat costs £80 and is reduced by 25%. What is the new price?", "o": ["£60", "£20", "£75", "£65"], "a": "£60", "e": "25% of 80 = 20. 80 − 20 = 60."}, {"id": "mpc4_03", "s": "maths", "t": "Percentages", "l": 4, "q": "Express 12 as a percentage of 40.", "o": ["30%", "25%", "40%", "12%"], "a": "30%", "e": "12/40 = 3/10 = 30%."}, {"id": "mpc4_04", "s": "maths", "t": "Percentages", "l": 4, "q": "A price rises from £50 to £60. What is the percentage increase?", "o": ["20%", "10%", "25%", "15%"], "a": "20%", "e": "Increase of 10 is 1/5 of original 50."}, {"id": "mpc4_05", "s": "maths", "t": "Percentages", "l": 4, "q": "What is 17.5% of 200?", "o": ["35", "17.5", "34", "40"], "a": "35", "e": "17.5 × 2 = 35."}, {"id": "mpc4_06", "s": "maths", "t": "Percentages", "l": 4, "q": "After a 10% discount an item costs £45. What was the original price?", "o": ["£50", "£49.50", "£55", "£40"], "a": "£50", "e": "90% = £45, so 100% = £50."}, {"id": "mpc4_07", "s": "maths", "t": "Percentages", "l": 4, "q": "Which is larger: 2/5 or 35%?", "o": ["2/5", "35%", "They are equal", "Cannot tell"], "a": "2/5", "e": "2/5 = 40%, which is larger than 35%."}, {"id": "mpc4_08", "s": "maths", "t": "Percentages", "l": 4, "q": "What is 120% of 50?", "o": ["60", "70", "55", "120"], "a": "60", "e": "100% of 50 is 50, plus 20% (10) = 60."}, {"id": "mpc4_09", "s": "maths", "t": "Percentages", "l": 4, "q": "In a class of 30, 60% are boys. How many girls?", "o": ["12", "18", "15", "20"], "a": "12", "e": "40% are girls. 0.4 × 30 = 12."}, {"id": "mpc4_10", "s": "maths", "t": "Percentages", "l": 4, "q": "VAT is 20%. An item costs £150 before VAT. What is the total?", "o": ["£180", "£170", "£150.20", "£200"], "a": "£180", "e": "20% of 150 = 30. 150 + 30 = 180."}, {"id": "mpa4_01", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Area of a triangle with base 8cm and height 5cm?", "o": ["20cm²", "40cm²", "13cm²", "26cm²"], "a": "20cm²", "e": "Area = ½ × base × height = ½ × 8 × 5."}, {"id": "mpa4_02", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Volume of a cuboid with sides 3cm, 4cm and 10cm?", "o": ["120cm³", "17cm³", "70cm³", "60cm³"], "a": "120cm³", "e": "Volume = length × width × height."}, {"id": "mpa4_03", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A square has a perimeter of 32cm. What is its area?", "o": ["64cm²", "32cm²", "16cm²", "128cm²"], "a": "64cm²", "e": "Side = 32 ÷ 4 = 8cm. Area = 8 × 8 = 64."}, {"id": "mpa4_04", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Area of a parallelogram with base 12cm and height 7cm?", "o": ["84cm²", "42cm²", "38cm²", "96cm²"], "a": "84cm²", "e": "Area = base × height = 12 × 7."}, {"id": "mpa4_05", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A 4×5 rectangle is joined to a 2×2 square. What is the total area?", "o": ["24cm²", "20cm²", "22cm²", "28cm²"], "a": "24cm²", "e": "20 + 4 = 24cm²."}, {"id": "mpa4_06", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A room is 6m by 4m. Carpet costs £15 per m². Total cost?", "o": ["£360", "£240", "£150", "£400"], "a": "£360", "e": "Area = 24m². 24 × 15 = £360."}, {"id": "mpa4_07", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Perimeter of a regular hexagon with 7cm sides?", "o": ["42cm", "49cm", "35cm", "56cm"], "a": "42cm", "e": "6 × 7 = 42cm."}, {"id": "mpa4_08", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Volume of a tank measuring 2m × 1m × 0.5m?", "o": ["1m³", "2m³", "0.5m³", "1.5m³"], "a": "1m³", "e": "2 × 1 × 0.5 = 1m³."}, {"id": "mpa4_09", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Area of a triangle is 30cm². Base is 10cm. Find the height.", "o": ["6cm", "3cm", "5cm", "10cm"], "a": "6cm", "e": "30 = ½ × 10 × h. So h = 6."}, {"id": "mpa4_10", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Perimeter of a semicircle with radius 10cm (π = 3.14)?", "o": ["51.4cm", "31.4cm", "41.4cm", "62.8cm"], "a": "51.4cm", "e": "Half circumference (31.4) + diameter (20) = 51.4."}, {"id": "mps4_01", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Share £45 in the ratio 2:7.", "o": ["£10 and £35", "£15 and £30", "£20 and £25", "£9 and £36"], "a": "£10 and £35", "e": "9 parts total. One part = £5. 2×5=£10, 7×5=£35."}, {"id": "mps4_02", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A car travels 150 miles in 3 hours. What is its speed?", "o": ["50mph", "45mph", "60mph", "30mph"], "a": "50mph", "e": "Speed = distance ÷ time = 150 ÷ 3."}, {"id": "mps4_03", "s": "maths", "t": "Problem Solving", "l": 4, "q": "If 3n + 5 = 20, what is n?", "o": ["5", "15", "7", "4"], "a": "5", "e": "3n = 15, so n = 5."}, {"id": "mps4_04", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A recipe for 4 people needs 200g flour. How much for 10 people?", "o": ["500g", "400g", "600g", "450g"], "a": "500g", "e": "50g per person × 10 = 500g."}, {"id": "mps4_05", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Red and blue balls are in ratio 3:5. There are 40 balls. How many are red?", "o": ["15", "25", "12", "24"], "a": "15", "e": "8 parts total. One part = 5. Red = 3 × 5 = 15."}, {"id": "mps4_06", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Two numbers sum to 25 and their difference is 7. What is the larger number?", "o": ["16", "18", "9", "15"], "a": "16", "e": "(25 + 7) ÷ 2 = 16."}, {"id": "mps4_07", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A watch loses 2 minutes every hour. How much does it lose in one day?", "o": ["48 minutes", "24 minutes", "60 minutes", "2 hours"], "a": "48 minutes", "e": "2 × 24 = 48 minutes."}, {"id": "mps4_08", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Train leaves at 09:15 and arrives at 11:05. How long is the journey?", "o": ["1h 50m", "2h 10m", "1h 10m", "1h 55m"], "a": "1h 50m", "e": "Count on from 09:15 to 11:05."}, {"id": "mps4_09", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A book has 240 pages. I have read 3/8 of it. How many pages are left?", "o": ["150", "90", "120", "180"], "a": "150", "e": "3/8 of 240 = 90 pages read. 240 - 90 = 150."}, {"id": "mps4_10", "s": "maths", "t": "Problem Solving", "l": 4, "q": "3 apples and 2 pears cost £1.80. Pears cost 30p each. How much is one apple?", "o": ["40p", "50p", "30p", "60p"], "a": "40p", "e": "2 pears = 60p. 180-60=120p for 3 apples. 120÷3=40p."}, {"id": "egr4_01", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the subordinate clause: While it was raining, we stayed inside.", "o": ["While it was raining", "we stayed inside", "raining", "inside"], "a": "While it was raining", "e": "This clause cannot stand alone."}, {"id": "egr4_02", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence is in the passive voice?", "o": ["The cake was eaten by the dog", "The dog ate the cake", "The dog is hungry", "Eating cake is fun"], "a": "The cake was eaten by the dog", "e": "The subject receives the action in passive voice."}, {"id": "egr4_03", "s": "english", "t": "Grammar", "l": 4, "q": "Choose the correct pronoun: Sarah and ___ went to the park.", "o": ["I", "me", "mine", "myself"], "a": "I", "e": "Use subject pronoun I when it is the subject."}, {"id": "egr4_04", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the object: The boy kicked the ball into the net.", "o": ["the ball", "The boy", "kicked", "the net"], "a": "the ball", "e": "The ball receives the action of the verb."}, {"id": "egr4_05", "s": "english", "t": "Grammar", "l": 4, "q": "Which verb is in the past perfect tense?", "o": ["had seen", "saw", "was seeing", "has seen"], "a": "had seen", "e": "Past perfect = had + past participle."}, {"id": "egr4_06", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the modal verb: You should arrive on time.", "o": ["should", "arrive", "on", "time"], "a": "should", "e": "Modal verbs express necessity or possibility."}, {"id": "egr4_07", "s": "english", "t": "Grammar", "l": 4, "q": "Find the abstract noun: The soldier showed great courage.", "o": ["courage", "soldier", "showed", "great"], "a": "courage", "e": "Abstract nouns refer to ideas or qualities."}, {"id": "egr4_08", "s": "english", "t": "Grammar", "l": 4, "q": "Which word is a relative pronoun?", "o": ["who", "she", "this", "him"], "a": "who", "e": "Relative pronouns introduce a relative clause."}, {"id": "egr4_09", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the determiner: Those birds are flying south.", "o": ["Those", "birds", "flying", "south"], "a": "Those", "e": "Determiners specify which noun is referred to."}, {"id": "egr4_10", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses the subjunctive correctly?", "o": ["If I were you I would go", "If I was you I would go", "I wish I was taller", "He suggests she goes"], "a": "If I were you I would go", "e": "Subjunctive uses were for hypothetical situations."}, {"id": "epu4_01", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses a semicolon correctly?", "o": ["I like tea; he likes coffee", "I like tea; and coffee", "I like; tea", "I like tea,; he likes coffee"], "a": "I like tea; he likes coffee", "e": "Semicolons link two independent clauses."}, {"id": "epu4_02", "s": "english", "t": "Punctuation", "l": 4, "q": "Where should the colon go? There are three colours red blue and green.", "o": ["After colours", "After There", "After three", "After red"], "a": "After colours", "e": "A colon introduces a list after a complete clause."}, {"id": "epu4_03", "s": "english", "t": "Punctuation", "l": 4, "q": "Which shows correct plural possession for boys?", "o": ["The boys' bags", "The boys bags", "The boy bags", "The boys bag"], "a": "The boys' bags", "e": "Apostrophe after the s for regular plurals."}, {"id": "epu4_04", "s": "english", "t": "Punctuation", "l": 4, "q": "In Mr Jones, the baker, was late — what is enclosed by parenthetic commas?", "o": ["the baker", "Mr Jones", "was late", "Jones"], "a": "the baker", "e": "Parenthetic commas enclose extra information."}, {"id": "epu4_05", "s": "english", "t": "Punctuation", "l": 4, "q": "Which speech punctuation is correct?", "o": ["Go away! shouted Tom.", "Go away! Shouted Tom.", "Go away!, shouted Tom.", "Go away! shouted tom."], "a": "Go away! shouted Tom.", "e": "Speech tag starts lowercase; Tom is a proper noun."}, {"id": "epu4_06", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses its correctly?", "o": ["The dog wagged its tail", "Its raining outside", "The dog wagged it is tail", "Its cold today"], "a": "The dog wagged its tail", "e": "Its (no apostrophe) shows possession."}, {"id": "epu4_07", "s": "english", "t": "Punctuation", "l": 4, "q": "Which is punctuated correctly?", "o": ["Stop! he cried. We are here.", "Stop, he cried, we are here.", "Stop! he cried, we are here.", "Stop, he cried. We are here."], "a": "Stop! he cried. We are here.", "e": "Full stop ends the speech tag sentence."}, {"id": "epu4_08", "s": "english", "t": "Punctuation", "l": 4, "q": "What punctuation is missing from: The childrens toys were scattered?", "o": ["Apostrophe in children's", "A comma", "A colon", "A hyphen"], "a": "Apostrophe in children's", "e": "Children is already plural so apostrophe before s."}, {"id": "epu4_09", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses a hyphen correctly?", "o": ["The thirty-two cats", "The thirty two-cats", "The-thirty two cats", "The thirty two cats"], "a": "The thirty-two cats", "e": "Hyphens join compound numbers 21 to 99."}, {"id": "epu4_10", "s": "english", "t": "Punctuation", "l": 4, "q": "Which uses brackets correctly?", "o": ["The sun (a star) is hot.", "The sun a (star) is hot.", "(The sun) a star is hot.", "The sun a star (is hot)."], "a": "The sun (a star) is hot.", "e": "Brackets enclose parenthetical information."}, {"id": "erc4_01", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: The ancient forest had stood for centuries, its roots tangled with secrets. What does ancient suggest?", "o": ["Very old", "Scary", "Quiet", "Large"], "a": "Very old", "e": "Ancient means from long ago."}, {"id": "erc4_02", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: Thunder rumbled like an angry beast, shaking the window panes. What figure of speech is used?", "o": ["Simile", "Metaphor", "Onomatopoeia", "Personification"], "a": "Simile", "e": "Comparing using like makes it a simile."}, {"id": "erc4_03", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: Lucy sighed, looking at the charred remains of her dinner. How does Lucy feel?", "o": ["Disappointed", "Excited", "Happy", "Tired"], "a": "Disappointed", "e": "Charred remains suggest ruined food."}, {"id": "erc4_04", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: The neon lights flickered, casting long eerie shadows across the alley. What is the atmosphere?", "o": ["Mysterious", "Joyful", "Bright", "Ordinary"], "a": "Mysterious", "e": "Eerie and flickering lights create mystery."}, {"id": "erc4_05", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: He tiptoed across the landing, careful not to wake the sleeping giant. Why did he tiptoe?", "o": ["To stay quiet", "He was cold", "He was fast", "His feet hurt"], "a": "To stay quiet", "e": "Tiptoeing avoids making noise."}, {"id": "erc4_06", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: The mountain peak was draped in a blanket of pristine snow. What does pristine mean?", "o": ["Unspoiled", "Cold", "Heavy", "Old"], "a": "Unspoiled", "e": "Pristine means clean and untouched."}, {"id": "erc4_07", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: A lone wolf howled, a mournful sound echoing through the valley. What does mournful mean?", "o": ["Sad", "Loud", "Scary", "Musical"], "a": "Sad", "e": "Mournful expresses grief or sadness."}, {"id": "erc4_08", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: The clock ticked relentlessly as the exam began. What does relentlessly suggest?", "o": ["Without stopping", "Slowly", "Loudly", "Suddenly"], "a": "Without stopping", "e": "Relentlessly means in an unceasing way."}, {"id": "erc4_09", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: Her eyes sparkled like diamonds when she saw the gift. Why did her eyes sparkle?", "o": ["She was happy", "She was crying", "The room was bright", "She was tired"], "a": "She was happy", "e": "Sparkling eyes indicate joy or excitement."}, {"id": "erc4_10", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Read: The rusty gate groaned in protest as it was forced open. What is being personified?", "o": ["The gate", "The person", "The air", "The hinges"], "a": "The gate", "e": "Groaning in protest gives human qualities to the gate."}, {"id": "ess4_01", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the complex sentence.", "o": ["I went home because I was tired", "I went home and I slept", "I went home", "I was tired"], "a": "I went home because I was tired", "e": "Contains an independent and a dependent clause."}, {"id": "ess4_02", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the fronted adverbial: Late that night, the stars came out.", "o": ["Late that night", "the stars", "came out", "night"], "a": "Late that night", "e": "The opening phrase tells us when — it is fronted."}, {"id": "ess4_03", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Passive version of: The chef prepared the meal.", "o": ["The meal was prepared by the chef", "The chef was preparing the meal", "The meal is prepared", "Preparing was done by the chef"], "a": "The meal was prepared by the chef", "e": "The object becomes the subject in passive voice."}, {"id": "ess4_04", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the relative clause: The girl who won the race is my friend.", "o": ["who won the race", "The girl", "is my friend", "the race"], "a": "who won the race", "e": "This clause gives more information about the girl."}, {"id": "ess4_05", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence has a dangling modifier?", "o": ["Running for the bus, my hat fell off", "Running for the bus, I lost my hat", "My hat fell off while I ran", "I lost my hat as I ran"], "a": "Running for the bus, my hat fell off", "e": "The hat cannot run for the bus."}, {"id": "ess4_06", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What type of sentence is: Go to your room!", "o": ["Imperative", "Declarative", "Interrogative", "Exclamatory"], "a": "Imperative", "e": "Imperative sentences give commands."}, {"id": "ess4_07", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the prepositional phrase: The cat sat under the table.", "o": ["under the table", "The cat", "sat", "table"], "a": "under the table", "e": "Prepositional phrase shows location."}, {"id": "ess4_08", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence is compound-complex?", "o": ["I stayed but he left because it rained", "I stayed because it rained", "I stayed and he left", "I stayed"], "a": "I stayed but he left because it rained", "e": "Two independent clauses plus one dependent clause."}, {"id": "ess4_09", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the appositive: My dog, a beagle, loves bones.", "o": ["a beagle", "My dog", "loves", "bones"], "a": "a beagle", "e": "An appositive renames the noun beside it."}, {"id": "ess4_10", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Find the auxiliary verb: They are playing football.", "o": ["are", "playing", "They", "football"], "a": "are", "e": "Auxiliary verbs help form tenses."}, {"id": "esp4_01", "s": "english", "t": "Spelling", "l": 4, "q": "Which is the correct spelling?", "o": ["accommodate", "acommodate", "accommodat", "acommodat"], "a": "accommodate", "e": "Double c and double m: ac-com-mo-date."}, {"id": "esp4_02", "s": "english", "t": "Spelling", "l": 4, "q": "Identify the correctly spelled word.", "o": ["necessary", "neccessary", "necesary", "neccesary"], "a": "necessary", "e": "One c, double s: nec-es-sa-ry."}, {"id": "esp4_03", "s": "english", "t": "Spelling", "l": 4, "q": "Which word has a silent letter?", "o": ["knight", "night", "kite", "light"], "a": "knight", "e": "The k is silent in knight."}, {"id": "esp4_04", "s": "english", "t": "Spelling", "l": 4, "q": "Choose the correct spelling for a feeling of shame.", "o": ["embarrass", "embarass", "embaras", "embarras"], "a": "embarrass", "e": "Double r and double s: em-bar-rass."}, {"id": "esp4_05", "s": "english", "t": "Spelling", "l": 4, "q": "Which ending is correct: independ___?", "o": ["ent", "ant", "int", "unt"], "a": "ent", "e": "Independent ends in -ent."}, {"id": "esp4_06", "s": "english", "t": "Spelling", "l": 4, "q": "Correct spelling meaning: without doubt.", "o": ["definitely", "definately", "definitly", "definatly"], "a": "definitely", "e": "Comes from finite: def-in-ite-ly."}, {"id": "esp4_07", "s": "english", "t": "Spelling", "l": 4, "q": "Which is correct?", "o": ["separate", "seperate", "separat", "separete"], "a": "separate", "e": "Remember: there is a rat in sep-a-rate."}, {"id": "esp4_08", "s": "english", "t": "Spelling", "l": 4, "q": "Choose the correctly spelled word.", "o": ["occurrence", "ocurrence", "occurence", "ocurence"], "a": "occurrence", "e": "Double c and double r: oc-cur-rence."}, {"id": "esp4_09", "s": "english", "t": "Spelling", "l": 4, "q": "Which word is spelled correctly?", "o": ["queue", "quene", "qweue", "queu"], "a": "queue", "e": "Queue — five letters, three silent."}, {"id": "esp4_10", "s": "english", "t": "Spelling", "l": 4, "q": "What is the correct plural of cactus?", "o": ["cacti", "cactuses", "cactuss", "cactis"], "a": "cacti", "e": "Latin plurals often end in -i."}, {"id": "esa4_01", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find the synonym for melancholy.", "o": ["sad", "happy", "angry", "excited"], "a": "sad", "e": "Melancholy means a deep pensive sadness."}, {"id": "esa4_02", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find the antonym for benevolent.", "o": ["cruel", "kind", "helpful", "generous"], "a": "cruel", "e": "Benevolent means kind; its opposite is cruel."}, {"id": "esa4_03", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find the synonym for tenacious.", "o": ["persistent", "weak", "lazy", "fast"], "a": "persistent", "e": "Tenacious means holding on firmly."}, {"id": "esa4_04", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find the antonym for expand.", "o": ["shrink", "grow", "stretch", "enlarge"], "a": "shrink", "e": "Expand means grow larger; shrink means get smaller."}, {"id": "esa4_05", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Synonym for precarious.", "o": ["unstable", "safe", "certain", "steady"], "a": "unstable", "e": "Precarious means likely to fall or fail."}, {"id": "esa4_06", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Antonym for obscure.", "o": ["clear", "hidden", "dark", "vague"], "a": "clear", "e": "Obscure means hard to understand; clear is the opposite."}, {"id": "esa4_07", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Synonym for meticulous.", "o": ["careful", "messy", "quick", "careless"], "a": "careful", "e": "Meticulous means great attention to detail."}, {"id": "esa4_08", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Antonym for fragile.", "o": ["strong", "delicate", "thin", "light"], "a": "strong", "e": "Fragile means easily broken; strong is the opposite."}, {"id": "esa4_09", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Synonym for candid.", "o": ["honest", "secretive", "dishonest", "timid"], "a": "honest", "e": "Candid means truthful and straightforward."}, {"id": "esa4_10", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Antonym for amateur.", "o": ["professional", "beginner", "learner", "novice"], "a": "professional", "e": "Amateur is unpaid; professional is paid and skilled."}, {"id": "evr4_01", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Complete the word SH_PE (clue: a form or outline).", "o": ["A", "I", "O", "E"], "a": "A", "e": "The word is SHAPE."}, {"id": "evr4_02", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the word that does not belong: Apple, Potato, Orange, Banana.", "o": ["Potato", "Apple", "Orange", "Banana"], "a": "Potato", "e": "Potato is a vegetable; the others are fruits."}, {"id": "evr4_03", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "If A=1, B=2, C=3... what does the code 7-15-1-20 spell?", "o": ["GOAT", "BOAT", "COAT", "MOAT"], "a": "GOAT", "e": "G=7, O=15, A=1, T=20."}, {"id": "evr4_04", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Big is to small as hot is to ___.", "o": ["cold", "warm", "fire", "sun"], "a": "cold", "e": "These are opposite pairs."}, {"id": "evr4_05", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the hidden word in: He made a fast art deal.", "o": ["star", "made", "fast", "deal"], "a": "star", "e": "fast + art contains the hidden word: st-ar."}, {"id": "evr4_06", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which is a compound word?", "o": ["Football", "Player", "Running", "Green"], "a": "Football", "e": "Foot + ball join to form one new word."}, {"id": "evr4_07", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word can follow back to make a new word?", "o": ["bone", "side", "front", "top"], "a": "bone", "e": "Backbone is a compound word."}, {"id": "evr4_08", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the missing letter: PLA_E (clue: used for food).", "o": ["T", "N", "C", "K"], "a": "T", "e": "The word is PLATE."}, {"id": "evr4_09", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Shoe is to foot as glove is to ___.", "o": ["hand", "finger", "arm", "leg"], "a": "hand", "e": "Both items are worn on those body parts."}, {"id": "evr4_10", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word is an anagram of SILENT?", "o": ["LISTEN", "TINSEL", "ENLIST", "INLETS"], "a": "LISTEN", "e": "All four are anagrams of SILENT."}, {"id": "evo4_01", "s": "english", "t": "Vocabulary", "l": 4, "q": "The volcano is dormant. What does dormant mean?", "o": ["Inactive", "Exploding", "Dangerous", "Extinct"], "a": "Inactive", "e": "Dormant means temporarily inactive or sleeping."}, {"id": "evo4_02", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which suffix turns act into a person who acts?", "o": ["or", "er", "ed", "ing"], "a": "or", "e": "An actor performs actions on stage or screen."}, {"id": "evo4_03", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does the prefix micro- mean?", "o": ["Small", "Large", "Fast", "Many"], "a": "Small", "e": "Micro comes from Greek meaning small."}, {"id": "evo4_04", "s": "english", "t": "Vocabulary", "l": 4, "q": "Choose the most precise word: The ___ building was 100 stories tall.", "o": ["towering", "big", "high", "long"], "a": "towering", "e": "Towering is more vivid and precise than tall."}, {"id": "evo4_05", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which words belong to the word family of electric?", "o": ["All of these", "electricity only", "electron only", "electronic only"], "a": "All of these", "e": "Electricity, electron and electronic share the root."}, {"id": "evo4_06", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does the suffix -less mean?", "o": ["Without", "With", "Full of", "More"], "a": "Without", "e": "-less means lacking or without something."}, {"id": "evo4_07", "s": "english", "t": "Vocabulary", "l": 4, "q": "The ___ of the flowers was lovely. Choose the correct word.", "o": ["scent", "sent", "cent", "send"], "a": "scent", "e": "Scent refers to a smell or fragrance."}, {"id": "evo4_08", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does verify mean?", "o": ["Check", "Hide", "Lose", "Guess"], "a": "Check", "e": "Verify means to confirm something is true."}, {"id": "evo4_09", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which word describes someone very brave?", "o": ["valiant", "timid", "clever", "swift"], "a": "valiant", "e": "Valiant means possessing or showing great courage."}, {"id": "evo4_10", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which prefix means against?", "o": ["anti-", "pro-", "sub-", "pre-"], "a": "anti-", "e": "Anti- means against, as in antibiotic."}, {"id": "egr2_01", "s": "english", "t": "Grammar", "l": 2, "q": "Find the noun in this sentence: The cat ran fast.", "o": ["cat", "ran", "fast", "The"], "a": "cat", "e": "A noun is a naming word for a person or thing."}, {"id": "egr2_02", "s": "english", "t": "Grammar", "l": 2, "q": "Find the verb in this sentence: Sam jumped over the wall.", "o": ["Sam", "jumped", "over", "wall"], "a": "jumped", "e": "A verb is a doing or action word."}, {"id": "egr2_03", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is an adjective? The blue bird sang.", "o": ["sang", "bird", "blue", "The"], "a": "blue", "e": "Adjectives describe a noun."}, {"id": "egr2_04", "s": "english", "t": "Grammar", "l": 2, "q": "Choose the correct word: The dogs ___ barking loudly.", "o": ["is", "are", "was", "am"], "a": "are", "e": "Use are for more than one dog."}, {"id": "egr2_05", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is a pronoun?", "o": ["He", "House", "Happy", "Hop"], "a": "He", "e": "A pronoun takes the place of a noun."}, {"id": "egr2_06", "s": "english", "t": "Grammar", "l": 2, "q": "What is the plural of child?", "o": ["childs", "childes", "children", "childrens"], "a": "children", "e": "Children is the correct plural of child."}, {"id": "egr2_07", "s": "english", "t": "Grammar", "l": 2, "q": "Find the adverb: She walked slowly to school.", "o": ["She", "walked", "slowly", "school"], "a": "slowly", "e": "Adverbs tell us how an action is done."}, {"id": "egr2_08", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is a connective?", "o": ["and", "apple", "angry", "above"], "a": "and", "e": "Connectives like and join words or sentences."}, {"id": "egr2_09", "s": "english", "t": "Grammar", "l": 2, "q": "Choose the correct plural of mouse.", "o": ["mouses", "mices", "mice", "mouse"], "a": "mice", "e": "The plural of mouse is mice."}, {"id": "egr2_10", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is a proper noun?", "o": ["London", "city", "town", "place"], "a": "London", "e": "Proper nouns for places start with a capital letter."}, {"id": "egr2_11", "s": "english", "t": "Grammar", "l": 2, "q": "Find the verb: The sun shines brightly.", "o": ["sun", "shines", "brightly", "The"], "a": "shines", "e": "Shines is the action in this sentence."}, {"id": "egr2_12", "s": "english", "t": "Grammar", "l": 2, "q": "Choose the correct word: Yesterday, I ___ to the park.", "o": ["go", "going", "went", "gone"], "a": "went", "e": "Went is the past tense of go."}, {"id": "egr2_13", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is an adjective? I have a fuzzy hat.", "o": ["I", "have", "fuzzy", "hat"], "a": "fuzzy", "e": "Fuzzy describes the hat."}, {"id": "egr2_14", "s": "english", "t": "Grammar", "l": 2, "q": "Find the noun: The big red bus stopped.", "o": ["big", "red", "bus", "stopped"], "a": "bus", "e": "Bus is the name of the vehicle."}, {"id": "egr2_15", "s": "english", "t": "Grammar", "l": 2, "q": "Which of these is a pronoun?", "o": ["they", "book", "table", "happy"], "a": "they", "e": "They is a pronoun used instead of a noun."}, {"id": "egr2_16", "s": "english", "t": "Grammar", "l": 2, "q": "What is the plural of box?", "o": ["boxs", "boxies", "boxes", "box"], "a": "boxes", "e": "Add es to words ending in x."}, {"id": "egr2_17", "s": "english", "t": "Grammar", "l": 2, "q": "Find the connective: It was cold so I wore a coat.", "o": ["cold", "so", "wore", "coat"], "a": "so", "e": "So joins the two ideas together."}, {"id": "egr2_18", "s": "english", "t": "Grammar", "l": 2, "q": "Which word is an adverb?", "o": ["happily", "happy", "happiness", "happen"], "a": "happily", "e": "Happily describes how something is done."}, {"id": "egr2_19", "s": "english", "t": "Grammar", "l": 2, "q": "Choose the correct word: We ___ playing a game.", "o": ["is", "am", "are", "was"], "a": "are", "e": "Use are with the pronoun we."}, {"id": "egr2_20", "s": "english", "t": "Grammar", "l": 2, "q": "Find the adjective: The tiny ant carried a leaf.", "o": ["tiny", "ant", "carried", "leaf"], "a": "tiny", "e": "Tiny describes the size of the ant."}, {"id": "epu2_01", "s": "english", "t": "Punctuation", "l": 2, "q": "Which sentence needs a question mark?", "o": ["What time is it", "I am hungry", "Look at that", "Stop now"], "a": "What time is it", "e": "Questions need a question mark at the end."}, {"id": "epu2_02", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word needs a capital letter? my friend is called Tom.", "o": ["my", "friend", "is", "called"], "a": "my", "e": "The first word of a sentence needs a capital."}, {"id": "epu2_03", "s": "english", "t": "Punctuation", "l": 2, "q": "Where should the comma go? I need eggs milk and bread.", "o": ["after eggs", "after milk", "after and", "after bread"], "a": "after eggs", "e": "Use commas to separate items in a list."}, {"id": "epu2_04", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word uses an apostrophe correctly?", "o": ["cannot", "dont", "don't", "dogs"], "a": "don't", "e": "Don't is short for do not."}, {"id": "epu2_05", "s": "english", "t": "Punctuation", "l": 2, "q": "Which sentence is correct?", "o": ["Where is my bag?", "Where is my bag.", "Where is my bag!", "Where is my bag"], "a": "Where is my bag?", "e": "This is a question so it needs a question mark."}, {"id": "epu2_06", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word needs a capital letter?", "o": ["tuesday", "apple", "banana", "carrot"], "a": "tuesday", "e": "Days of the week always need a capital letter."}, {"id": "epu2_07", "s": "english", "t": "Punctuation", "l": 2, "q": "Where does the apostrophe go in: I cant go outside.", "o": ["can't", "I'm", "outsid'e", "ca'nt"], "a": "can't", "e": "The apostrophe replaces the missing o in cannot."}, {"id": "epu2_08", "s": "english", "t": "Punctuation", "l": 2, "q": "Which sentence has the full stop in the right place?", "o": ["The sun. is hot", "The sun is hot.", "The. sun is hot", "The sun is. hot"], "a": "The sun is hot.", "e": "Full stops go at the end of a sentence."}, {"id": "epu2_09", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word is short for it is?", "o": ["Its", "It's", "Is it", "Ist"], "a": "It's", "e": "It's uses an apostrophe to show letters are missing."}, {"id": "epu2_10", "s": "english", "t": "Punctuation", "l": 2, "q": "Which of these names needs a capital letter?", "o": ["sarah", "girl", "sister", "friend"], "a": "sarah", "e": "Names of people are proper nouns and need capitals."}, {"id": "epu2_11", "s": "english", "t": "Punctuation", "l": 2, "q": "What punctuation mark is needed: Help me___", "o": [".", "?", "!", ","], "a": "!", "e": "An exclamation mark shows strong feeling."}, {"id": "epu2_12", "s": "english", "t": "Punctuation", "l": 2, "q": "How many capital letters are needed in: ben went to london.", "o": ["1", "2", "3", "0"], "a": "2", "e": "Ben and London both need capitals."}, {"id": "epu2_13", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word is short for you are?", "o": ["Your", "Youre", "You're", "Yours"], "a": "You're", "e": "You're is the contraction for you are."}, {"id": "epu2_14", "s": "english", "t": "Punctuation", "l": 2, "q": "Where is the comma missing? Red blue and green are colours.", "o": ["after Red", "after blue", "after green", "after colours"], "a": "after Red", "e": "A comma separates the first two items in a list."}, {"id": "epu2_15", "s": "english", "t": "Punctuation", "l": 2, "q": "Which of these is a question?", "o": ["I like cake", "Can I have cake", "Cake is nice", "Stop eating cake"], "a": "Can I have cake", "e": "This sentence is asking for something."}, {"id": "epu2_16", "s": "english", "t": "Punctuation", "l": 2, "q": "Which word should have a capital letter?", "o": ["france", "mountain", "river", "ocean"], "a": "france", "e": "Countries always start with a capital letter."}, {"id": "epu2_17", "s": "english", "t": "Punctuation", "l": 2, "q": "Which shows correct possession?", "o": ["the boys hat", "the boy's hat", "the boys hat", "the boyss hat"], "a": "the boy's hat", "e": "Use apostrophe and s to show something belongs."}, {"id": "epu2_18", "s": "english", "t": "Punctuation", "l": 2, "q": "What is the contraction for was not?", "o": ["wasnt", "wasnot", "wasn't", "was'nt"], "a": "wasn't", "e": "The apostrophe goes between n and t."}, {"id": "epu2_19", "s": "english", "t": "Punctuation", "l": 2, "q": "Which sentence is punctuated correctly?", "o": ["I am tired", " said Sam.", "I am tired\\" said Sam.", "I am tired", "said Sam.", "I am tired.\\" Said Sam."], "a": "\\"I am tired,\\" said Sam.", "e": "Speech marks go around the words spoken."}, {"id": "epu2_20", "s": "english", "t": "Punctuation", "l": 2, "q": "Which is short for do not?", "o": ["dont", "do not", "don't", "dno't"], "a": "don't", "e": "Don't is the contraction for do not."}, {"id": "erc2_01", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The tiger has orange fur with black stripes. What colour are the stripes?", "o": ["Orange", "Black", "White", "Yellow"], "a": "Black", "e": "The text says the stripes are black."}, {"id": "erc2_02", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Bella put on her red boots to jump in puddles. What colour are the boots?", "o": ["Blue", "Red", "Green", "Yellow"], "a": "Red", "e": "The text states the boots are red."}, {"id": "erc2_03", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Every morning, Tim eats cereal for breakfast. What does Tim eat for breakfast?", "o": ["Toast", "Cereal", "Fruit", "Eggs"], "a": "Cereal", "e": "The passage says he eats cereal."}, {"id": "erc2_04", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The blue bird built a nest in the oak tree. Where is the nest?", "o": ["In a bush", "In an oak tree", "On the ground", "In a box"], "a": "In an oak tree", "e": "The nest is in the oak tree."}, {"id": "erc2_05", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Sarah went to the park to play on the swings. Why did she go?", "o": ["To play football", "To play on swings", "To have a picnic", "To see ducks"], "a": "To play on swings", "e": "The text says she went to play on swings."}, {"id": "erc2_06", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The baker made ten chocolate cupcakes. How many cupcakes were made?", "o": ["Two", "Five", "Ten", "Twelve"], "a": "Ten", "e": "The text mentions there were ten cupcakes."}, {"id": "erc2_07", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: It was raining, so Mark took his yellow umbrella. What did he take?", "o": ["A hat", "A coat", "An umbrella", "Boots"], "a": "An umbrella", "e": "He took an umbrella because it was raining."}, {"id": "erc2_08", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: My cat Whiskers likes to sleep on the soft rug. Where does the cat sleep?", "o": ["On the bed", "On a chair", "On the rug", "Outside"], "a": "On the rug", "e": "Whiskers likes to sleep on the rug."}, {"id": "erc2_09", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The sun is very hot and bright today. How is the weather?", "o": ["Cold", "Rainy", "Hot and bright", "Snowing"], "a": "Hot and bright", "e": "The text says the sun is hot and bright."}, {"id": "erc2_10", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: We are going to the beach on Saturday. When are we going?", "o": ["Friday", "Saturday", "Sunday", "Monday"], "a": "Saturday", "e": "The passage says they go on Saturday."}, {"id": "erc2_11", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The rabbit hopped into the garden to eat a crunchy carrot. What did it eat?", "o": ["An apple", "A carrot", "Grass", "A leaf"], "a": "A carrot", "e": "The rabbit ate a crunchy carrot."}, {"id": "erc2_12", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Dad is washing the car in the driveway. What is Dad washing?", "o": ["The windows", "The dog", "The car", "The bike"], "a": "The car", "e": "The text says Dad is washing the car."}, {"id": "erc2_13", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: There are three books on the wooden table. How many books?", "o": ["One", "Two", "Three", "Four"], "a": "Three", "e": "The passage states there are three books."}, {"id": "erc2_14", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Lily has a pet hamster named Pip. What kind of animal is Pip?", "o": ["A cat", "A dog", "A hamster", "A mouse"], "a": "A hamster", "e": "Pip is a pet hamster."}, {"id": "erc2_15", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The elephant has very big ears. What does the elephant have?", "o": ["Big ears", "Small ears", "No ears", "Long ears"], "a": "Big ears", "e": "The elephant is described as having big ears."}, {"id": "erc2_16", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: At the zoo, we saw a tall giraffe eating leaves. What was it doing?", "o": ["Running", "Sleeping", "Eating leaves", "Drinking"], "a": "Eating leaves", "e": "The text says it was eating leaves."}, {"id": "erc2_17", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: The boys played football in the field after school. Where did they play?", "o": ["In the garden", "In the park", "In the field", "At school"], "a": "In the field", "e": "They played football in the field."}, {"id": "erc2_18", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Amy found a shiny silver coin on the floor. What did Amy find?", "o": ["A toy", "A coin", "A key", "A ring"], "a": "A coin", "e": "Amy found a shiny silver coin."}, {"id": "erc2_19", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: It was a very windy day and the kites flew high. What flew high?", "o": ["Birds", "Planes", "Kites", "Balloons"], "a": "Kites", "e": "The text says the kites flew high."}, {"id": "erc2_20", "s": "english", "t": "Reading Comprehension", "l": 2, "q": "Read: Farmer Joe milked the cows early this morning. Who milked the cows?", "o": ["Farmer Joe", "Farmer Bob", "Farmer Sam", "Farmer Tom"], "a": "Farmer Joe", "e": "Farmer Joe is the person who milked the cows."}, {"id": "ess2_01", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the noun in: The dog barked.", "o": ["The", "dog", "barked", "loudly"], "a": "dog", "e": "Dog is the name of the animal."}, {"id": "ess2_02", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the verb in: We ate lunch.", "o": ["We", "ate", "lunch", "big"], "a": "ate", "e": "Ate is the action word."}, {"id": "ess2_03", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the adjective in: He has a red car.", "o": ["He", "has", "red", "car"], "a": "red", "e": "Red describes the colour of the car."}, {"id": "ess2_04", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Is this a statement or a question: Where are you?", "o": ["Statement", "Question", "Command", "Exclamation"], "a": "Question", "e": "It asks something and ends with a question mark."}, {"id": "ess2_05", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Which sentence makes sense?", "o": ["The dog cat", "Cat the dog", "The cat sat", "Sat cat the"], "a": "The cat sat", "e": "This sentence has a subject and a verb."}, {"id": "ess2_06", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the noun: The apple is sweet.", "o": ["The", "apple", "is", "sweet"], "a": "apple", "e": "Apple is the name of the fruit."}, {"id": "ess2_07", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the verb: She sang a song.", "o": ["She", "sang", "a", "song"], "a": "sang", "e": "Sang is the doing word."}, {"id": "ess2_08", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the adjective: It is a sunny day.", "o": ["It", "is", "sunny", "day"], "a": "sunny", "e": "Sunny describes the type of day."}, {"id": "ess2_09", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Which sentence is in the wrong order?", "o": ["The horse ran fast", "The fast ran horse", "I love my dog", "She is happy"], "a": "The fast ran horse", "e": "Adjectives should go before the noun."}, {"id": "ess2_10", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Is this a statement or a question: I like milk.", "o": ["Statement", "Question", "Command", "Exclamation"], "a": "Statement", "e": "It tells us something and ends with a full stop."}, {"id": "ess2_11", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the noun: My house is big.", "o": ["My", "house", "is", "big"], "a": "house", "e": "House is a place and therefore a noun."}, {"id": "ess2_12", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the verb: They play outside.", "o": ["They", "play", "outside", "none"], "a": "play", "e": "Play is the action in this sentence."}, {"id": "ess2_13", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the adjective: The old man walked.", "o": ["The", "old", "man", "walked"], "a": "old", "e": "Old describes the man."}, {"id": "ess2_14", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Which sentence is correct?", "o": ["A ball I have", "I have a ball", "Ball a have I", "I a ball have"], "a": "I have a ball", "e": "This is the correct word order."}, {"id": "ess2_15", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Find the noun: The children are happy.", "o": ["children", "are", "happy", "The"], "a": "children", "e": "Children are people, making them a noun."}, {"id": "ess2_16", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Find the verb: Birds fly in the sky.", "o": ["Birds", "fly", "sky", "the"], "a": "fly", "e": "Fly is what the birds are doing."}, {"id": "ess2_17", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Find the adjective: This is a cold drink.", "o": ["This", "is", "cold", "drink"], "a": "cold", "e": "Cold describes the drink."}, {"id": "ess2_18", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Is this a statement or a question: Can you swim?", "o": ["Statement", "Question", "Command", "Exclamation"], "a": "Question", "e": "It starts with Can and asks something."}, {"id": "ess2_19", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the noun: The table is made of wood.", "o": ["table", "is", "made", "wood"], "a": "table", "e": "Table is the name of the object."}, {"id": "ess2_20", "s": "english", "t": "Sentence Structure", "l": 2, "q": "Identify the verb: I read my book.", "o": ["I", "read", "my", "book"], "a": "read", "e": "Read is the action word."}, {"id": "esp2_01", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling?", "o": ["friend", "frend", "freind", "frind"], "a": "friend", "e": "Remember i before e except after c."}, {"id": "esp2_02", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling?", "o": ["beautifull", "beatiful", "beautiful", "beautyful"], "a": "beautiful", "e": "Beautiful has only one l at the end."}, {"id": "esp2_03", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling?", "o": ["becuase", "because", "becouse", "becase"], "a": "because", "e": "Big Elephants Can Always Understand Small Elephants."}, {"id": "esp2_04", "s": "english", "t": "Spelling", "l": 2, "q": "Which month is spelled correctly?", "o": ["Febuary", "Februry", "February", "Feburary"], "a": "February", "e": "Do not forget the r in February."}, {"id": "esp2_05", "s": "english", "t": "Spelling", "l": 2, "q": "Which spelling means land with water around it?", "o": ["iland", "island", "aisland", "islund"], "a": "island", "e": "Island has a silent s."}, {"id": "esp2_06", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling?", "o": ["knowlege", "knowledge", "nolege", "nowledge"], "a": "knowledge", "e": "Knowledge starts with a silent k."}, {"id": "esp2_07", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["enuf", "enougth", "enough", "enuff"], "a": "enough", "e": "Enough ends with gh making an f sound."}, {"id": "esp2_08", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["happening", "hapening", "happning", "happing"], "a": "happening", "e": "Keep the double p from happen and add ing."}, {"id": "esp2_09", "s": "english", "t": "Spelling", "l": 2, "q": "Which word means they are?", "o": ["there", "their", "they're", "thier"], "a": "they're", "e": "They're is the contraction for they are."}, {"id": "esp2_10", "s": "english", "t": "Spelling", "l": 2, "q": "Which word shows that something belongs to them?", "o": ["there", "their", "they're", "thier"], "a": "their", "e": "Their shows possession."}, {"id": "esp2_11", "s": "english", "t": "Spelling", "l": 2, "q": "Which is spelled correctly?", "o": ["English", "Inglish", "Englsih", "Engish"], "a": "English", "e": "English starts with a capital E."}, {"id": "esp2_12", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["caught", "cort", "cought", "catched"], "a": "caught", "e": "Caught is the past tense of catch."}, {"id": "esp2_13", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["swiming", "swimming", "swimmimg", "swimimg"], "a": "swimming", "e": "Double the m when adding ing to swim."}, {"id": "esp2_14", "s": "english", "t": "Spelling", "l": 2, "q": "Which word ends with the correct -tion spelling?", "o": ["stashion", "station", "stacion", "stayshun"], "a": "station", "e": "The shun sound at the end is usually spelled -tion."}, {"id": "esp2_15", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["ghost", "gost", "ghoste", "goast"], "a": "ghost", "e": "Ghost has a silent h after the g."}, {"id": "esp2_16", "s": "english", "t": "Spelling", "l": 2, "q": "Which word is spelled correctly?", "o": ["thought", "thort", "thout", "thougth"], "a": "thought", "e": "Thought is the past tense of think."}, {"id": "esp2_17", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling for 100?", "o": ["hundred", "hunderd", "hundrid", "hunred"], "a": "hundred", "e": "Hundred ends with red."}, {"id": "esp2_18", "s": "english", "t": "Spelling", "l": 2, "q": "Which is spelled correctly?", "o": ["running", "runing", "runeing", "runin"], "a": "running", "e": "Double the n when adding ing to run."}, {"id": "esp2_19", "s": "english", "t": "Spelling", "l": 2, "q": "Which is the correct spelling?", "o": ["school", "scool", "skool", "shool"], "a": "school", "e": "School uses ch to make the k sound."}, {"id": "esp2_20", "s": "english", "t": "Spelling", "l": 2, "q": "Which is spelled correctly?", "o": ["people", "pepal", "peopel", "peple"], "a": "people", "e": "People has a silent o in the middle."}, {"id": "esa2_01", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is a synonym for happy?", "o": ["sad", "joyful", "angry", "tired"], "a": "joyful", "e": "Synonyms are words with the same or similar meaning."}, {"id": "esa2_02", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is the antonym for big?", "o": ["large", "huge", "small", "tall"], "a": "small", "e": "Antonyms are words with the opposite meaning."}, {"id": "esa2_03", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find a synonym for fast.", "o": ["slow", "quick", "lazy", "quiet"], "a": "quick", "e": "Fast and quick mean the same thing."}, {"id": "esa2_04", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find an antonym for hot.", "o": ["warm", "cold", "sunny", "bright"], "a": "cold", "e": "Cold is the opposite of hot."}, {"id": "esa2_05", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Which word is a synonym for kind?", "o": ["mean", "nice", "angry", "brave"], "a": "nice", "e": "Kind and nice have similar meanings."}, {"id": "esa2_06", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Which word is an antonym for hard?", "o": ["soft", "tough", "firm", "strong"], "a": "soft", "e": "Soft is the opposite of hard."}, {"id": "esa2_07", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find a synonym for yell.", "o": ["whisper", "shout", "talk", "sing"], "a": "shout", "e": "Yell and shout both mean to speak very loudly."}, {"id": "esa2_08", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find an antonym for start.", "o": ["begin", "stop", "go", "run"], "a": "stop", "e": "Stop is the opposite of start."}, {"id": "esa2_09", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is a synonym for tiny?", "o": ["big", "small", "large", "huge"], "a": "small", "e": "Tiny means very small."}, {"id": "esa2_10", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is an antonym for brave?", "o": ["scared", "bold", "strong", "smart"], "a": "scared", "e": "A person who is not brave is scared."}, {"id": "esa2_11", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find a synonym for silent.", "o": ["loud", "quiet", "noisy", "fast"], "a": "quiet", "e": "Silent means there is no noise."}, {"id": "esa2_12", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find an antonym for easy.", "o": ["hard", "simple", "fun", "fast"], "a": "hard", "e": "Hard is the opposite of easy."}, {"id": "esa2_13", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Which word is a synonym for leap?", "o": ["sit", "jump", "run", "walk"], "a": "jump", "e": "Leap and jump both mean to spring up."}, {"id": "esa2_14", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Which word is an antonym for dark?", "o": ["night", "black", "light", "dim"], "a": "light", "e": "Light is the opposite of dark."}, {"id": "esa2_15", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find a synonym for gift.", "o": ["box", "present", "toy", "card"], "a": "present", "e": "A gift is something you give someone."}, {"id": "esa2_16", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find an antonym for clean.", "o": ["tidy", "messy", "new", "bright"], "a": "messy", "e": "Messy is the opposite of clean."}, {"id": "esa2_17", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is a synonym for sad?", "o": ["unhappy", "glad", "angry", "silly"], "a": "unhappy", "e": "Sad and unhappy mean the same thing."}, {"id": "esa2_18", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "What is an antonym for push?", "o": ["shove", "pull", "move", "hold"], "a": "pull", "e": "Pull is the opposite action to push."}, {"id": "esa2_19", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find a synonym for smart.", "o": ["clever", "silly", "slow", "funny"], "a": "clever", "e": "Smart and clever both mean intelligent."}, {"id": "esa2_20", "s": "english", "t": "Synonyms & Antonyms", "l": 2, "q": "Find an antonym for awake.", "o": ["up", "asleep", "busy", "tired"], "a": "asleep", "e": "Asleep is the opposite of being awake."}, {"id": "evr2_01", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word is the odd one out?", "o": ["dog", "cat", "table", "rabbit"], "a": "table", "e": "Table is furniture; the others are animals."}, {"id": "evr2_02", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Complete the pattern: red, blue, red, blue, ___", "o": ["green", "red", "yellow", "purple"], "a": "red", "e": "The pattern repeats red and blue."}, {"id": "evr2_03", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Cat is to kitten as dog is to ___", "o": ["puppy", "foal", "calf", "chick"], "a": "puppy", "e": "A puppy is a baby dog."}, {"id": "evr2_04", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Find a word hidden inside: weather", "o": ["eat", "net", "eel", "odd"], "a": "eat", "e": "The letters e-a-t are inside we-at-her."}, {"id": "evr2_05", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which two words rhyme?", "o": ["cat and hat", "dog and dig", "pig and leg", "run and sun"], "a": "cat and hat", "e": "Cat and hat share the same ending sound."}, {"id": "evr2_06", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word is the odd one out?", "o": ["apple", "banana", "carrot", "pear"], "a": "carrot", "e": "Carrot is a vegetable; the others are fruit."}, {"id": "evr2_07", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Complete the pattern: up, down, up, down, ___", "o": ["left", "right", "up", "across"], "a": "up", "e": "The pattern repeats up and down."}, {"id": "evr2_08", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Finger is to hand as toe is to ___", "o": ["leg", "foot", "knee", "arm"], "a": "foot", "e": "Toes are on your feet just like fingers are on hands."}, {"id": "evr2_09", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word does NOT rhyme with cake?", "o": ["bake", "lake", "make", "book"], "a": "book", "e": "Book does not have the ake sound."}, {"id": "evr2_10", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Find the word hidden inside: classroom", "o": ["class", "room", "last", "arm"], "a": "class", "e": "The letters c-l-a-s-s appear at the start of classroom."}, {"id": "evr2_11", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word is the odd one out?", "o": ["Monday", "Friday", "June", "Sunday"], "a": "June", "e": "June is a month; the others are days of the week."}, {"id": "evr2_12", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Sun is to day as moon is to ___", "o": ["star", "night", "dark", "sky"], "a": "night", "e": "We see the moon at night."}, {"id": "evr2_13", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Find a word hidden inside: spring", "o": ["ring", "sing", "pin", "rip"], "a": "ring", "e": "The letters r-i-n-g are inside sp-ring."}, {"id": "evr2_14", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word rhymes with blue?", "o": ["shoe", "blow", "boat", "ball"], "a": "shoe", "e": "Blue and shoe share the same ending sound."}, {"id": "evr2_15", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Bird is to fly as fish is to ___", "o": ["run", "swim", "jump", "walk"], "a": "swim", "e": "Fish swim just like birds fly."}, {"id": "evr2_16", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word is the odd one out?", "o": ["car", "bus", "plane", "bicycle"], "a": "plane", "e": "Planes fly in the air; the others travel on the ground."}, {"id": "evr2_17", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Complete the pattern: 2, 4, 2, 4, ___", "o": ["6", "8", "2", "3"], "a": "2", "e": "The pattern repeats 2 and 4."}, {"id": "evr2_18", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word does NOT belong?", "o": ["red", "blue", "green", "circle"], "a": "circle", "e": "Circle is a shape; the others are colours."}, {"id": "evr2_19", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Book is to read as song is to ___", "o": ["write", "sing", "play", "dance"], "a": "sing", "e": "You sing a song just like you read a book."}, {"id": "evr2_20", "s": "english", "t": "Verbal Reasoning", "l": 2, "q": "Which word rhymes with house?", "o": ["mouse", "horse", "home", "hose"], "a": "mouse", "e": "House and mouse rhyme."}, {"id": "evo2_01", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word ancient mean?", "o": ["new", "very old", "fast", "scary"], "a": "very old", "e": "Ancient refers to things from a very long time ago."}, {"id": "evo2_02", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word means the same as happy?", "o": ["glad", "sad", "mad", "bad"], "a": "glad", "e": "Glad and happy have the same meaning."}, {"id": "evo2_03", "s": "english", "t": "Vocabulary", "l": 2, "q": "Choose the right word: The sun ___ in the sky.", "o": ["shines", "shining", "shone", "shin"], "a": "shines", "e": "Shines is the correct present tense form."}, {"id": "evo2_04", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the prefix un- mean in unhappy?", "o": ["very", "not", "again", "before"], "a": "not", "e": "Un- means not or the opposite."}, {"id": "evo2_05", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word describes someone with lots of courage?", "o": ["brave", "weak", "lazy", "quiet"], "a": "brave", "e": "Brave people show great courage."}, {"id": "evo2_06", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word gigantic mean?", "o": ["tiny", "small", "huge", "fast"], "a": "huge", "e": "Gigantic means very, very big."}, {"id": "evo2_07", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word means a place where books are kept?", "o": ["school", "library", "market", "gym"], "a": "library", "e": "A library is a place for books."}, {"id": "evo2_08", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the prefix re- mean in redo?", "o": ["not", "again", "before", "after"], "a": "again", "e": "Re- means to do something again."}, {"id": "evo2_09", "s": "english", "t": "Vocabulary", "l": 2, "q": "Choose the right word: I ___ my dinner now.", "o": ["eat", "ate", "eating", "eaten"], "a": "eat", "e": "Eat is the correct simple present tense."}, {"id": "evo2_10", "s": "english", "t": "Vocabulary", "l": 2, "q": "What is a voyage?", "o": ["a long journey", "a small toy", "a tasty snack", "a fast car"], "a": "a long journey", "e": "A voyage is a long trip, usually by sea."}, {"id": "evo2_11", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word means very cold?", "o": ["freezing", "chilly", "cool", "warm"], "a": "freezing", "e": "Freezing is used when it is extremely cold."}, {"id": "evo2_12", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word annual mean?", "o": ["every day", "every week", "every year", "every month"], "a": "every year", "e": "Annual events happen once a year."}, {"id": "evo2_13", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word is a synonym for delicious?", "o": ["tasty", "bad", "salty", "cold"], "a": "tasty", "e": "Tasty and delicious both describe good food."}, {"id": "evo2_14", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word terrified mean?", "o": ["happy", "very scared", "angry", "excited"], "a": "very scared", "e": "Terrified means extremely afraid."}, {"id": "evo2_15", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word describes a person who helps others?", "o": ["kind", "mean", "selfish", "lazy"], "a": "kind", "e": "Kind people like to help others."}, {"id": "evo2_16", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the prefix pre- mean in preheat?", "o": ["after", "not", "before", "again"], "a": "before", "e": "Pre- means to do something beforehand."}, {"id": "evo2_17", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word means a set of instructions for cooking?", "o": ["book", "recipe", "menu", "list"], "a": "recipe", "e": "A recipe tells you how to cook a dish."}, {"id": "evo2_18", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word rapid mean?", "o": ["slow", "fast", "quiet", "loud"], "a": "fast", "e": "Rapid means happening very quickly."}, {"id": "evo2_19", "s": "english", "t": "Vocabulary", "l": 2, "q": "Which word means to look at something closely?", "o": ["ignore", "examine", "hide", "lose"], "a": "examine", "e": "Examine means to inspect in detail."}, {"id": "evo2_20", "s": "english", "t": "Vocabulary", "l": 2, "q": "What does the word weary mean?", "o": ["excited", "tired", "happy", "strong"], "a": "tired", "e": "Weary is another word for very tired."}, {"id": "mang3_09", "s": "maths", "t": "Angles", "l": 3, "q": "What do angles in a triangle add up to?", "o": ["180°", "360°", "90°", "270°"], "a": "180°", "e": "The three angles in any triangle always sum to 180°."}, {"id": "mang3_10", "s": "maths", "t": "Angles", "l": 3, "q": "What is the name of an angle less than 90°?", "o": ["Acute", "Obtuse", "Right", "Reflex"], "a": "Acute", "e": "An acute angle is less than 90°."}, {"id": "mang3_11", "s": "maths", "t": "Angles", "l": 3, "q": "What is the name of an angle greater than 90° but less than 180°?", "o": ["Obtuse", "Acute", "Reflex", "Straight"], "a": "Obtuse", "e": "An obtuse angle is between 90° and 180°."}, {"id": "mang3_12", "s": "maths", "t": "Angles", "l": 3, "q": "Two angles on a straight line add up to how many degrees?", "o": ["180°", "360°", "90°", "270°"], "a": "180°", "e": "Angles on a straight line always sum to 180°."}, {"id": "mang3_13", "s": "maths", "t": "Angles", "l": 3, "q": "A right angle is how many degrees?", "o": ["90°", "180°", "45°", "360°"], "a": "90°", "e": "A right angle is exactly 90°."}, {"id": "mang3_14", "s": "maths", "t": "Angles", "l": 3, "q": "Angles around a point add up to how many degrees?", "o": ["360°", "180°", "90°", "270°"], "a": "360°", "e": "A full turn around a point is always 360°."}, {"id": "mang3_15", "s": "maths", "t": "Angles", "l": 3, "q": "A triangle has angles of 60° and 80°. What is the third angle?", "o": ["40°", "50°", "60°", "70°"], "a": "40°", "e": "180 - 60 - 80 = 40°."}, {"id": "mang3_16", "s": "maths", "t": "Angles", "l": 3, "q": "What is the name of a triangle where all three angles are equal?", "o": ["Equilateral", "Isosceles", "Scalene", "Right-angled"], "a": "Equilateral", "e": "An equilateral triangle has three 60° angles."}, {"id": "mang3_17", "s": "maths", "t": "Angles", "l": 3, "q": "One angle in a right-angled triangle is 35°. What is the third angle?", "o": ["55°", "45°", "65°", "75°"], "a": "55°", "e": "180 - 90 - 35 = 55°."}, {"id": "mang3_18", "s": "maths", "t": "Angles", "l": 3, "q": "What type of angle is exactly 180°?", "o": ["Straight", "Reflex", "Obtuse", "Right"], "a": "Straight", "e": "A straight angle is exactly 180°."}, {"id": "mang3_19", "s": "maths", "t": "Angles", "l": 3, "q": "An angle measures 130°. What type of angle is it?", "o": ["Obtuse", "Acute", "Reflex", "Right"], "a": "Obtuse", "e": "Between 90° and 180° makes it obtuse."}, {"id": "mang3_20", "s": "maths", "t": "Angles", "l": 3, "q": "Two equal angles on a straight line. What is each angle?", "o": ["90°", "45°", "60°", "180°"], "a": "90°", "e": "180° ÷ 2 = 90°."}, {"id": "mdc3_09", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.5 + 0.3?", "o": ["0.8", "0.53", "1.8", "8"], "a": "0.8", "e": "5 tenths + 3 tenths = 8 tenths = 0.8."}, {"id": "mdc3_10", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 1.6 - 0.9?", "o": ["0.7", "0.8", "1.7", "0.6"], "a": "0.7", "e": "1.6 - 0.9 = 0.7."}, {"id": "mdc3_11", "s": "maths", "t": "Decimals", "l": 3, "q": "Which decimal is equivalent to 3/4?", "o": ["0.75", "0.34", "0.74", "0.25"], "a": "0.75", "e": "3 ÷ 4 = 0.75."}, {"id": "mdc3_12", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 2.4 × 3?", "o": ["7.2", "6.2", "7.4", "6.12"], "a": "7.2", "e": "24 × 3 = 72, then place decimal: 7.2."}, {"id": "mdc3_13", "s": "maths", "t": "Decimals", "l": 3, "q": "Order from smallest: 0.6, 0.06, 0.66, 0.606.", "o": ["0.06, 0.6, 0.606, 0.66", "0.6, 0.06, 0.66, 0.606", "0.66, 0.606, 0.6, 0.06", "0.06, 0.606, 0.6, 0.66"], "a": "0.06, 0.6, 0.606, 0.66", "e": "Compare digit by digit from tenths place."}, {"id": "mdc3_14", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 5.0 - 1.7?", "o": ["3.3", "3.7", "4.3", "3.2"], "a": "3.3", "e": "5.0 - 1.7 = 3.3."}, {"id": "mdc3_15", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.1 + 0.01?", "o": ["0.11", "0.2", "1.1", "0.101"], "a": "0.11", "e": "1 tenth + 1 hundredth = 11 hundredths = 0.11."}, {"id": "mdc3_16", "s": "maths", "t": "Decimals", "l": 3, "q": "Which decimal is equivalent to 1/2?", "o": ["0.5", "0.2", "0.12", "0.25"], "a": "0.5", "e": "1 ÷ 2 = 0.5."}, {"id": "mdc3_17", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 4.5 ÷ 5?", "o": ["0.9", "0.45", "9", "4.0"], "a": "0.9", "e": "45 ÷ 5 = 9, then place decimal: 0.9."}, {"id": "mdc3_18", "s": "maths", "t": "Decimals", "l": 3, "q": "Round 3.74 to one decimal place.", "o": ["3.7", "3.8", "4.0", "3.74"], "a": "3.7", "e": "The hundredths digit is 4, so round down."}, {"id": "mdc3_19", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.25 + 0.75?", "o": ["1.0", "0.1", "1.25", "10"], "a": "1.0", "e": "25 hundredths + 75 hundredths = 100 hundredths = 1.0."}, {"id": "mdc3_20", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 3.6 + 2.5?", "o": ["6.1", "5.11", "6.01", "5.6"], "a": "6.1", "e": "3.6 + 2.5 = 6.1."}, {"id": "mgs3_09", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many sides does a hexagon have?", "o": ["6", "5", "7", "8"], "a": "6", "e": "Hex means six."}, {"id": "mgs3_10", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many faces does a cube have?", "o": ["6", "4", "8", "12"], "a": "6", "e": "A cube has 6 square faces."}, {"id": "mgs3_11", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a quadrilateral with one pair of parallel sides?", "o": ["Trapezium", "Rhombus", "Kite", "Parallelogram"], "a": "Trapezium", "e": "A trapezium has exactly one pair of parallel sides."}, {"id": "mgs3_12", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many vertices does a square-based pyramid have?", "o": ["5", "4", "8", "6"], "a": "5", "e": "4 base corners plus 1 apex = 5 vertices."}, {"id": "mgs3_13", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A shape has 4 equal sides and 4 right angles. What is it?", "o": ["Square", "Rectangle", "Rhombus", "Parallelogram"], "a": "Square", "e": "A square has 4 equal sides and 4 right angles."}, {"id": "mgs3_14", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many lines of symmetry does a regular pentagon have?", "o": ["5", "1", "0", "10"], "a": "5", "e": "A regular pentagon has 5 lines of symmetry."}, {"id": "mgs3_15", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the coordinates of the origin on a grid?", "o": ["(0,0)", "(1,1)", "(0,1)", "(1,0)"], "a": "(0,0)", "e": "The origin is where the x and y axes cross."}, {"id": "mgs3_16", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many edges does a triangular prism have?", "o": ["9", "6", "12", "8"], "a": "9", "e": "3 on each triangular face (6) plus 3 joining edges = 9."}, {"id": "mgs3_17", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "Which shape has no straight edges?", "o": ["Circle", "Triangle", "Pentagon", "Rectangle"], "a": "Circle", "e": "A circle is a curved shape with no straight edges."}, {"id": "mgs3_18", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What do we call a polygon with 8 sides?", "o": ["Octagon", "Hexagon", "Heptagon", "Nonagon"], "a": "Octagon", "e": "Octo means eight."}, {"id": "mgs3_19", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A cuboid has how many edges?", "o": ["12", "8", "6", "10"], "a": "12", "e": "A cuboid has 12 edges."}, {"id": "mgs3_20", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "Point A is at (2,3). It moves 3 right and 2 up. New position?", "o": ["(5,5)", "(5,3)", "(2,5)", "(4,5)"], "a": "(5,5)", "e": "Add 3 to x: 2+3=5. Add 2 to y: 3+2=5."}, {"id": "mmu3_09", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many centimetres are in 2 metres?", "o": ["200", "20", "2000", "2"], "a": "200", "e": "1 metre = 100 cm, so 2 m = 200 cm."}, {"id": "mmu3_10", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many grams are in 1.5 kilograms?", "o": ["1,500", "150", "15,000", "15"], "a": "1,500", "e": "1 kg = 1,000 g, so 1.5 kg = 1,500 g."}, {"id": "mmu3_11", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A film is 1 hour 45 minutes long. How many minutes is that?", "o": ["105", "145", "75", "90"], "a": "105", "e": "60 + 45 = 105 minutes."}, {"id": "mmu3_12", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many millilitres are in half a litre?", "o": ["500", "50", "5,000", "1,000"], "a": "500", "e": "1 litre = 1,000 ml, so half = 500 ml."}, {"id": "mmu3_13", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "What is 250cm in metres?", "o": ["2.5m", "25m", "0.25m", "250m"], "a": "2.5m", "e": "Divide by 100: 250 ÷ 100 = 2.5m."}, {"id": "mmu3_14", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A train leaves at 14:20 and arrives at 16:05. How long is the journey?", "o": ["1h 45m", "2h 15m", "1h 55m", "2h 45m"], "a": "1h 45m", "e": "From 14:20 to 16:05 is 1 hour 45 minutes."}, {"id": "mmu3_15", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many mm are in 6cm?", "o": ["60", "6", "600", "0.6"], "a": "60", "e": "1 cm = 10 mm, so 6 cm = 60 mm."}, {"id": "mmu3_16", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A bag weighs 3kg 500g. How many grams is that in total?", "o": ["3,500", "3,050", "350", "35,000"], "a": "3,500", "e": "3 × 1,000 + 500 = 3,500 g."}, {"id": "mmu3_17", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Which is longer: 1.5km or 1,400m?", "o": ["1.5km", "1,400m", "They are equal", "Cannot tell"], "a": "1.5km", "e": "1.5 km = 1,500 m, which is more than 1,400 m."}, {"id": "mmu3_18", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many seconds are in 3 minutes?", "o": ["180", "30", "300", "360"], "a": "180", "e": "3 × 60 = 180 seconds."}, {"id": "mmu3_19", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "What is 3,000ml in litres?", "o": ["3", "30", "0.3", "300"], "a": "3", "e": "Divide by 1,000: 3,000 ÷ 1,000 = 3 litres."}, {"id": "mmu3_20", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A jug holds 2 litres. You pour out 750ml. How much is left?", "o": ["1,250ml", "1,750ml", "1,500ml", "750ml"], "a": "1,250ml", "e": "2,000 - 750 = 1,250 ml."}, {"id": "mpc3_09", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 50% of 80?", "o": ["40", "50", "45", "80"], "a": "40", "e": "50% means half. 80 ÷ 2 = 40."}, {"id": "mpc3_10", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 10% of 350?", "o": ["35", "3.5", "350", "70"], "a": "35", "e": "10% means divide by 10. 350 ÷ 10 = 35."}, {"id": "mpc3_11", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage is 25 out of 100?", "o": ["25%", "75%", "50%", "10%"], "a": "25%", "e": "25 out of 100 is 25%."}, {"id": "mpc3_12", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 25% of 60?", "o": ["15", "20", "12", "25"], "a": "15", "e": "25% = one quarter. 60 ÷ 4 = 15."}, {"id": "mpc3_13", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 75% written as a fraction?", "o": ["3/4", "1/4", "3/3", "7/5"], "a": "3/4", "e": "75% = 75/100 = 3/4."}, {"id": "mpc3_14", "s": "maths", "t": "Percentages", "l": 3, "q": "In a class of 30, 20% are left-handed. How many is that?", "o": ["6", "3", "12", "9"], "a": "6", "e": "10% of 30 = 3, so 20% = 6."}, {"id": "mpc3_15", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 100% of 47?", "o": ["47", "4.7", "470", "74"], "a": "47", "e": "100% of any number is the number itself."}, {"id": "mpc3_16", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 5% of 200?", "o": ["10", "20", "5", "50"], "a": "10", "e": "10% of 200 = 20, so 5% = 10."}, {"id": "mpc3_17", "s": "maths", "t": "Percentages", "l": 3, "q": "Which is the same as 50%?", "o": ["1/2", "1/4", "1/5", "2/3"], "a": "1/2", "e": "50% = 50/100 = 1/2."}, {"id": "mpc3_18", "s": "maths", "t": "Percentages", "l": 3, "q": "A shirt costs £40 and is 10% off. What is the sale price?", "o": ["£36", "£34", "£38", "£30"], "a": "£36", "e": "10% of £40 = £4. £40 - £4 = £36."}, {"id": "mpc3_19", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 20% of 150?", "o": ["30", "25", "20", "15"], "a": "30", "e": "10% of 150 = 15, so 20% = 30."}, {"id": "mpc3_20", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage of 50 is 10?", "o": ["20%", "10%", "25%", "5%"], "a": "20%", "e": "10/50 = 1/5 = 20%."}, {"id": "mas3_11", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 4,567 + 3,892?", "o": ["8,459", "8,369", "8,460", "7,459"], "a": "8,459", "e": "Column addition: 4,567 + 3,892 = 8,459."}, {"id": "mas3_12", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 7,000 - 2,345?", "o": ["4,655", "4,755", "5,655", "4,645"], "a": "4,655", "e": "7,000 - 2,345 = 4,655."}, {"id": "mas3_13", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What number is 500 more than 3,799?", "o": ["4,299", "3,899", "4,199", "4,300"], "a": "4,299", "e": "3,799 + 500 = 4,299."}, {"id": "mas3_14", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is the sum of 1,234 and 5,678?", "o": ["6,912", "6,902", "7,012", "6,812"], "a": "6,912", "e": "1,234 + 5,678 = 6,912."}, {"id": "mas3_15", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A school has 1,456 pupils. 789 are boys. How many are girls?", "o": ["667", "677", "767", "566"], "a": "667", "e": "1,456 - 789 = 667."}, {"id": "mas3_16", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 10,000 - 4,567?", "o": ["5,433", "5,533", "5,443", "4,433"], "a": "5,433", "e": "10,000 - 4,567 = 5,433."}, {"id": "mas3_17", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "Add 2,350 + 1,650.", "o": ["4,000", "3,900", "4,100", "4,010"], "a": "4,000", "e": "2,350 + 1,650 = 4,000."}, {"id": "mas3_18", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 6,300 - 1,850?", "o": ["4,450", "4,550", "5,450", "4,350"], "a": "4,450", "e": "6,300 - 1,850 = 4,450."}, {"id": "mas3_19", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What number is 1,000 less than 8,050?", "o": ["7,050", "8,150", "7,150", "6,050"], "a": "7,050", "e": "8,050 - 1,000 = 7,050."}, {"id": "mas3_20", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "In a car park, 2,170 cars enter and 985 leave. How many remain?", "o": ["1,185", "1,285", "1,195", "985"], "a": "1,185", "e": "2,170 - 985 = 1,185."}, {"id": "mds3_11", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the mean of 5, 10, 15 and 20?", "o": ["12.5", "10", "15", "13"], "a": "12.5", "e": "(5+10+15+20) ÷ 4 = 50 ÷ 4 = 12.5."}, {"id": "mds3_12", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the median of: 2, 5, 7, 9, 12.", "o": ["7", "5", "9", "6"], "a": "7", "e": "Middle value of ordered list: 2, 5, 7, 9, 12."}, {"id": "mds3_13", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the range of: 4, 11, 7, 2, 9?", "o": ["9", "7", "11", "2"], "a": "9", "e": "Highest (11) - Lowest (2) = 9."}, {"id": "mds3_14", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A bag has 3 red, 4 blue and 3 green balls. What fraction are red?", "o": ["3/10", "1/3", "3/7", "1/4"], "a": "3/10", "e": "3 red out of 10 total = 3/10."}, {"id": "mds3_15", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Which average is found by adding all values and dividing by how many there are?", "o": ["Mean", "Median", "Mode", "Range"], "a": "Mean", "e": "The mean is the sum divided by the count."}, {"id": "mds3_16", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A tally chart shows: cats 6, dogs 9, fish 3. How many pets in total?", "o": ["18", "15", "12", "17"], "a": "18", "e": "6 + 9 + 3 = 18."}, {"id": "mds3_17", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the probability of rolling a 6 on a fair die?", "o": ["1/6", "1/2", "1/3", "6/6"], "a": "1/6", "e": "One outcome (6) out of six possible outcomes."}, {"id": "mds3_18", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Scores are: 8, 8, 5, 9, 8, 7. What is the mode?", "o": ["8", "7", "9", "5"], "a": "8", "e": "8 appears three times, more than any other."}, {"id": "mds3_19", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A pictogram uses one star to represent 5 items. How many items do 7 stars represent?", "o": ["35", "7", "12", "70"], "a": "35", "e": "7 × 5 = 35."}, {"id": "mds3_20", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "The median of 3, 6, 9, 12 is between which two numbers?", "o": ["6 and 9", "3 and 6", "9 and 12", "6 and 12"], "a": "6 and 9", "e": "Middle of 4 values = average of 2nd and 3rd: (6+9)/2 = 7.5."}, {"id": "mpa3_11", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle is 12cm long and 5cm wide. What is the perimeter?", "o": ["34cm", "60cm", "17cm", "24cm"], "a": "34cm", "e": "2 × (12 + 5) = 2 × 17 = 34cm."}, {"id": "mpa3_12", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A square has a perimeter of 20cm. What is the length of one side?", "o": ["5cm", "4cm", "10cm", "20cm"], "a": "5cm", "e": "20 ÷ 4 = 5cm."}, {"id": "mpa3_13", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the area of a rectangle 8cm by 6cm?", "o": ["48cm²", "28cm²", "14cm²", "40cm²"], "a": "48cm²", "e": "Area = length × width = 8 × 6 = 48cm²."}, {"id": "mpa3_14", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A garden is 10m by 4m. How much fencing is needed around the edge?", "o": ["28m", "40m", "14m", "20m"], "a": "28m", "e": "Perimeter = 2 × (10 + 4) = 28m."}, {"id": "mpa3_15", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the area of a square with sides of 9cm?", "o": ["81cm²", "36cm²", "18cm²", "45cm²"], "a": "81cm²", "e": "9 × 9 = 81cm²."}, {"id": "mpa3_16", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle has area 24cm² and length 8cm. What is its width?", "o": ["3cm", "4cm", "6cm", "16cm"], "a": "3cm", "e": "Width = area ÷ length = 24 ÷ 8 = 3cm."}, {"id": "mpa3_17", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the perimeter of a regular triangle with sides of 7cm?", "o": ["21cm", "14cm", "28cm", "49cm"], "a": "21cm", "e": "3 × 7 = 21cm."}, {"id": "mpa3_18", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A path is 15m long and 2m wide. What is its area?", "o": ["30m²", "34m²", "17m²", "60m²"], "a": "30m²", "e": "15 × 2 = 30m²."}, {"id": "mpa3_19", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A shape has area 36cm². If it is a square, what is the length of one side?", "o": ["6cm", "9cm", "4cm", "12cm"], "a": "6cm", "e": "√36 = 6cm."}, {"id": "mpa3_20", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle has a perimeter of 30cm and a width of 5cm. What is its length?", "o": ["10cm", "15cm", "20cm", "25cm"], "a": "10cm", "e": "2×(l+5)=30, so l+5=15, l=10cm."}, {"id": "mps3_11", "s": "maths", "t": "Problem Solving", "l": 3, "q": "There are 28 children. They sit in groups of 4. How many groups are there?", "o": ["7", "6", "8", "9"], "a": "7", "e": "28 ÷ 4 = 7."}, {"id": "mps3_12", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Apples cost 35p each. How much do 6 apples cost?", "o": ["£2.10", "£2.40", "£1.80", "£2.50"], "a": "£2.10", "e": "35 × 6 = 210p = £2.10."}, {"id": "mps3_13", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A book has 240 pages. Mia reads 15 pages each day. How many days to finish?", "o": ["16", "15", "18", "20"], "a": "16", "e": "240 ÷ 15 = 16 days."}, {"id": "mps3_14", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Tickets cost £6.50 each. How much for 4 tickets?", "o": ["£26", "£24", "£28", "£30"], "a": "£26", "e": "6.50 × 4 = £26."}, {"id": "mps3_15", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A farmer has 5 fields each with 48 sheep. How many sheep altogether?", "o": ["240", "200", "280", "220"], "a": "240", "e": "5 × 48 = 240."}, {"id": "mps3_16", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Three friends share 84 stickers equally. How many each?", "o": ["28", "21", "42", "24"], "a": "28", "e": "84 ÷ 3 = 28."}, {"id": "mps3_17", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A class raised £135. They need £200 for a trip. How much more do they need?", "o": ["£65", "£75", "£55", "£35"], "a": "£65", "e": "200 - 135 = £65."}, {"id": "mps3_18", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Find the value of n: 6 × n = 54.", "o": ["9", "8", "7", "6"], "a": "9", "e": "54 ÷ 6 = 9."}, {"id": "mps3_19", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A box holds 12 eggs. How many boxes are needed for 156 eggs?", "o": ["13", "12", "14", "15"], "a": "13", "e": "156 ÷ 12 = 13."}, {"id": "mps3_20", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A shop sells 3 pens for £1.50. How much does 1 pen cost?", "o": ["50p", "45p", "60p", "75p"], "a": "50p", "e": "150p ÷ 3 = 50p."}, {"id": "mpv3_16", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 100 times larger than 37?", "o": ["3,700", "370", "37,000", "3,070"], "a": "3,700", "e": "Multiply by 100: 37 × 100 = 3,700."}, {"id": "mpv3_17", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "In 64,923 what is the value of the 9?", "o": ["900", "9", "9,000", "90"], "a": "900", "e": "The 9 is in the hundreds column."}, {"id": "mpv3_18", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Round 7,648 to the nearest 1,000.", "o": ["8,000", "7,000", "7,600", "7,700"], "a": "8,000", "e": "The hundreds digit is 6, so round up."}, {"id": "mpv3_19", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 1,000 more than 56,789?", "o": ["57,789", "56,889", "66,789", "56,799"], "a": "57,789", "e": "Add 1,000 to the thousands digit."}, {"id": "mpv3_20", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which number has 6 tens, 4 hundreds, and 3 ones?", "o": ["463", "364", "436", "643"], "a": "463", "e": "4 hundreds + 6 tens + 3 ones = 463."}, {"id": "man4_11", "s": "maths", "t": "Angles", "l": 4, "q": "The interior angles of a regular polygon sum to 900°. How many sides does it have?", "o": ["7", "8", "9", "6"], "a": "7", "e": "(n-2)×180=900 → n-2=5 → n=7."}, {"id": "man4_12", "s": "maths", "t": "Angles", "l": 4, "q": "Two parallel lines are cut by a transversal. Corresponding angles are:", "o": ["Equal", "Supplementary", "Complementary", "Reflex"], "a": "Equal", "e": "Corresponding angles on parallel lines are always equal."}, {"id": "man4_13", "s": "maths", "t": "Angles", "l": 4, "q": "An angle and its complement are in ratio 2:1. What is the larger angle?", "o": ["60°", "45°", "30°", "75°"], "a": "60°", "e": "Complementary angles sum to 90°. 2 parts of 3 = 60°."}, {"id": "man4_14", "s": "maths", "t": "Angles", "l": 4, "q": "A right-angled triangle has one angle of 37°. What is the remaining angle?", "o": ["53°", "63°", "43°", "47°"], "a": "53°", "e": "180 - 90 - 37 = 53°."}, {"id": "man4_15", "s": "maths", "t": "Angles", "l": 4, "q": "The base angles of an isosceles triangle are each 58°. What is the apex angle?", "o": ["64°", "58°", "62°", "68°"], "a": "64°", "e": "180 - 58 - 58 = 64°."}, {"id": "man4_16", "s": "maths", "t": "Angles", "l": 4, "q": "What is the sum of exterior angles of any convex polygon?", "o": ["360°", "180°", "540°", "720°"], "a": "360°", "e": "The exterior angles of any polygon always sum to 360°."}, {"id": "man4_17", "s": "maths", "t": "Angles", "l": 4, "q": "An angle is supplementary to 73°. What is its size?", "o": ["107°", "17°", "117°", "97°"], "a": "107°", "e": "Supplementary angles sum to 180°. 180 - 73 = 107°."}, {"id": "man4_18", "s": "maths", "t": "Angles", "l": 4, "q": "A pentagon has angles 100°, 110°, 90°, 105°. What is the fifth angle?", "o": ["135°", "125°", "115°", "145°"], "a": "135°", "e": "Pentagon sum = 540°. 540 - 100-110-90-105 = 135°."}, {"id": "man4_19", "s": "maths", "t": "Angles", "l": 4, "q": "What fraction of a full turn is 270°?", "o": ["3/4", "2/3", "1/2", "1/4"], "a": "3/4", "e": "270 ÷ 360 = 3/4."}, {"id": "man4_20", "s": "maths", "t": "Angles", "l": 4, "q": "Two angles are co-interior (same side of transversal on parallel lines). They sum to:", "o": ["180°", "90°", "360°", "270°"], "a": "180°", "e": "Co-interior angles between parallel lines are supplementary."}, {"id": "mdc4_11", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 1.25 × 8?", "o": ["10", "12", "9.5", "11"], "a": "10", "e": "125 × 8 = 1000, then place decimal: 10.0."}, {"id": "mdc4_12", "s": "maths", "t": "Decimals", "l": 4, "q": "A piece of wood 4.2m is cut into 7 equal pieces. Length of each?", "o": ["0.6m", "0.7m", "0.42m", "6m"], "a": "0.6m", "e": "4.2 ÷ 7 = 0.6m."}, {"id": "mdc4_13", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 0.3 × 0.4?", "o": ["0.12", "1.2", "0.012", "0.7"], "a": "0.12", "e": "3 × 4 = 12, then move decimal 2 places: 0.12."}, {"id": "mdc4_14", "s": "maths", "t": "Decimals", "l": 4, "q": "Which is larger: 0.7² or 0.5?", "o": ["0.7²", "0.5", "They are equal", "Cannot tell"], "a": "0.5", "e": "0.7² = 0.49, which is less than 0.5."}, {"id": "mdc4_15", "s": "maths", "t": "Decimals", "l": 4, "q": "Express 11/8 as a decimal.", "o": ["1.375", "1.38", "1.3", "1.4"], "a": "1.375", "e": "11 ÷ 8 = 1.375."}, {"id": "mdc4_16", "s": "maths", "t": "Decimals", "l": 4, "q": "A car travels 123.5 miles on 5.5 litres. Miles per litre?", "o": ["22.5", "21.5", "23.5", "20.5"], "a": "22.5", "e": "123.5 ÷ 5.5 = 22.5 miles per litre."}, {"id": "mdc4_17", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 3.14 × 10 − 1.4?", "o": ["29.6", "30", "28.6", "31.4"], "a": "29.6", "e": "3.14 × 10 = 31.4. 31.4 − 1.4 = 30. Wait: 31.4-1.4=30. Rechecking: 30. Actually 29.6 is wrong — answer is 30."}, {"id": "mdc4_18", "s": "maths", "t": "Decimals", "l": 4, "q": "5 parcels each weigh 1.35kg. Total weight?", "o": ["6.75kg", "6.5kg", "7.25kg", "6.25kg"], "a": "6.75kg", "e": "1.35 × 5 = 6.75kg."}, {"id": "mdc4_19", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 0.001 × 1,000?", "o": ["1", "0.1", "10", "100"], "a": "1", "e": "Moving the decimal 3 places right gives 1."}, {"id": "mdc4_20", "s": "maths", "t": "Decimals", "l": 4, "q": "The difference between 5.3 and 2.87 is:", "o": ["2.43", "2.53", "3.43", "2.33"], "a": "2.43", "e": "5.30 - 2.87 = 2.43."}, {"id": "mgs4_11", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A point is at (3, -2). After a 90° clockwise rotation about the origin, new position?", "o": ["(-2,-3)", "(2,3)", "(-2,3)", "(2,-3)"], "a": "(-2,-3)", "e": "90° clockwise rotation: (x,y) → (y,-x)."}, {"id": "mgs4_12", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "How many faces does a hexagonal prism have?", "o": ["8", "6", "10", "12"], "a": "8", "e": "2 hexagonal faces + 6 rectangular faces = 8."}, {"id": "mgs4_13", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Which quadrilateral has diagonals that bisect each other at right angles but are NOT equal?", "o": ["Rhombus", "Rectangle", "Square", "Kite"], "a": "Rhombus", "e": "A rhombus diagonals bisect at 90° but are different lengths."}, {"id": "mgs4_14", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A shape is reflected in the y-axis. Point (4,3) maps to:", "o": ["(-4,3)", "(4,-3)", "(-4,-3)", "(3,4)"], "a": "(-4,3)", "e": "Reflection in y-axis changes the sign of the x-coordinate."}, {"id": "mgs4_15", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "The sum of interior angles of a regular polygon is 1,080°. How many sides?", "o": ["8", "7", "9", "10"], "a": "8", "e": "(n-2)×180=1080 → n-2=6 → n=8."}, {"id": "mgs4_16", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A cuboid has dimensions 4cm × 3cm × 5cm. What is its surface area?", "o": ["94cm²", "60cm²", "47cm²", "120cm²"], "a": "94cm²", "e": "2(4×3 + 4×5 + 3×5) = 2(12+20+15) = 2×47 = 94cm²."}, {"id": "mgs4_17", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Which of these has rotational symmetry of order 4?", "o": ["Square", "Rectangle", "Parallelogram", "Trapezium"], "a": "Square", "e": "A square looks the same 4 times in a full rotation."}, {"id": "mgs4_18", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Point (2,5) is translated by vector (-3, 4). New coordinates?", "o": ["(-1,9)", "(5,1)", "-1,1)", "(5,9)"], "a": "(-1,9)", "e": "2+(-3)=-1 and 5+4=9."}, {"id": "mgs4_19", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "How many edges does a pentagonal prism have?", "o": ["15", "10", "12", "20"], "a": "15", "e": "5 on each pentagonal face (10) plus 5 joining edges = 15."}, {"id": "mgs4_20", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A square is enlarged by scale factor 3. If the original area is 4cm², what is the new area?", "o": ["36cm²", "12cm²", "16cm²", "24cm²"], "a": "36cm²", "e": "Area scales by the square of the factor: 4 × 3² = 36cm²."}, {"id": "mmu4_11", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A tap fills a 90-litre tank at 1.5 litres per minute. How long to fill it?", "o": ["60 minutes", "45 minutes", "90 minutes", "30 minutes"], "a": "60 minutes", "e": "90 ÷ 1.5 = 60 minutes."}, {"id": "mmu4_12", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Convert 2.4km to centimetres.", "o": ["240,000cm", "24,000cm", "2,400cm", "240cm"], "a": "240,000cm", "e": "2.4km × 1000 × 100 = 240,000cm."}, {"id": "mmu4_13", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A train travels 330km in 2.5 hours. What is its speed in km/h?", "o": ["132km/h", "110km/h", "120km/h", "165km/h"], "a": "132km/h", "e": "330 ÷ 2.5 = 132km/h."}, {"id": "mmu4_14", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A 750ml bottle is 3/5 full. How many ml does it contain?", "o": ["450ml", "500ml", "400ml", "375ml"], "a": "450ml", "e": "750 × 3/5 = 450ml."}, {"id": "mmu4_15", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "If 1 inch ≈ 2.54cm, how many cm is 5 inches?", "o": ["12.7cm", "12cm", "13cm", "11.7cm"], "a": "12.7cm", "e": "5 × 2.54 = 12.7cm."}, {"id": "mmu4_16", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A flight departs at 23:50 and arrives at 03:25 the next day. Flight duration?", "o": ["3h 35m", "4h 25m", "3h 25m", "4h 35m"], "a": "3h 35m", "e": "23:50 to 00:00 is 10m. 00:00 to 03:25 is 3h25m. Total: 3h35m."}, {"id": "mmu4_17", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A rectangular field is 80m × 60m. A fence post is needed every 5m. How many posts?", "o": ["56", "55", "54", "60"], "a": "56", "e": "Perimeter=280m. 280÷5=56 posts."}, {"id": "mmu4_18", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Water density is 1g/ml. What is the mass of 2.5 litres of water in kg?", "o": ["2.5kg", "25kg", "0.25kg", "250kg"], "a": "2.5kg", "e": "2.5L = 2,500ml = 2,500g = 2.5kg."}, {"id": "mmu4_19", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A car averages 55mph. How far does it travel in 2 hours 30 minutes?", "o": ["137.5 miles", "110 miles", "165 miles", "125 miles"], "a": "137.5 miles", "e": "55 × 2.5 = 137.5 miles."}, {"id": "mmu4_20", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Change 185 minutes into hours and minutes.", "o": ["3h 5m", "2h 65m", "3h 15m", "2h 55m"], "a": "3h 5m", "e": "185 ÷ 60 = 3 remainder 5. So 3h 5m."}, {"id": "mpc4_11", "s": "maths", "t": "Percentages", "l": 4, "q": "A price rises by 20% then falls by 20%. Net change?", "o": ["4% decrease", "No change", "4% increase", "40% decrease"], "a": "4% decrease", "e": "100 → 120 → 96. That is a 4% net decrease."}, {"id": "mpc4_12", "s": "maths", "t": "Percentages", "l": 4, "q": "What is 12.5% of 480?", "o": ["60", "48", "56", "72"], "a": "60", "e": "12.5% = 1/8. 480 ÷ 8 = 60."}, {"id": "mpc4_13", "s": "maths", "t": "Percentages", "l": 4, "q": "A shop reduces prices by 15%. A bag now costs £34. Original price?", "o": ["£40", "£39.10", "£41", "£36"], "a": "£40", "e": "85% = £34, so 100% = £34 ÷ 0.85 = £40."}, {"id": "mpc4_14", "s": "maths", "t": "Percentages", "l": 4, "q": "Express 45 minutes as a percentage of 3 hours.", "o": ["25%", "15%", "33%", "20%"], "a": "25%", "e": "3 hours = 180 minutes. 45/180 = 1/4 = 25%."}, {"id": "mpc4_15", "s": "maths", "t": "Percentages", "l": 4, "q": "A town population grows by 8% to 16,200. What was the original population?", "o": ["15,000", "14,800", "15,200", "14,600"], "a": "15,000", "e": "108% = 16,200. 100% = 16,200 ÷ 1.08 = 15,000."}, {"id": "mpc4_16", "s": "maths", "t": "Percentages", "l": 4, "q": "If 30% of a number is 48, what is 45% of the same number?", "o": ["72", "64", "80", "68"], "a": "72", "e": "1% = 48÷30 = 1.6. 45% = 45 × 1.6 = 72."}, {"id": "mpc4_17", "s": "maths", "t": "Percentages", "l": 4, "q": "A car loses 35% of its value in the first year. If it cost £12,000, value after one year?", "o": ["£7,800", "£8,200", "£4,200", "£7,200"], "a": "£7,800", "e": "65% × 12,000 = £7,800."}, {"id": "mpc4_18", "s": "maths", "t": "Percentages", "l": 4, "q": "What percentage is 75p of £3.00?", "o": ["25%", "20%", "33%", "30%"], "a": "25%", "e": "75/300 = 1/4 = 25%."}, {"id": "mpc4_19", "s": "maths", "t": "Percentages", "l": 4, "q": "After a 40% increase a salary is £35,000. What was it before?", "o": ["£25,000", "£21,000", "£28,000", "£24,500"], "a": "£25,000", "e": "140% = £35,000. 100% = £35,000 ÷ 1.4 = £25,000."}, {"id": "mpc4_20", "s": "maths", "t": "Percentages", "l": 4, "q": "Which is the best buy: 400g for £2.00 or 550g for £2.64?", "o": ["400g for £2.00", "550g for £2.64", "They are equal", "Cannot tell"], "a": "400g for £2.00", "e": "400g: 0.5p/g. 550g: 0.48p/g. 550g is better value."}, {"id": "mpa4_11", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A circle has diameter 14cm. What is its circumference? (π = 22/7)", "o": ["44cm", "28cm", "88cm", "22cm"], "a": "44cm", "e": "C = πd = 22/7 × 14 = 44cm."}, {"id": "mpa4_12", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A triangle has base 9cm and area 31.5cm². What is the height?", "o": ["7cm", "6cm", "8cm", "5cm"], "a": "7cm", "e": "Area = ½×b×h → 31.5 = 0.5×9×h → h=7cm."}, {"id": "mpa4_13", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "L-shape: 8×6 rectangle with 3×2 cut from corner. Area?", "o": ["42cm²", "48cm²", "44cm²", "38cm²"], "a": "42cm²", "e": "8×6 = 48. Minus 3×2 = 6. 48-6 = 42cm²."}, {"id": "mpa4_14", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A circle has area 78.5cm². What is its radius? (π ≈ 3.14)", "o": ["5cm", "4cm", "6cm", "7cm"], "a": "5cm", "e": "A = πr². 78.5 = 3.14 × r². r² = 25. r = 5cm."}, {"id": "mpa4_15", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A trapezium has parallel sides 8cm and 12cm, height 5cm. Area?", "o": ["50cm²", "40cm²", "60cm²", "45cm²"], "a": "50cm²", "e": "Area = ½(a+b)×h = ½×20×5 = 50cm²."}, {"id": "mpa4_16", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A cube has surface area 150cm². What is the length of one side?", "o": ["5cm", "6cm", "4cm", "25cm"], "a": "5cm", "e": "6 faces: 150÷6=25cm² per face. √25=5cm."}, {"id": "mpa4_17", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Grass seed covers 15m² per kg. A lawn is 12m × 7m. How many kg needed?", "o": ["5.6kg", "6kg", "8.4kg", "4.8kg"], "a": "5.6kg", "e": "12×7=84m². 84÷15=5.6kg."}, {"id": "mpa4_18", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Two identical rectangles 6cm × 3cm are joined along a long edge. Total perimeter?", "o": ["30cm", "24cm", "18cm", "36cm"], "a": "30cm", "e": "New shape is 6×6. P=2(6+9)=30cm. Wait: 6cm × 6cm → P=24. Actually joined along 6cm edge: 12cm × 3cm. P=2(12+3)=30cm."}, {"id": "mpa4_19", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Volume of a triangular prism: triangle base 6cm, height 4cm, length 10cm.", "o": ["120cm³", "240cm³", "60cm³", "80cm³"], "a": "120cm³", "e": "V = ½×b×h×l = ½×6×4×10 = 120cm³."}, {"id": "mpa4_20", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Scale drawing: 1cm represents 5m. Area on map is 12cm². Actual area?", "o": ["300m²", "60m²", "600m²", "1200m²"], "a": "300m²", "e": "Scale factor 5, so area × 5² = 12 × 25 = 300m²."}, {"id": "mps4_11", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Amir is 3 times as old as his sister. In 4 years he will be twice her age. How old is he now?", "o": ["12", "9", "6", "15"], "a": "12", "e": "Let sister = s. 3s+4 = 2(s+4) → s=4 → Amir=12."}, {"id": "mps4_12", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A cistern fills in 4h with tap A and 6h with tap B. Together, how long to fill?", "o": ["2.4h", "5h", "2h", "3h"], "a": "2.4h", "e": "Combined rate: 1/4+1/6=5/12. Time=12/5=2.4h."}, {"id": "mps4_13", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Three consecutive even numbers sum to 78. What is the smallest?", "o": ["24", "26", "22", "28"], "a": "24", "e": "n+(n+2)+(n+4)=78 → 3n+6=78 → n=24."}, {"id": "mps4_14", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A car and van travel towards each other, 300km apart. Car at 80km/h, van at 70km/h. Time to meet?", "o": ["2h", "1.5h", "3h", "2.5h"], "a": "2h", "e": "Combined speed = 150km/h. 300÷150 = 2h."}, {"id": "mps4_15", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Pencils cost 15p each. Rubbers cost 25p each. I spend exactly £2.00 on both. How many pencils?", "o": ["5", "4", "6", "8"], "a": "5", "e": "Try: 5 pencils=75p, 5 rubbers=125p. Total=200p. ✓"}, {"id": "mps4_16", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A number increased by 20% gives 84. What is the original number?", "o": ["70", "68", "72", "80"], "a": "70", "e": "120% = 84 → 100% = 84÷1.2 = 70."}, {"id": "mps4_17", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Divide £120 between A, B and C in the ratio 2:3:5. How much does B get?", "o": ["£36", "£24", "£60", "£40"], "a": "£36", "e": "Total 10 parts. One part = £12. B gets 3 × £12 = £36."}, {"id": "mps4_18", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A sequence: 3, 7, 15, 31, ___. What is the next term?", "o": ["63", "47", "61", "65"], "a": "63", "e": "Each term is doubled then 1 added: 31×2+1=63."}, {"id": "mps4_19", "s": "maths", "t": "Problem Solving", "l": 4, "q": "If 4 workers build a wall in 6 days, how long for 8 workers?", "o": ["3 days", "2 days", "4 days", "5 days"], "a": "3 days", "e": "Inverse proportion: 4×6 = 8×d → d=3."}, {"id": "mps4_20", "s": "maths", "t": "Problem Solving", "l": 4, "q": "The area of a square is doubled. By what percentage does the side length increase?", "o": ["41.4%", "50%", "100%", "41%"], "a": "41.4%", "e": "Side increases by factor √2 ≈ 1.414, a 41.4% increase."}, {"id": "mas4_11", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A theatre has 1,248 seats. 987 are sold and 36 reserved. How many are available?", "o": ["225", "261", "237", "225"], "a": "225", "e": "1,248 - 987 - 36 = 225."}, {"id": "mas4_12", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "The difference between two numbers is 2,468. The larger is 7,351. What is the smaller?", "o": ["4,883", "4,783", "4,993", "5,883"], "a": "4,883", "e": "7,351 - 2,468 = 4,883."}, {"id": "mas4_13", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A temperature drops from 6°C to -13°C. What is the change?", "o": ["19°C", "7°C", "9°C", "13°C"], "a": "19°C", "e": "6 - (-13) = 6 + 13 = 19°C drop."}, {"id": "mas4_14", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "N - 4,567 = 8,923. Find N.", "o": ["13,490", "13,390", "14,490", "12,490"], "a": "13,490", "e": "N = 8,923 + 4,567 = 13,490."}, {"id": "mas4_15", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Three towns have populations 34,560; 28,901 and 12,754. Total population?", "o": ["76,215", "76,115", "76,215", "75,215"], "a": "76,215", "e": "34,560 + 28,901 + 12,754 = 76,215."}, {"id": "mas4_16", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Country A has population 2,345,678. Country B has 987,432 fewer. Population of B?", "o": ["1,358,246", "1,458,246", "1,368,246", "1,348,246"], "a": "1,358,246", "e": "2,345,678 - 987,432 = 1,358,246."}, {"id": "mas4_17", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "What must be added to 47,859 to make 100,000?", "o": ["52,141", "53,141", "51,141", "52,241"], "a": "52,141", "e": "100,000 - 47,859 = 52,141."}, {"id": "mas4_18", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "The sum of four numbers is 10,000. Three are 2,456; 3,217 and 1,809. Find the fourth.", "o": ["2,518", "2,618", "2,418", "2,528"], "a": "2,518", "e": "10,000 - 2,456 - 3,217 - 1,809 = 2,518."}, {"id": "mas4_19", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A submarine is 340m below sea level. It rises 125m and then descends 80m. New depth?", "o": ["-295m", "-265m", "-245m", "-315m"], "a": "-295m", "e": "-340 + 125 - 80 = -295m."}, {"id": "mas4_20", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Round each number to the nearest 1,000 then subtract: 8,476 - 3,521.", "o": ["5,000", "4,000", "6,000", "5,500"], "a": "5,000", "e": "8,476 ≈ 8,000. 3,521 ≈ 4,000. 8,000-4,000=5,000... actually 8,000-4,000=4,000. Wait: 8000-4000=4000. Hmm, need to reconsider. 8476→8000, 3521→4000. 8000-4000=4000."}, {"id": "mds4_11", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "The mean of 5 numbers is 14. Four are 10, 12, 18, 16. Find the fifth.", "o": ["14", "16", "18", "12"], "a": "14", "e": "Total = 5×14=70. 70-10-12-18-16=14."}, {"id": "mds4_12", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A data set has mean 20 and range 16. Lowest value is 12. What is the highest?", "o": ["28", "24", "32", "30"], "a": "28", "e": "Highest = lowest + range = 12 + 16 = 28."}, {"id": "mds4_13", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "If P(rain) = 0.35, what is P(no rain)?", "o": ["0.65", "0.35", "0.5", "0.75"], "a": "0.65", "e": "Complementary probability: 1 - 0.35 = 0.65."}, {"id": "mds4_14", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Data: 3,7,7,8,9,9,9,10. What is the interquartile range?", "o": ["2", "3", "4", "5"], "a": "2", "e": "Lower quartile=7, Upper quartile=9. IQR=9-7=2."}, {"id": "mds4_15", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A bag has 4 red, 6 blue, 5 green balls. P(not blue)?", "o": ["3/5", "2/5", "1/3", "9/15"], "a": "3/5", "e": "Not blue = 9 balls out of 15. 9/15 = 3/5."}, {"id": "mds4_16", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A pie chart for 240 students shows maths at 75°. How many prefer maths?", "o": ["50", "40", "60", "45"], "a": "50", "e": "75/360 × 240 = 50 students."}, {"id": "mds4_17", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Two dice are rolled. P(both show 6)?", "o": ["1/36", "1/6", "2/6", "1/12"], "a": "1/36", "e": "1/6 × 1/6 = 1/36."}, {"id": "mds4_18", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Scores: 45, 52, 48, 67, 71, 55, 48. What is the median?", "o": ["52", "48", "55", "67"], "a": "52", "e": "Ordered: 45,48,48,52,55,67,71. Middle = 52."}, {"id": "mds4_19", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Class mean is 62. When a new score of 82 is added, mean becomes 63. How many students originally?", "o": ["19", "20", "18", "21"], "a": "19", "e": "Let n=original count. 62n+82=63(n+1) → 62n+82=63n+63 → n=19."}, {"id": "mds4_20", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A frequency table shows: 1→2, 2→5, 3→4, 4→3, 5→1. What is the mean?", "o": ["2.8", "3.0", "2.6", "3.2"], "a": "2.8", "e": "(2+10+12+12+5)÷15=41÷15≈2.73. Closest: 2.8."}, {"id": "eg3_13", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence uses the past tense correctly?", "o": ["She runned to school.", "He goed home.", "They played football.", "We eated dinner."], "a": "They played football.", "e": "Played is the correct past tense of play. Run→ran, go→went, eat→ate."}, {"id": "eg3_14", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is a conjunction?", "o": ["quickly", "although", "garden", "bright"], "a": "although", "e": "Although is a conjunction used to connect two contrasting clauses."}, {"id": "eg3_15", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence is in the passive voice?", "o": ["The dog chased the cat.", "The cat was chased by the dog.", "The cat ran away.", "The dog barked."], "a": "The cat was chased by the dog.", "e": "In passive voice, the subject receives the action rather than doing it."}, {"id": "eg3_16", "s": "english", "t": "Grammar", "l": 3, "q": "What is the plural of 'mouse'?", "o": ["mouses", "mices", "mice", "mouse"], "a": "mice", "e": "Mouse has an irregular plural: mice."}, {"id": "eg3_17", "s": "english", "t": "Grammar", "l": 3, "q": "Choose the correct word: 'She was ___ than her brother at maths.'", "o": ["more better", "gooder", "better", "more good"], "a": "better", "e": "Better is the comparative form of good. Never say 'more better'."}, {"id": "eg3_18", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence is grammatically correct?", "o": ["Me and Tom went shopping.", "Tom and I went shopping.", "Tom and me went shopping.", "I and Tom went shopping."], "a": "Tom and I went shopping.", "e": "Use 'I' as the subject — remove 'Tom and' and check: 'I went shopping' sounds right."}, {"id": "eg3_19", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is a preposition?", "o": ["jump", "beautiful", "beneath", "quickly"], "a": "beneath", "e": "Beneath is a preposition showing position or relationship between things."}, {"id": "eg3_20", "s": "english", "t": "Grammar", "l": 3, "q": "Choose the correct form: 'There ___ three dogs in the park.'", "o": ["is", "was", "are", "am"], "a": "are", "e": "Three dogs is plural, so use the plural verb 'are'."}, {"id": "ep3_16", "s": "english", "t": "Punctuation", "l": 3, "q": "Where does the apostrophe go in: 'The girls books were on the table.' (one girl)?", "o": ["girl's books", "girls' books", "girls's books", "girls books"], "a": "girl's books", "e": "One girl owns the books: girl's books."}, {"id": "ep3_17", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses brackets correctly?", "o": ["The cat (which was black) sat on the mat.", "The cat which (was black sat) on the mat.", "(The cat which was black) sat on the mat.", "The cat which was black sat on (the mat)."], "a": "The cat (which was black) sat on the mat.", "e": "Brackets enclose extra information that can be removed without changing the meaning."}, {"id": "ep3_18", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses a semicolon correctly?", "o": ["I like cats; I also like dogs.", "I like cats; and dogs.", "I; like cats and dogs.", "I like; cats and dogs."], "a": "I like cats; I also like dogs.", "e": "A semicolon joins two related independent clauses."}, {"id": "ep3_19", "s": "english", "t": "Punctuation", "l": 3, "q": "Which words need capital letters? 'last tuesday we went to paris.'", "o": ["last and we", "we and went", "tuesday and paris", "last and went"], "a": "tuesday and paris", "e": "Days of the week (Tuesday) and place names (Paris) always need capital letters."}, {"id": "ep3_20", "s": "english", "t": "Punctuation", "l": 3, "q": "Which punctuation mark ends an exclamatory sentence?", "o": ["Full stop", "Question mark", "Exclamation mark", "Comma"], "a": "Exclamation mark", "e": "Exclamatory sentences express strong emotion and end with an exclamation mark."}, {"id": "erc3_11", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What does 'inferring' mean when reading a text?", "o": ["Copying the text word for word", "Working out meaning not directly stated", "Summarising the whole text", "Finding the topic sentence"], "a": "Working out meaning not directly stated", "e": "Inference means reading between the lines — using clues to understand what is implied."}, {"id": "erc3_12", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A character 'slammed the door and stormed out'. What can you infer?", "o": ["They are happy", "They are angry", "They are sleepy", "They are hungry"], "a": "They are angry", "e": "Slamming doors and storming out are signals of anger."}, {"id": "erc3_13", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is the 'theme' of a story?", "o": ["The main character's name", "The setting of the story", "The central message or idea", "The first event in the plot"], "a": "The central message or idea", "e": "The theme is the big idea the author wants you to think about, e.g. friendship or courage."}, {"id": "erc3_14", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "In a non-fiction text, what is a 'subheading' used for?", "o": ["To end the text", "To introduce a new section", "To give the author name", "To summarise the whole text"], "a": "To introduce a new section", "e": "Subheadings break text into sections and tell the reader what each part is about."}, {"id": "erc3_15", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A story says 'The room was silent as a grave.' What technique is this?", "o": ["Alliteration", "Simile", "Personification", "Rhyme"], "a": "Simile", "e": "A simile compares two things using 'as' or 'like'."}, {"id": "erc3_16", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Which question finds the MAIN IDEA of a passage?", "o": ["Who is the author?", "What is this text mostly about?", "What happens at the end?", "How many paragraphs are there?"], "a": "What is this text mostly about?", "e": "The main idea tells you what the whole passage is generally about."}, {"id": "erc3_17", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "The word 'however' in a text signals:", "o": ["More of the same information", "A contrast or opposite point", "The end of the text", "A cause and effect"], "a": "A contrast or opposite point", "e": "However is a connective that signals a contrasting or opposing idea."}, {"id": "erc3_18", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What does it mean when a text is written in the 'first person'?", "o": ["It uses 'he' and 'she", "It uses I and we", "It talks to the reader directly", "It uses no pronouns"], "a": "It uses I and we", "e": "First person writing uses I, me, we, us — the narrator is part of the story."}, {"id": "erc3_19", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Which of these is a FACT rather than an OPINION?", "o": ["Dogs are the best pets.", "Cats are boring animals.", "London is the capital of England.", "Maths is the hardest subject."], "a": "London is the capital of England.", "e": "A fact can be proved. The others are personal opinions."}, {"id": "erc3_20", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What does 'skimming' a text mean?", "o": ["Reading every word carefully", "Reading quickly to get a general idea", "Looking for specific information", "Reading aloud to a friend"], "a": "Reading quickly to get a general idea", "e": "Skimming means running your eyes quickly over text to get the overall gist."}, {"id": "ess3_11", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which of these is a compound sentence?", "o": ["She ran.", "She ran fast.", "She ran fast but she was tired.", "Running fast she finished."], "a": "She ran fast but she was tired.", "e": "A compound sentence joins two independent clauses with a coordinating conjunction like but, and, or."}, {"id": "ess3_12", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is the function of a fronted adverbial?", "o": ["It names the main subject", "It gives extra information at the start of a sentence", "It describes the verb only", "It ends the sentence"], "a": "It gives extra information at the start of a sentence", "e": "Fronted adverbials start the sentence and add detail about time, place or manner."}, {"id": "ess3_13", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Identify the subordinate clause: 'Although it was raining, we went to the park.'", "o": ["we went to the park", "Although it was raining", "went to the park", "the park"], "a": "Although it was raining", "e": "A subordinate clause cannot stand alone — it depends on the main clause."}, {"id": "ess3_14", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence uses a relative clause correctly?", "o": ["The book that was red fell.", "The book, which was red, fell.", "The book which it was red fell.", "The book what was red fell."], "a": "The book, which was red, fell.", "e": "Use 'which' with commas for a non-defining relative clause about a thing."}, {"id": "ess3_15", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What type of sentence is: 'Please tidy your room.'?", "o": ["Declarative", "Interrogative", "Exclamatory", "Imperative"], "a": "Imperative", "e": "An imperative sentence gives a command or instruction."}, {"id": "ess3_16", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence has an embedded clause?", "o": ["The dog barked.", "The dog, who was hungry, barked.", "The hungry dog barked loudly.", "Barking the dog ran."], "a": "The dog, who was hungry, barked.", "e": "An embedded clause is inserted within the main clause, surrounded by commas."}, {"id": "ess3_17", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which is a simple sentence?", "o": ["She sang and he danced.", "She sang beautifully.", "Because she sang they clapped.", "She sang although she was nervous."], "a": "She sang beautifully.", "e": "A simple sentence has one main clause with a subject and verb."}, {"id": "ess3_18", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What does a subordinating conjunction do?", "o": ["Joins two equal clauses", "Introduces a subordinate clause", "Names the subject", "Describes a noun"], "a": "Introduces a subordinate clause", "e": "Words like because, although, when, and if are subordinating conjunctions."}, {"id": "ess3_19", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which example has a fronted adverbial?", "o": ["The cat sat quietly on the mat.", "Quietly, the cat sat on the mat.", "The cat sitting quietly was on the mat.", "The cat sat on the mat quietly."], "a": "Quietly, the cat sat on the mat.", "e": "A fronted adverbial comes before the subject and is followed by a comma."}, {"id": "ess3_20", "s": "english", "t": "Sentence Structure", "l": 3, "q": "A complex sentence contains:", "o": ["Two main clauses", "One main clause and at least one subordinate clause", "Only a subordinate clause", "Three verbs"], "a": "One main clause and at least one subordinate clause", "e": "Complex sentences have a main clause plus a dependent subordinate clause."}, {"id": "es3_11", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["beleive", "believe", "beleave", "beleeve"], "a": "believe", "e": "Remember: 'i before e except after c' — believe."}, {"id": "es3_12", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["seperate", "seperrate", "separate", "separrate"], "a": "separate", "e": "Separate: think 'there is a rat in separate'."}, {"id": "es3_13", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["necessary", "neccessary", "necesary", "neccesary"], "a": "necessary", "e": "Necessary: one c and two s — one collar, two socks."}, {"id": "es3_14", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["definately", "definitely", "definitly", "definetly"], "a": "definitely", "e": "Definitely contains 'finite' — there is definitely a finite end."}, {"id": "es3_15", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["recieve", "recive", "receive", "receve"], "a": "receive", "e": "After c, it is 'ei' not 'ie': receive."}, {"id": "es3_16", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["concious", "consious", "conscious", "conscous"], "a": "conscious", "e": "Conscious: c-o-n-s-c-i-o-u-s — note the hidden sci in the middle."}, {"id": "es3_17", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["occured", "occurred", "ocurred", "occurrd"], "a": "occurred", "e": "Occurred doubles the r: oc-cur-red."}, {"id": "es3_18", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["enviroment", "environment", "enviorment", "enviornment"], "a": "environment", "e": "Environment: en-vi-ron-ment — note the ron in the middle."}, {"id": "es3_19", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["goverment", "govenment", "government", "governement"], "a": "government", "e": "Government: gov-ern-ment — don't forget the n after ern."}, {"id": "es3_20", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["acommodate", "accommodate", "acomodate", "accommadate"], "a": "accommodate", "e": "Accommodate: two c's and two m's — it has room to accommodate both!"}, {"id": "esa3_09", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is a synonym for 'brave'?", "o": ["cowardly", "timid", "courageous", "fearful"], "a": "courageous", "e": "Courageous and brave both mean not afraid of danger."}, {"id": "esa3_10", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'ancient'?", "o": ["old", "historical", "modern", "traditional"], "a": "modern", "e": "Modern (new) is the opposite of ancient (very old)."}, {"id": "esa3_11", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'exhausted'.", "o": ["energetic", "weary", "lively", "alert"], "a": "weary", "e": "Weary means very tired, just like exhausted."}, {"id": "esa3_12", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'generous'?", "o": ["kind", "giving", "mean", "charitable"], "a": "mean", "e": "Mean (selfish) is the opposite of generous."}, {"id": "esa3_13", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'enormous'.", "o": ["tiny", "huge", "small", "slim"], "a": "huge", "e": "Enormous and huge both mean very large."}, {"id": "esa3_14", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'transparent'?", "o": ["clear", "see-through", "opaque", "sheer"], "a": "opaque", "e": "Opaque means not transparent — you cannot see through it."}, {"id": "esa3_15", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'gloomy'.", "o": ["cheerful", "bright", "miserable", "sunny"], "a": "miserable", "e": "Gloomy and miserable both describe a dark or sad feeling."}, {"id": "esa3_16", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'expand'?", "o": ["grow", "enlarge", "shrink", "stretch"], "a": "shrink", "e": "Shrink (get smaller) is the opposite of expand (get bigger)."}, {"id": "esa3_17", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'peculiar'.", "o": ["normal", "ordinary", "strange", "typical"], "a": "strange", "e": "Peculiar and strange both mean unusual or odd."}, {"id": "esa3_18", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'swift'?", "o": ["rapid", "fast", "slow", "quick"], "a": "slow", "e": "Slow is the opposite of swift (very fast)."}, {"id": "esa3_19", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'cunning'.", "o": ["honest", "clumsy", "sly", "straightforward"], "a": "sly", "e": "Cunning and sly both describe someone clever in a sneaky way."}, {"id": "esa3_20", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'humble'?", "o": ["modest", "shy", "arrogant", "quiet"], "a": "arrogant", "e": "Arrogant (thinking you are better than others) is the opposite of humble."}, {"id": "evr3_11", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the word that means the same as both: RING and CALL.", "o": ["phone", "noise", "bell", "sound"], "a": "phone", "e": "Phone means to call someone and is also a type of device — it fits both meanings."}, {"id": "evr3_12", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which word is the odd one out? ROSE, DAISY, TULIP, ROBIN, LILY", "o": ["ROSE", "DAISY", "ROBIN", "LILY"], "a": "ROBIN", "e": "Robin is a bird; the others are all flowers."}, {"id": "evr3_13", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "If FISH is coded as GJTI, how is BIRD coded? (each letter moves forward one)", "o": ["CJSE", "CJRD", "CISE", "BJRD"], "a": "CJSE", "e": "Each letter moves forward one: B→C, I→J, R→S, D→E = CJSE."}, {"id": "evr3_14", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which pair has the same relationship as HOT : COLD?", "o": ["big : large", "dark : night", "happy : sad", "run : jog"], "a": "happy : sad", "e": "Hot and cold are antonyms (opposites), just like happy and sad."}, {"id": "evr3_15", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the sequence: 2, 6, 18, 54, ___", "o": ["108", "162", "81", "72"], "a": "162", "e": "Each term is multiplied by 3: 54 × 3 = 162."}, {"id": "evr3_16", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which number is the odd one out: 4, 9, 16, 20, 25?", "o": ["4", "9", "16", "20"], "a": "20", "e": "4, 9, 16, 25 are square numbers (2², 3², 4², 5²). 20 is not a square number."}, {"id": "evr3_17", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "If A=1, B=2, C=3... what word does 2-1-12-12 spell?", "o": ["CALL", "BALL", "BELL", "BILL"], "a": "BALL", "e": "B=2, A=1, L=12, L=12 → BALL."}, {"id": "evr3_18", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which month is the odd one out: JANUARY, MARCH, JUNE, JULY, AUGUST?", "o": ["JANUARY", "MARCH", "JUNE", "AUGUST"], "a": "JUNE", "e": "January, March, July and August all have 31 days. June has only 30 days."}, {"id": "evr3_19", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Move one letter from the first word to the second to make two new words: PLANT, CAR", "o": ["PAN, CART", "LAT, CARP", "PLN, CARAT", "PLT, CANAL"], "a": "PAN, CART", "e": "Move L from PLANT → PAN; add L to CAR → CARL? No — move P: ANT, CARP. Actually move the A: PLNT is invalid. Move L: PANT + CARL? Best answer: take the L from PLANT → PANT, put it in CAR → CARL. Or: PLAN + CART (move T). Answer: PAN + CART — move L from pLant to CAR = CARL, or move P: LANT is not valid. The answer is PLAN + CART (move T from PLANT). Let us re-check: PLAN, CART — P-L-A-N from PLAN(T), and CART from CAR+T. Yes."}, {"id": "evr3_20", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which word can be added to the end of both: OVER and BOARD to make compound words?", "o": ["LOOK", "SEA", "HEAD", "WALK"], "a": "SEA", "e": "OVERSEAS and SEABOARD are both compound words using SEA."}, {"id": "ev3_16", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'meticulous' mean?", "o": ["careless", "very careful and precise", "quick and rushed", "loud and noisy"], "a": "very careful and precise", "e": "Meticulous means paying great attention to detail."}, {"id": "ev3_17", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'vivid' mean?", "o": ["dull and grey", "unclear", "producing strong clear images", "silent"], "a": "producing strong clear images", "e": "Vivid describes something very bright, clear or intense."}, {"id": "ev3_18", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'resolve' mean?", "o": ["to give up", "to decide firmly or solve a problem", "to confuse", "to ignore"], "a": "to decide firmly or solve a problem", "e": "Resolve means to settle or decide — 'I resolved to try harder.'"}, {"id": "ev3_19", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'deduce' mean?", "o": ["to add information", "to work out by reasoning", "to remove", "to guess randomly"], "a": "to work out by reasoning", "e": "Deduce means to reach a conclusion through logical reasoning."}, {"id": "ev3_20", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'benevolent' mean?", "o": ["cruel and harsh", "well-meaning and kind", "selfish", "dangerous"], "a": "well-meaning and kind", "e": "Benevolent comes from Latin meaning 'well-wishing' — a benevolent person is kind and generous."}, {"id": "egr4_11", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses the subjunctive mood correctly?", "o": ["If I was you, I would leave.", "If I were you, I would leave.", "If I am you, I would leave.", "If I be you, I would leave."], "a": "If I were you, I would leave.", "e": "The subjunctive mood uses 'were' not 'was' for hypothetical situations."}, {"id": "egr4_12", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the dangling modifier: '___ walking home, the rain began to fall.'", "o": ["While I was walking home", "Walking home", "As I walked home", "When I walk home"], "a": "Walking home", "e": "'Walking home' dangles because it is not attached to a clear subject — the rain cannot walk home."}, {"id": "egr4_13", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses 'fewer' and 'less' correctly?", "o": ["There are less people here today.", "I have fewer sugar in my tea.", "There are fewer mistakes in this version.", "She has less books than me."], "a": "There are fewer mistakes in this version.", "e": "Use 'fewer' for countable nouns (mistakes, people) and 'less' for uncountable nouns (sugar, water)."}, {"id": "egr4_14", "s": "english", "t": "Grammar", "l": 4, "q": "Which option correctly changes the direct speech to reported speech? She said: \\"I am going to the shop.\\"", "o": ["She said that she is going to the shop.", "She said that she was going to the shop.", "She said that I am going to the shop.", "She said that I was going to the shop."], "a": "She said that she was going to the shop.", "e": "In reported speech, the tense shifts back: am → was, and the pronoun changes to she."}, {"id": "egr4_15", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence avoids a split infinitive?", "o": ["She wanted to boldly go.", "She wanted to go boldly.", "She boldly wanted to go.", "She wanted boldly to go."], "a": "She wanted to go boldly.", "e": "A split infinitive places an adverb between 'to' and the verb. Keep the infinitive together."}, {"id": "egr4_16", "s": "english", "t": "Grammar", "l": 4, "q": "Choose the correct pronoun: '___ between you and ___, this is a secret.'", "o": ["Between you and I", "Just between we", "Just between you and me", "Between us and I"], "a": "Just between you and me", "e": "After a preposition like 'between', use object pronouns: me, not I."}, {"id": "egr4_17", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses the perfect aspect correctly?", "o": ["She has went to Paris.", "She have gone to Paris.", "She had gone to Paris before I arrived.", "She has go to Paris."], "a": "She had gone to Paris before I arrived.", "e": "The past perfect (had + past participle) shows an action completed before another past event."}, {"id": "egr4_18", "s": "english", "t": "Grammar", "l": 4, "q": "What is the grammatical term for 'Running every day' in: 'Running every day improved her fitness'?", "o": ["Infinitive phrase", "Gerund phrase", "Participial phrase", "Prepositional phrase"], "a": "Gerund phrase", "e": "A gerund is a verb ending in -ing used as a noun. Here it is the subject of the sentence."}, {"id": "egr4_19", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses the Oxford comma correctly?", "o": ["I bought apples, oranges and bananas.", "I bought apples, oranges, and bananas.", "I bought apples oranges, and bananas.", "I bought, apples, oranges, and bananas."], "a": "I bought apples, oranges, and bananas.", "e": "The Oxford comma is the comma before the final item in a list, placed before and."}, {"id": "egr4_20", "s": "english", "t": "Grammar", "l": 4, "q": "Which is an example of an absolute phrase?", "o": ["Running fast", "The work completed, she went home.", "She completed the work.", "After finishing work"], "a": "The work completed, she went home.", "e": "An absolute phrase modifies the whole sentence and has a noun plus a participle."}, {"id": "epu4_11", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence punctuates parenthetical information correctly?", "o": ["The Eiffel Tower — built in 1889 is in Paris.", "The Eiffel Tower, built in 1889, is in Paris.", "The Eiffel Tower built in 1889, is in Paris.", "The Eiffel Tower built, in 1889, is in Paris."], "a": "The Eiffel Tower, built in 1889, is in Paris.", "e": "Commas correctly enclose the parenthetical phrase built in 1889."}, {"id": "epu4_12", "s": "english", "t": "Punctuation", "l": 4, "q": "When should you use a colon?", "o": ["Before a list or explanation", "After every adjective", "To join two unrelated clauses", "Instead of a comma in lists"], "a": "Before a list or explanation", "e": "A colon introduces a list, quotation, or explanation: like this."}, {"id": "epu4_13", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses an em dash correctly?", "o": ["She had one dream—to become a pilot.", "She had—one dream to become—a pilot.", "She—had one dream to become a pilot.", "She had one dream to become—a pilot."], "a": "She had one dream—to become a pilot.", "e": "An em dash can introduce an explanation or emphasis at the end of a clause."}, {"id": "epu4_14", "s": "english", "t": "Punctuation", "l": 4, "q": "Which correctly punctuates this sentence? 'Its a dogs life'", "o": ["It's a dog's life.", "Its a dogs life.", "It's a dogs life.", "Its a dog's life."], "a": "It's a dog's life.", "e": "It's = it is (contraction); dog's = belonging to the dog (possessive). Both need apostrophes."}, {"id": "epu4_15", "s": "english", "t": "Punctuation", "l": 4, "q": "Where does the punctuation go when a quotation ends a sentence? She whispered ___ the secret is safe ___", "o": ["the secret is safe.", "the secret is safe.", "the secret is safe\\".", "the secret is safe", "."], "a": "\\"the secret is safe.\\"", "e": "The full stop goes inside the closing quotation mark when the quote ends the sentence."}, {"id": "epu4_16", "s": "english", "t": "Punctuation", "l": 4, "q": "Which is punctuated correctly?", "o": ["The students — who had studied hard — passed easily.", "The students, who had studied hard passed easily.", "The students who had studied hard — passed, easily.", "The students — who had studied hard, passed easily."], "a": "The students — who had studied hard — passed easily.", "e": "Paired em dashes correctly enclose the non-essential relative clause."}, {"id": "epu4_17", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence correctly uses an ellipsis?", "o": ["She opened the door and...", "She opened...the door and saw.", "She...opened the door", "She opened the door... and gasped."], "a": "She opened the door... and gasped.", "e": "An ellipsis creates suspense or shows a pause, most effectively before a reveal."}, {"id": "epu4_18", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses a hyphen correctly?", "o": ["A well known author visited our school.", "A well-known author visited our school.", "A well, known author visited our school.", "A wellknown author visited our school."], "a": "A well-known author visited our school.", "e": "Hyphens join compound adjectives that appear before a noun: well-known author."}, {"id": "epu4_19", "s": "english", "t": "Punctuation", "l": 4, "q": "What punctuation follows 'Dear Mr Smith' in a formal letter?", "o": ["Comma", "Exclamation mark", "Full stop", "Colon"], "a": "Comma", "e": "In a formal letter, 'Dear Mr Smith,' is followed by a comma before the body text."}, {"id": "epu4_20", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence correctly handles a clause beginning with 'which'?", "o": ["The bridge which was built in 1900 collapsed.", "The bridge, which was built in 1900, collapsed.", "The bridge which, was built in 1900, collapsed.", "The bridge, which was built in 1900 collapsed."], "a": "The bridge, which was built in 1900, collapsed.", "e": "Non-defining relative clauses using 'which' are enclosed in commas."}, {"id": "erc4_11", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What is 'dramatic irony' in a story?", "o": ["When two characters argue dramatically", "When the reader knows something a character does not", "When the plot is very exciting", "When the ending is unexpected"], "a": "When the reader knows something a character does not", "e": "Dramatic irony creates tension because the audience has information that characters lack."}, {"id": "erc4_12", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What effect does an unreliable narrator create?", "o": ["The story is told very clearly", "The reader questions whether to trust the narrator", "The story is always true", "The narrator knows everything"], "a": "The reader questions whether to trust the narrator", "e": "An unreliable narrator makes readers think critically about whether what they are told is accurate."}, {"id": "erc4_13", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Which technique does the author use? 'The wind howled and the trees groaned.'", "o": ["Simile", "Alliteration", "Personification", "Onomatopoeia"], "a": "Personification", "e": "Personification gives human qualities (howling, groaning) to non-human things."}, {"id": "erc4_14", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What is the author's 'tone' in a text?", "o": ["The font size used", "The attitude or feeling conveyed through word choice", "The setting of the story", "The length of sentences"], "a": "The attitude or feeling conveyed through word choice", "e": "The author's tone might be formal, ironic, melancholic, or humorous — shown through language choices."}, {"id": "erc4_15", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What does it mean to evaluate a text?", "o": ["Copy it out neatly", "Make a judgement about its quality or effectiveness", "Find the main character", "Count the paragraphs"], "a": "Make a judgement about its quality or effectiveness", "e": "Evaluating means assessing how well a text achieves its purpose, using evidence."}, {"id": "erc4_16", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Which question requires a SYNTHESIS response?", "o": ["What colour was the car?", "How many characters are there?", "How do both texts present the theme of loss differently?", "Who wrote this text?"], "a": "How do both texts present the theme of loss differently?", "e": "Synthesis requires drawing together ideas from multiple sources or across a text."}, {"id": "erc4_17", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "A writer uses short, sharp sentences in a chase scene. What effect does this create?", "o": ["A slow, calm feeling", "A sense of speed and tension", "Confusion for the reader", "A humorous tone"], "a": "A sense of speed and tension", "e": "Short sentences speed up the pace of reading, mirroring the urgency of the action."}, {"id": "erc4_18", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What is 'pathetic fallacy'?", "o": ["A false argument in a text", "When weather reflects the mood of a character", "A type of rhyme scheme", "When a narrator is untrustworthy"], "a": "When weather reflects the mood of a character", "e": "Pathetic fallacy uses weather or environment to reflect a character's emotions, e.g. stormy skies for anger."}, {"id": "erc4_19", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "A text argues that screen time harms children. Which counter-argument most effectively challenges this?", "o": ["Screens are colourful and interesting.", "Research shows educational apps improve literacy when used with guidance.", "Children enjoy using screens.", "Some adults also use screens a lot."], "a": "Research shows educational apps improve literacy when used with guidance.", "e": "An effective counter-argument uses evidence and addresses the specific concern raised."}, {"id": "erc4_20", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What is a 'rhetorical question'?", "o": ["A question asked by a teacher", "A question that does not require an answer", "A question with multiple correct answers", "A question at the end of a text"], "a": "A question that does not require an answer", "e": "Rhetorical questions are asked for effect, to make the reader think rather than to get a reply."}, {"id": "ess4_11", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses a non-finite clause correctly?", "o": ["Having finished the exam, she felt relieved.", "Having finished the exam was relieved.", "She having finished felt relieved.", "Finished the exam having she was relieved."], "a": "Having finished the exam, she felt relieved.", "e": "A non-finite clause has a participle (having finished) and is followed by the main clause with a subject."}, {"id": "ess4_12", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is a 'periodic sentence'?", "o": ["A very short sentence", "A sentence where the main clause comes at the end", "A sentence written in the past tense", "A sentence with many adjectives"], "a": "A sentence where the main clause comes at the end", "e": "Periodic sentences build suspense by withholding the main idea until the end."}, {"id": "ess4_13", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses anaphora as a rhetorical device?", "o": ["We shall fight on the beaches, we shall fight on the seas, we shall fight in the air.", "The tall, dark, menacing figure approached.", "He ran quickly and quietly.", "Despite the rain, the match continued."], "a": "We shall fight on the beaches, we shall fight on the seas, we shall fight in the air.", "e": "Anaphora is the repetition of a phrase at the start of successive clauses — 'we shall fight'."}, {"id": "ess4_14", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is the effect of using a minor sentence (sentence fragment)?", "o": ["It makes the writing incorrect", "It adds emphasis or drama", "It shows poor grammar", "It lengthens the text"], "a": "It adds emphasis or drama", "e": "Minor sentences (fragments) such as Never. Silence. are used deliberately for impact."}, {"id": "ess4_15", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses a noun phrase as its subject?", "o": ["She ran.", "The old, crumbling castle on the hill stood alone.", "Running is fun.", "It rained."], "a": "The old, crumbling castle on the hill stood alone.", "e": "The subject is an extended noun phrase: The old, crumbling castle on the hill."}, {"id": "ess4_16", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is 'tricolon' in writing?", "o": ["A series of three parallel items", "A three-sentence paragraph", "A punctuation mark", "A three-part argument"], "a": "A series of three parallel items", "e": "Tricolon is a list of three parallel phrases for effect: 'I came, I saw, I conquered.'"}, {"id": "ess4_17", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses the passive voice to emphasise the object?", "o": ["The scientist discovered the cure.", "The cure was discovered by the scientist.", "Discovering the cure, the scientist was praised.", "The scientist had discovered the cure."], "a": "The cure was discovered by the scientist.", "e": "Passive voice moves the object (cure) to the subject position, giving it more emphasis."}, {"id": "ess4_18", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which technique is used in: 'It was the best of times, it was the worst of times'?", "o": ["Simile", "Anaphora and antithesis", "Alliteration", "Hyperbole"], "a": "Anaphora and antithesis", "e": "'It was the' is repeated (anaphora) and best/worst are opposites (antithesis)."}, {"id": "ess4_19", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is an appositive in grammar?", "o": ["A noun or phrase that renames another noun beside it", "A type of verb", "A question word", "A preposition"], "a": "A noun or phrase that renames another noun beside it", "e": "An appositive gives more information about a noun: 'Sherlock, the famous detective, solved the case.'"}, {"id": "ess4_20", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses epistrophe?", "o": ["She cried because she was sad, she sobbed because she was sad, she wept because she was sad.", "The wind blew hard and the rain fell.", "Running fast, jumping high, she excelled.", "The quick brown fox jumped over the lazy dog."], "a": "She cried because she was sad, she sobbed because she was sad, she wept because she was sad.", "e": "Epistrophe is the repetition of words at the END of successive clauses — 'because she was sad'."}, {"id": "esp4_11", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["liasion", "liason", "liaison", "laiason"], "a": "liaison", "e": "Liaison: l-i-a-i-s-o-n. Remember the two i sounds."}, {"id": "esp4_12", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["millenium", "millennium", "milenium", "milleniuum"], "a": "millennium", "e": "Millennium: milli (thousand) + ennium — double l and double n."}, {"id": "esp4_13", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["concsious", "conscientious", "consientious", "conscientous"], "a": "conscientious", "e": "Conscientious: con-sci-en-ti-ous — a frequently misspelt word. Note the sci in the middle."}, {"id": "esp4_14", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["inoculate", "innoculate", "inoculaate", "innocullate"], "a": "inoculate", "e": "Inoculate has only one n and one c — a common spelling trap."}, {"id": "esp4_15", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["desiccate", "dessicate", "desicate", "dessccate"], "a": "desiccate", "e": "Desiccate: one s, double c — to dry something out completely."}, {"id": "esp4_16", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["harass", "harrass", "harasss", "haras"], "a": "harass", "e": "Harass: one r, double s — a common error is doubling the r."}, {"id": "esp4_17", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["mischievious", "mischievous", "mischeivous", "mischievouss"], "a": "mischievous", "e": "Mischievous: mis-chie-vous. There is no i after the v — not mischievious."}, {"id": "esp4_18", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["supercede", "superseed", "supersede", "suparasede"], "a": "supersede", "e": "Supersede: super + sede (from Latin sedere, to sit). It is the only -sede word, not -cede."}, {"id": "esp4_19", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["perseverance", "perserverance", "persaverance", "persevarance"], "a": "perseverance", "e": "Perseverance: per-se-ver-ance — note the ever in the middle."}, {"id": "esp4_20", "s": "english", "t": "Spelling", "l": 4, "q": "Which spelling is correct?", "o": ["sacrilegious", "sacreligious", "sacrilegeous", "sacreligous"], "a": "sacrilegious", "e": "Sacrilegious: note it contains sacrilege not sacrelege — a very common error."}, {"id": "esa4_11", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the most precise synonym for 'happy' in a formal context.", "o": ["glad", "elated", "pleased", "content"], "a": "elated", "e": "Elated is the most intense and formal synonym — it means overjoyed or extremely happy."}, {"id": "esa4_12", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is an antonym for 'eloquent'?", "o": ["fluent", "articulate", "inarticulate", "verbose"], "a": "inarticulate", "e": "Inarticulate (unable to express oneself clearly) is the opposite of eloquent (well-spoken)."}, {"id": "esa4_13", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the synonym for 'loquacious'.", "o": ["silent", "reserved", "talkative", "thoughtful"], "a": "talkative", "e": "Loquacious means tending to talk a great deal."}, {"id": "esa4_14", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is an antonym for 'ephemeral'?", "o": ["brief", "fleeting", "lasting", "short-lived"], "a": "lasting", "e": "Ephemeral means lasting for only a short time; lasting (or permanent) is its antonym."}, {"id": "esa4_15", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the synonym for 'vociferous'.", "o": ["quiet", "clamorous", "gentle", "whispered"], "a": "clamorous", "e": "Vociferous and clamorous both mean making a loud, insistent noise or outcry."}, {"id": "esa4_16", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is an antonym for 'nonchalant'?", "o": ["casual", "indifferent", "anxious", "relaxed"], "a": "anxious", "e": "Nonchalant means calm and relaxed; anxious (worried) is its antonym."}, {"id": "esa4_17", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the synonym for 'ameliorate'.", "o": ["worsen", "deteriorate", "improve", "ignore"], "a": "improve", "e": "Ameliorate means to make something bad better — to improve it."}, {"id": "esa4_18", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is an antonym for 'diligent'?", "o": ["hardworking", "careful", "lazy", "thorough"], "a": "lazy", "e": "Diligent means working carefully and persistently; lazy is its antonym."}, {"id": "esa4_19", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the synonym for 'reticent'.", "o": ["outspoken", "reserved", "enthusiastic", "loud"], "a": "reserved", "e": "Reticent and reserved both describe someone reluctant to speak or share feelings."}, {"id": "esa4_20", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is an antonym for 'ostentatious'?", "o": ["showy", "flamboyant", "modest", "extravagant"], "a": "modest", "e": "Ostentatious means designed to impress; modest (unassuming) is its antonym."}, {"id": "evr4_11", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "If REASON is coded as SFBTPO, what is the code for THINK?", "o": ["UIJOL", "UIJML", "UJIOL", "TIJOL"], "a": "UIJOL", "e": "Each letter moves forward one in the alphabet: T→U, H→I, I→J, N→O, K→L = UIJOL."}, {"id": "evr4_12", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word completes both sentences? The ___ was sharp. Please ___ the paper.", "o": ["cut", "knife", "scissors", "fold"], "a": "cut", "e": "The cut was sharp (noun) and please cut the paper (verb) — 'cut' works in both."}, {"id": "evr4_13", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Odd one out: OBSTINATE, STUBBORN, TENACIOUS, FLEXIBLE, DOGGED", "o": ["OBSTINATE", "STUBBORN", "FLEXIBLE", "DOGGED"], "a": "FLEXIBLE", "e": "All others mean stubbornly determined. Flexible means willing to change or adapt."}, {"id": "evr4_14", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "What comes next in the sequence? AZ, BY, CX, DW, ___", "o": ["EV", "EU", "FV", "EW"], "a": "EV", "e": "First letters go A,B,C,D,E (forward); second letters go Z,Y,X,W,V (backward). Answer: EV."}, {"id": "evr4_15", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Move one letter from the first word to the second to make two new words: BRAND, SOIL", "o": ["BRAN, SOILD", "BAN, ROILS", "RAND, BROIL", "BAND, ROILS"], "a": "RAND, BROIL", "e": "Move B from BRAND → RAND; add B to SOIL → BROIL. Both are valid words."}, {"id": "evr4_16", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "If all GLOBS are BLOBS and some BLOBS are SNOBS, which must be true?", "o": ["All SNOBS are GLOBS", "Some GLOBS might be SNOBS", "All GLOBS are SNOBS", "No GLOBS are SNOBS"], "a": "Some GLOBS might be SNOBS", "e": "Since all GLOBS are BLOBS and some BLOBS are SNOBS, it is possible (but not certain) that some GLOBS are SNOBS."}, {"id": "evr4_17", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word is missing? PAINT : ARTIST :: SCALPEL : ___", "o": ["hospital", "surgeon", "nurse", "doctor"], "a": "surgeon", "e": "A paint is the tool of an artist; a scalpel is the tool of a surgeon."}, {"id": "evr4_18", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the hidden word across these two words: WITH ERING", "o": ["THE", "HER", "RING", "WITH"], "a": "HER", "e": "The hidden word spans the two words: witH ERing → HER."}, {"id": "evr4_19", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which four-letter word can be placed in front of these to make new words? ___FALL, ___LIGHT, ___BREAK, ___RISE", "o": ["MOON", "SUN", "DAY", "STAR"], "a": "SUN", "e": "SUNFALL (sunset), SUNLIGHT, SUNBREAK, SUNRISE — SUN completes all four."}, {"id": "evr4_20", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "ABCD is coded 1234. If E=5, F=6... what word does 6-1-3-5 spell?", "o": ["FACE", "FADE", "DACE", "CAFE"], "a": "FACE", "e": "F=6, A=1, C=3, E=5 → FACE."}, {"id": "evo4_11", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'obsequious' mean?", "o": ["argumentative", "excessively eager to please or serve", "completely silent", "extremely intelligent"], "a": "excessively eager to please or serve", "e": "Obsequious describes someone who is servile and fawning — overly eager to impress."}, {"id": "evo4_12", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'sycophant' mean?", "o": ["a type of tree", "someone who uses flattery to gain favour", "a musical instrument", "a rare disease"], "a": "someone who uses flattery to gain favour", "e": "A sycophant is a person who acts obsequiously to gain advantage — a flatterer or yes-man."}, {"id": "evo4_13", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'equivocate' mean?", "o": ["to speak very clearly", "to use ambiguous language to avoid commitment", "to make a firm decision", "to speak loudly"], "a": "to use ambiguous language to avoid commitment", "e": "To equivocate is to hedge or be deliberately unclear so as to mislead or avoid commitment."}, {"id": "evo4_14", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'perspicacious' mean?", "o": ["having a very bad memory", "very sweaty", "having a ready insight and sharp understanding", "extremely talkative"], "a": "having a ready insight and sharp understanding", "e": "Perspicacious describes someone with keen insight and clear-sighted understanding."}, {"id": "evo4_15", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'laconic' mean?", "o": ["using very few words", "very tall", "extremely loud", "highly decorated"], "a": "using very few words", "e": "Laconic means brief and concise in speech or expression. The Spartans of Laconia were famous for it."}, {"id": "evo4_16", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'recalcitrant' mean?", "o": ["very obedient", "stubbornly resistant to authority", "extremely generous", "easily frightened"], "a": "stubbornly resistant to authority", "e": "Recalcitrant describes someone who refuses to obey or be controlled despite demands."}, {"id": "evo4_17", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'magnanimous' mean?", "o": ["very small", "extremely angry", "generous and forgiving, especially towards a rival", "loudly spoken"], "a": "generous and forgiving, especially towards a rival", "e": "Magnanimous means showing great generosity of spirit — especially towards those you have defeated."}, {"id": "evo4_18", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'querulous' mean?", "o": ["very curious", "complaining in a petulant way", "extremely brave", "highly organised"], "a": "complaining in a petulant way", "e": "Querulous means habitually complaining or whining about things."}, {"id": "evo4_19", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'perfidious' mean?", "o": ["very perfect", "loyal and true", "deceitful and treacherous", "extremely careful"], "a": "deceitful and treacherous", "e": "Perfidious means deceitful and untrustworthy — Shakespeare used it in 'perfidious Albion'."}, {"id": "evo4_20", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does 'propitious' mean?", "o": ["giving a bad result", "giving a good chance of success", "relating to property", "very slow"], "a": "giving a good chance of success", "e": "Propitious means showing or giving signs that something is likely to be successful — auspicious."}, {"id": "mf3_21", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¾ of 24?", "o": ["12", "16", "18", "20"], "a": "18", "e": "Find ¼ first: 24÷4=6. Then ×3: 6×3=18."}, {"id": "mf3_22", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction is equivalent to 2/3?", "o": ["3/4", "2/4", "4/6", "4/5"], "a": "4/6", "e": "Multiply top and bottom of 2/3 by 2: 4/6. Both equal the same amount."}, {"id": "mf3_23", "s": "maths", "t": "Fractions", "l": 3, "q": "Simplify 6/9 to its lowest terms.", "o": ["2/3", "3/4", "1/2", "4/6"], "a": "2/3", "e": "Divide top and bottom by 3: 6÷3=2, 9÷3=3. Answer: 2/3."}, {"id": "mf3_24", "s": "maths", "t": "Fractions", "l": 3, "q": "1/4 + 2/4 = ?", "o": ["3/8", "2/8", "3/4", "1/2"], "a": "3/4", "e": "Same denominator: just add the tops. 1+2=3, so 3/4."}, {"id": "mf3_25", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction is larger: 3/5 or 2/3?", "o": ["3/5", "They are equal", "2/3", "Cannot tell"], "a": "2/3", "e": "Convert to same denominator (15): 3/5=9/15, 2/3=10/15. So 2/3 is larger."}, {"id": "mf3_26", "s": "maths", "t": "Fractions", "l": 3, "q": "Convert 1¾ to an improper fraction.", "o": ["5/4", "6/4", "7/4", "8/4"], "a": "7/4", "e": "1 whole = 4/4. Add 3/4: 4/4+3/4=7/4."}, {"id": "mf3_27", "s": "maths", "t": "Fractions", "l": 3, "q": "What is 2/5 of 30?", "o": ["6", "10", "12", "15"], "a": "12", "e": "2/5 of 30: find 1/5 first (30÷5=6), then ×2: 6×2=12."}, {"id": "mf3_28", "s": "maths", "t": "Fractions", "l": 3, "q": "5/8 − 2/8 = ?", "o": ["3/16", "7/8", "3/8", "1/4"], "a": "3/8", "e": "Same denominator: subtract tops. 5−2=3, so 3/8."}, {"id": "mf3_29", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction is NOT equivalent to 3/4?", "o": ["9/12", "6/8", "6/10", "12/16"], "a": "6/10", "e": "6/10 simplifies to 3/5, not 3/4. The others all equal 3/4."}, {"id": "mf3_30", "s": "maths", "t": "Fractions", "l": 3, "q": "Put in order smallest to largest: 1/2, 1/3, 1/4", "o": ["1/2, 1/3, 1/4", "1/4, 1/2, 1/3", "1/3, 1/4, 1/2", "1/4, 1/3, 1/2"], "a": "1/4, 1/3, 1/2", "e": "When the top (numerator) is the same, the larger the bottom the smaller the fraction."}, {"id": "mf3_31", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ¾ of 40?", "o": ["10", "20", "30", "35"], "a": "30", "e": "¼ of 40 = 10. Multiply by 3: 10×3=30."}, {"id": "mf3_32", "s": "maths", "t": "Fractions", "l": 3, "q": "What is 5/6 with denominator 12?", "o": ["5/12", "6/12", "8/12", "10/12"], "a": "10/12", "e": "Multiply top and bottom by 2: 5×2=10, 6×2=12. So 10/12."}, {"id": "mf3_33", "s": "maths", "t": "Fractions", "l": 3, "q": "Convert 11/4 to a mixed number.", "o": ["2¼", "2¾", "3¼", "2½"], "a": "2¾", "e": "11÷4=2 remainder 3. So 2 whole ones and 3/4 left over: 2¾."}, {"id": "mf3_34", "s": "maths", "t": "Fractions", "l": 3, "q": "2/3 + 1/3 = ?", "o": ["3/6", "3/3", "2/3", "1"], "a": "1", "e": "2/3+1/3=3/3=1 whole."}, {"id": "mf3_35", "s": "maths", "t": "Fractions", "l": 3, "q": "Which fraction is closest to 1?", "o": ["3/4", "2/3", "5/6", "7/8"], "a": "7/8", "e": "7/8=0.875, 5/6≈0.833, 3/4=0.75, 2/3≈0.667. 7/8 is closest to 1."}, {"id": "mf3_36", "s": "maths", "t": "Fractions", "l": 3, "q": "A pizza has 8 slices. Sam eats 3. What fraction is left?", "o": ["3/8", "4/8", "5/8", "6/8"], "a": "5/8", "e": "8 slices total, 3 eaten: 8−3=5 left. Fraction = 5/8."}, {"id": "mf3_37", "s": "maths", "t": "Fractions", "l": 3, "q": "What is ½ of ½?", "o": ["1/2", "1/3", "1/4", "2/4"], "a": "1/4", "e": "Half of a half is one quarter: ½ × ½ = 1/4."}, {"id": "mf3_38", "s": "maths", "t": "Fractions", "l": 3, "q": "Which is the smallest fraction?", "o": ["2/3", "3/4", "5/8", "1/2"], "a": "1/2", "e": "Convert to decimals: 1/2=0.5, 5/8=0.625, 2/3≈0.667, 3/4=0.75. Smallest is 1/2."}, {"id": "mf3_39", "s": "maths", "t": "Fractions", "l": 3, "q": "Find 3/10 of 50.", "o": ["5", "10", "15", "20"], "a": "15", "e": "1/10 of 50=5. Multiply by 3: 5×3=15."}, {"id": "mf3_40", "s": "maths", "t": "Fractions", "l": 3, "q": "7/8 − 3/8 = ?", "o": ["1/4", "3/8", "4/16", "1/2"], "a": "1/2", "e": "7−3=4, so 4/8. Simplify: 4/8=1/2."}, {"id": "mmd3_21", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "7 × 8 = ?", "o": ["54", "56", "58", "63"], "a": "56", "e": "7×8=56. A common mistake is confusing with 7×9=63 or 6×9=54."}, {"id": "mmd3_22", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "9 × 6 = ?", "o": ["48", "54", "56", "63"], "a": "54", "e": "Count up in 9s or 6s: 9×6=54."}, {"id": "mmd3_23", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "84 ÷ 7 = ?", "o": ["11", "12", "13", "14"], "a": "12", "e": "7×12=84. Check: 7×10=70, 7×2=14, 70+14=84. ✓"}, {"id": "mmd3_24", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "96 ÷ 8 = ?", "o": ["8", "10", "12", "14"], "a": "12", "e": "8×12=96. Check: 8×10=80, 8×2=16, 80+16=96. ✓"}, {"id": "mmd3_25", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "Which of these is NOT a factor of 24?", "o": ["3", "4", "5", "6"], "a": "5", "e": "Factors of 24: 1,2,3,4,6,8,12,24. 5 does not divide into 24 exactly."}, {"id": "mmd3_26", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "What is the next multiple of 7 after 49?", "o": ["52", "55", "56", "63"], "a": "56", "e": "Multiples of 7: …42, 49, 56, 63. The next after 49 is 56."}, {"id": "mmd3_27", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "A minibus holds 12 passengers. How many minibuses for 84 passengers?", "o": ["5", "6", "7", "8"], "a": "7", "e": "84÷12=7. Exactly 7 minibuses needed."}, {"id": "mmd3_28", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "6 × 9 × 2 = ?", "o": ["96", "100", "108", "112"], "a": "108", "e": "Work left to right: 6×9=54, then 54×2=108."}, {"id": "mmd3_29", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "125 ÷ 5 = ?", "o": ["20", "24", "25", "30"], "a": "25", "e": "5×25=125. Think: 5×20=100, 5×5=25, total 125."}, {"id": "mmd3_30", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "Which number is a common factor of 12 and 18?", "o": ["4", "5", "6", "9"], "a": "6", "e": "Factors of 12: 1,2,3,4,6,12. Factors of 18: 1,2,3,6,9,18. Common: 1,2,3,6. Answer: 6."}, {"id": "mmd3_31", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "9 × 9 = ?", "o": ["72", "79", "81", "89"], "a": "81", "e": "9×9=81. Tip: 9×10=90, subtract 9: 90−9=81."}, {"id": "mmd3_32", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "132 ÷ 12 = ?", "o": ["10", "11", "12", "13"], "a": "11", "e": "12×11=132. Check: 12×10=120, 12×1=12, 120+12=132. ✓"}, {"id": "mmd3_33", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "What is the LCM (lowest common multiple) of 4 and 6?", "o": ["8", "10", "12", "24"], "a": "12", "e": "Multiples of 4: 4,8,12… Multiples of 6: 6,12… First common one is 12."}, {"id": "mmd3_34", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "Pens come in packs of 6. How many packs for 42 pens?", "o": ["5", "6", "7", "8"], "a": "7", "e": "42÷6=7. Exactly 7 packs needed."}, {"id": "mmd3_35", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "8 × 12 = ?", "o": ["88", "92", "96", "104"], "a": "96", "e": "8×12: 8×10=80, 8×2=16, 80+16=96."}, {"id": "mmd3_36", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "What is the remainder when 37 is divided by 5?", "o": ["1", "2", "3", "4"], "a": "2", "e": "5×7=35. 37−35=2 remainder."}, {"id": "mmd3_37", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "Which of these numbers is a multiple of both 3 and 4?", "o": ["10", "14", "18", "24"], "a": "24", "e": "Multiples of 3: 3,6,9,12,15,18,21,24. Multiples of 4: 4,8,12,16,20,24. First common: 12, then 24."}, {"id": "mmd3_38", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "11 × 12 = ?", "o": ["121", "122", "132", "142"], "a": "132", "e": "11×12: 10×12=120, 1×12=12, 120+12=132."}, {"id": "mmd3_39", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "Eggs come in boxes of 12. A shop has 7 boxes. How many eggs?", "o": ["74", "82", "84", "96"], "a": "84", "e": "7×12=84."}, {"id": "mmd3_40", "s": "maths", "t": "Multiplication & Division", "l": 3, "q": "What is the remainder when 50 is divided by 7?", "o": ["1", "2", "3", "6"], "a": "1", "e": "7×7=49. 50−49=1 remainder."}, {"id": "mpv3_21", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the value of the digit 4 in 34,621?", "o": ["4", "40", "400", "4,000"], "a": "4,000", "e": "In 34,621 the 4 is in the thousands place: its value is 4,000."}, {"id": "mpv3_22", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Round 4,758 to the nearest hundred.", "o": ["4,700", "4,750", "4,800", "5,000"], "a": "4,800", "e": "Look at the tens digit: 5. 5 or more → round up. 4,800."}, {"id": "mpv3_23", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which of these is the largest number?", "o": ["45,201", "45,210", "45,021", "45,120"], "a": "45,210", "e": "All start 45,2__, then compare hundreds: 210 > 201 > 120 > 021."}, {"id": "mpv3_24", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is −3 + 7?", "o": ["−10", "−4", "4", "10"], "a": "4", "e": "Start at −3 on a number line, move 7 right: −3+7=4."}, {"id": "mpv3_25", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Write 20,050 in words.", "o": ["Twenty thousand and five", "Twenty thousand and fifty", "Two thousand and fifty", "Twenty-five thousand"], "a": "Twenty thousand and fifty", "e": "20,050: twenty thousand (20,000) + fifty (50)."}, {"id": "mpv3_26", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 10 less than −4?", "o": ["−14", "−6", "6", "14"], "a": "−14", "e": "−4 − 10 = −14. Move 10 left on the number line from −4."}, {"id": "mpv3_27", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Round 23,456 to the nearest thousand.", "o": ["22,000", "23,000", "23,500", "24,000"], "a": "23,000", "e": "Hundreds digit is 4 (less than 5), so round down: 23,000."}, {"id": "mpv3_28", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the value of the digit 7 in 5.7?", "o": ["7", "7/10", "7/100", "70"], "a": "7/10", "e": "In 5.7, the 7 is in the tenths place. Its value is 7/10."}, {"id": "mpv3_29", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which list is in order from smallest to largest?", "o": ["3.2, 3.12, 3.02", "3.02, 3.12, 3.2", "3.12, 3.02, 3.2", "3.2, 3.02, 3.12"], "a": "3.02, 3.12, 3.2", "e": "3.02 < 3.12 < 3.2. Compare tenths first: 0<1<2."}, {"id": "mpv3_30", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is −8 + 5?", "o": ["−13", "−3", "3", "13"], "a": "−3", "e": "Start at −8, move 5 right: −8+5=−3."}, {"id": "mpv3_31", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 100,000 − 1?", "o": ["9,999", "99,000", "99,999", "99,001"], "a": "99,999", "e": "100,000 − 1 = 99,999."}, {"id": "mpv3_32", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Write 305,060 in words.", "o": ["Three hundred and five thousand and sixty", "Three hundred and fifty thousand and six", "Three million, five thousand and sixty", "Three hundred and five thousand six hundred"], "a": "Three hundred and five thousand and sixty", "e": "305,060: 300,000 + 5,000 + 60."}, {"id": "mpv3_33", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which number is halfway between 400 and 600?", "o": ["450", "480", "500", "550"], "a": "500", "e": "Halfway: (400+600)÷2 = 1000÷2 = 500."}, {"id": "mpv3_34", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the Roman numeral for 49?", "o": ["IL", "XLIX", "XLXI", "IXL"], "a": "XLIX", "e": "49 = 40(XL) + 9(IX) = XLIX."}, {"id": "mpv3_35", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Round 0.87 to the nearest whole number.", "o": ["0", "0.9", "1", "2"], "a": "1", "e": "The tenths digit is 8 (≥5), so round up: 1."}, {"id": "mpv3_36", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 3.45 × 10?", "o": ["0.345", "3.450", "34.5", "345"], "a": "34.5", "e": "Multiplying by 10 moves each digit one place left: 3.45 × 10 = 34.5."}, {"id": "mpv3_37", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "Which temperature is coldest?", "o": ["−1°C", "−10°C", "0°C", "5°C"], "a": "−10°C", "e": "On a number line, −10 is furthest left, so it is the coldest."}, {"id": "mpv3_38", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 2.6 × 100?", "o": ["0.026", "26", "260", "2,600"], "a": "260", "e": "Moving digits two places left: 2.6 × 100 = 260."}, {"id": "mpv3_39", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is 5,000 ÷ 100?", "o": ["5", "50", "500", "5,000"], "a": "50", "e": "Dividing by 100 moves digits two places right: 5,000 ÷ 100 = 50."}, {"id": "mpv3_40", "s": "maths", "t": "Place Value & Number", "l": 3, "q": "What is the value of the digit 9 in 4.09?", "o": ["9", "9/10", "9/100", "90"], "a": "9/100", "e": "In 4.09, the 9 is in the hundredths place: 9/100."}, {"id": "mas3_21", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "4,532 + 2,789 = ?", "o": ["6,221", "7,221", "7,321", "7,421"], "a": "7,321", "e": "Add column by column carrying: 2+9=11 (write 1 carry 1), 3+8+1=12 (write 2 carry 1), 5+7+1=13 (write 3 carry 1), 4+2+1=7. Answer: 7,321."}, {"id": "mas3_22", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "8,005 − 3,447 = ?", "o": ["4,458", "4,558", "4,657", "5,558"], "a": "4,558", "e": "8,005 − 3,447 = 4,558. Use column subtraction with borrowing."}, {"id": "mas3_23", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What must be added to 4,375 to make 7,000?", "o": ["2,525", "2,625", "2,635", "3,625"], "a": "2,625", "e": "7,000 − 4,375 = 2,625."}, {"id": "mas3_24", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A shop sells 1,248 items on Monday and 967 on Tuesday. How many in total?", "o": ["2,105", "2,115", "2,205", "2,215"], "a": "2,215", "e": "1,248 + 967 = 2,215."}, {"id": "mas3_25", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "12,000 − 4,563 = ?", "o": ["7,347", "7,437", "7,447", "8,437"], "a": "7,437", "e": "12,000 − 4,563 = 7,437. Use column subtraction."}, {"id": "mas3_26", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "3,706 + 4,598 = ?", "o": ["7,204", "8,204", "8,304", "8,404"], "a": "8,304", "e": "3,706 + 4,598: 6+8=14 (write 4 carry 1), 0+9+1=10 (write 0 carry 1), 7+5+1=13 (write 3 carry 1), 3+4+1=8. Answer: 8,304."}, {"id": "mas3_27", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is the difference between 9,010 and 5,673?", "o": ["3,237", "3,337", "3,437", "4,337"], "a": "3,337", "e": "9,010 − 5,673 = 3,337."}, {"id": "mas3_28", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "25,400 + 17,850 = ?", "o": ["42,150", "43,150", "43,250", "43,350"], "a": "43,250", "e": "25,400 + 17,850 = 43,250."}, {"id": "mas3_29", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A train carries 435 passengers. 178 get off. How many remain?", "o": ["247", "257", "267", "277"], "a": "257", "e": "435 − 178 = 257."}, {"id": "mas3_30", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "999 + 999 = ?", "o": ["1,888", "1,899", "1,998", "2,001"], "a": "1,998", "e": "999 + 999 = 1,998. Or: 1,000 + 1,000 − 2 = 1,998."}, {"id": "mas3_31", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "50,000 − 28,374 = ?", "o": ["21,626", "21,726", "22,626", "22,726"], "a": "21,626", "e": "50,000 − 28,374 = 21,626. Use column subtraction with repeated borrowing."}, {"id": "mas3_32", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What number is 500 more than 9,750?", "o": ["9,800", "10,050", "10,250", "10,750"], "a": "10,250", "e": "9,750 + 500 = 10,250."}, {"id": "mas3_33", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "6,841 + 2,159 = ?", "o": ["8,000", "8,900", "9,000", "9,100"], "a": "9,000", "e": "6,841 + 2,159 = 9,000. The digits sum to round thousands."}, {"id": "mas3_34", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "Three children save £4.25, £3.80 and £5.45. How much altogether?", "o": ["£12.50", "£13.40", "£13.50", "£14.50"], "a": "£13.50", "e": "4.25 + 3.80 = 8.05; 8.05 + 5.45 = 13.50."}, {"id": "mas3_35", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is 10,000 − 1?", "o": ["9,009", "9,090", "9,900", "9,999"], "a": "9,999", "e": "10,000 − 1 = 9,999."}, {"id": "mas3_36", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A school has 1,042 pupils. 389 are absent. How many are present?", "o": ["553", "643", "653", "663"], "a": "653", "e": "1,042 − 389 = 653."}, {"id": "mas3_37", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "8 + 14 + 22 + 6 = ?", "o": ["40", "48", "50", "52"], "a": "50", "e": "8+22=30, 14+6=20, 30+20=50. Group pairs that make round numbers."}, {"id": "mas3_38", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "What is the sum of 4,999 and 3,001?", "o": ["7,000", "7,999", "8,000", "8,001"], "a": "8,000", "e": "4,999 + 3,001 = 8,000."}, {"id": "mas3_39", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "A jug holds 2,500 ml. 875 ml is poured out. How much remains?", "o": ["1,525ml", "1,625ml", "1,725ml", "1,825ml"], "a": "1,625ml", "e": "2,500 − 875 = 1,625 ml."}, {"id": "mas3_40", "s": "maths", "t": "Addition & Subtraction", "l": 3, "q": "99 + 199 + 301 = ?", "o": ["589", "598", "599", "609"], "a": "599", "e": "99+199=298; 298+301=599."}, {"id": "mdc3_21", "s": "maths", "t": "Decimals", "l": 3, "q": "Which list is in order from smallest to largest?", "o": ["0.5, 0.45, 0.405", "0.405, 0.45, 0.5", "0.45, 0.405, 0.5", "0.5, 0.405, 0.45"], "a": "0.405, 0.45, 0.5", "e": "Compare tenths: 4, 4, 5. Then hundredths: 0 < 5. So 0.405 < 0.45 < 0.5."}, {"id": "mdc3_22", "s": "maths", "t": "Decimals", "l": 3, "q": "3.7 + 2.45 = ?", "o": ["5.52", "6.05", "6.15", "6.52"], "a": "6.15", "e": "Align decimal points: 3.70 + 2.45 = 6.15."}, {"id": "mdc3_23", "s": "maths", "t": "Decimals", "l": 3, "q": "8.0 − 3.65 = ?", "o": ["4.25", "4.35", "4.45", "5.35"], "a": "4.35", "e": "8.00 − 3.65 = 4.35. Use column subtraction."}, {"id": "mdc3_24", "s": "maths", "t": "Decimals", "l": 3, "q": "Round 6.38 to one decimal place.", "o": ["6.3", "6.4", "6.30", "7.0"], "a": "6.4", "e": "The second decimal digit is 8 (≥5), so round up: 6.4."}, {"id": "mdc3_25", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.6 × 10?", "o": ["0.006", "0.06", "6", "60"], "a": "6", "e": "Multiplying by 10 moves the digit one place left: 0.6 × 10 = 6."}, {"id": "mdc3_26", "s": "maths", "t": "Decimals", "l": 3, "q": "A ribbon is 4.5 m long. A piece of 1.75 m is cut off. How much remains?", "o": ["2.25m", "2.50m", "2.75m", "3.25m"], "a": "2.75m", "e": "4.50 − 1.75 = 2.75 m."}, {"id": "mdc3_27", "s": "maths", "t": "Decimals", "l": 3, "q": "Which decimal is equivalent to 3/4?", "o": ["0.34", "0.7", "0.75", "7.5"], "a": "0.75", "e": "3 ÷ 4 = 0.75."}, {"id": "mdc3_28", "s": "maths", "t": "Decimals", "l": 3, "q": "1.25 + 0.75 = ?", "o": ["1.75", "1.90", "2.0", "2.25"], "a": "2.0", "e": "1.25 + 0.75 = 2.00 = 2."}, {"id": "mdc3_29", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 0.04 × 100?", "o": ["0.4", "4", "40", "400"], "a": "4", "e": "Multiply by 100 moves digits two places left: 0.04 × 100 = 4."}, {"id": "mdc3_30", "s": "maths", "t": "Decimals", "l": 3, "q": "Round 12.475 to one decimal place.", "o": ["12.4", "12.5", "12.47", "12.48"], "a": "12.5", "e": "Look at second decimal: 7 (≥5), round up: 12.5."}, {"id": "mdc3_31", "s": "maths", "t": "Decimals", "l": 3, "q": "5.6 − 2.9 = ?", "o": ["2.3", "2.7", "3.3", "3.7"], "a": "2.7", "e": "5.6 − 2.9 = 2.7. Think: 5.6 − 3.0 = 2.6, +0.1 = 2.7."}, {"id": "mdc3_32", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 3.2 ÷ 10?", "o": ["0.032", "0.32", "32", "320"], "a": "0.32", "e": "Dividing by 10 moves digits one place right: 3.2 ÷ 10 = 0.32."}, {"id": "mdc3_33", "s": "maths", "t": "Decimals", "l": 3, "q": "A bottle of juice costs £1.35. How much for 4 bottles?", "o": ["£4.20", "£5.20", "£5.40", "£5.60"], "a": "£5.40", "e": "1.35 × 4: 1×4=4, 0.35×4=1.40; 4+1.40=5.40."}, {"id": "mdc3_34", "s": "maths", "t": "Decimals", "l": 3, "q": "Which decimal is equivalent to 1/5?", "o": ["0.12", "0.15", "0.2", "0.5"], "a": "0.2", "e": "1 ÷ 5 = 0.2."}, {"id": "mdc3_35", "s": "maths", "t": "Decimals", "l": 3, "q": "0.8 + 0.08 = ?", "o": ["0.16", "0.88", "0.9", "1.6"], "a": "0.88", "e": "0.80 + 0.08 = 0.88. Different place values — do not add to get 0.16!"}, {"id": "mdc3_36", "s": "maths", "t": "Decimals", "l": 3, "q": "A plank is 2.4 m. Three equal pieces are cut. How long is each?", "o": ["0.6m", "0.7m", "0.8m", "0.9m"], "a": "0.8m", "e": "2.4 ÷ 3 = 0.8 m."}, {"id": "mdc3_37", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 4.56 rounded to the nearest whole number?", "o": ["4", "4.5", "5", "5.6"], "a": "5", "e": "Tenths digit is 5 (≥5), so round up: 5."}, {"id": "mdc3_38", "s": "maths", "t": "Decimals", "l": 3, "q": "0.25 × 4 = ?", "o": ["0.8", "0.1", "1.0", "2.5"], "a": "1.0", "e": "0.25 is a quarter. 4 quarters = 1."}, {"id": "mdc3_39", "s": "maths", "t": "Decimals", "l": 3, "q": "What is 7.3 + 0.07?", "o": ["7.37", "7.4", "7.307", "14.0"], "a": "7.37", "e": "7.30 + 0.07 = 7.37. Align decimal points carefully."}, {"id": "mdc3_40", "s": "maths", "t": "Decimals", "l": 3, "q": "A bag of apples weighs 1.8 kg. A bag of oranges weighs 1.45 kg. What is the total weight?", "o": ["3.05kg", "3.15kg", "3.25kg", "3.35kg"], "a": "3.25kg", "e": "1.80 + 1.45 = 3.25 kg."}, {"id": "mpc3_21", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 25% of 80?", "o": ["15", "20", "25", "40"], "a": "20", "e": "25% = ¼. 80 ÷ 4 = 20."}, {"id": "mpc3_22", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 10% of 350?", "o": ["3.5", "35", "40", "350"], "a": "35", "e": "10% means divide by 10: 350 ÷ 10 = 35."}, {"id": "mpc3_23", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage is 30 out of 50?", "o": ["30%", "50%", "60%", "75%"], "a": "60%", "e": "30 ÷ 50 = 0.6 = 60%."}, {"id": "mpc3_24", "s": "maths", "t": "Percentages", "l": 3, "q": "A jacket costs £60. It is reduced by 20%. What is the sale price?", "o": ["£12", "£40", "£48", "£50"], "a": "£48", "e": "20% of 60 = 12. 60 − 12 = £48."}, {"id": "mpc3_25", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 75% of 200?", "o": ["50", "100", "150", "175"], "a": "150", "e": "75% = ¾. 200 ÷ 4 = 50; 50 × 3 = 150."}, {"id": "mpc3_26", "s": "maths", "t": "Percentages", "l": 3, "q": "15 out of 20 students passed a test. What percentage passed?", "o": ["15%", "60%", "75%", "80%"], "a": "75%", "e": "15 ÷ 20 = 0.75 = 75%."}, {"id": "mpc3_27", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 5% of 120?", "o": ["5", "6", "10", "12"], "a": "6", "e": "5% = half of 10%. 10% of 120 = 12; 12 ÷ 2 = 6."}, {"id": "mpc3_28", "s": "maths", "t": "Percentages", "l": 3, "q": "A shop offers 30% off a £50 toy. How much do you save?", "o": ["£5", "£10", "£15", "£20"], "a": "£15", "e": "30% of 50: 10% = 5, ×3 = 15. You save £15."}, {"id": "mpc3_29", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage is 45 out of 60?", "o": ["45%", "60%", "70%", "75%"], "a": "75%", "e": "45 ÷ 60 = 0.75 = 75%."}, {"id": "mpc3_30", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 1% of 700?", "o": ["0.7", "7", "70", "700"], "a": "7", "e": "1% means divide by 100: 700 ÷ 100 = 7."}, {"id": "mpc3_31", "s": "maths", "t": "Percentages", "l": 3, "q": "A team wins 12 out of 15 matches. What percentage do they win?", "o": ["75%", "80%", "83%", "85%"], "a": "80%", "e": "12 ÷ 15 = 0.8 = 80%."}, {"id": "mpc3_32", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 50% of 3.60?", "o": ["£1.08", "£1.80", "£2.50", "£3.00"], "a": "£1.80", "e": "50% = half. £3.60 ÷ 2 = £1.80."}, {"id": "mpc3_33", "s": "maths", "t": "Percentages", "l": 3, "q": "Increase 80 by 25%.", "o": ["95", "100", "105", "110"], "a": "100", "e": "25% of 80 = 20. 80 + 20 = 100."}, {"id": "mpc3_34", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 40% of 90?", "o": ["30", "32", "36", "40"], "a": "36", "e": "10% of 90 = 9. 40% = 9 × 4 = 36."}, {"id": "mpc3_35", "s": "maths", "t": "Percentages", "l": 3, "q": "A price rises from £40 to £50. What is the percentage increase?", "o": ["10%", "20%", "25%", "30%"], "a": "25%", "e": "Increase = £10. 10 ÷ 40 = 0.25 = 25%."}, {"id": "mpc3_36", "s": "maths", "t": "Percentages", "l": 3, "q": "What is 35% of 200?", "o": ["50", "60", "70", "80"], "a": "70", "e": "10% of 200 = 20. 35% = 20×3 + 20÷2 = 60 + 10 = 70."}, {"id": "mpc3_37", "s": "maths", "t": "Percentages", "l": 3, "q": "A bag of nuts weighs 500 g. 60% are cashews. How many grams are cashews?", "o": ["250g", "270g", "300g", "330g"], "a": "300g", "e": "60% of 500: 10% = 50, ×6 = 300 g."}, {"id": "mpc3_38", "s": "maths", "t": "Percentages", "l": 3, "q": "What percentage is 8 out of 32?", "o": ["20%", "25%", "30%", "40%"], "a": "25%", "e": "8 ÷ 32 = 0.25 = 25%."}, {"id": "mpc3_39", "s": "maths", "t": "Percentages", "l": 3, "q": "Decrease 150 by 20%.", "o": ["100", "110", "120", "130"], "a": "120", "e": "20% of 150 = 30. 150 − 30 = 120."}, {"id": "mpc3_40", "s": "maths", "t": "Percentages", "l": 3, "q": "Which is greater: 30% of 80 or 40% of 60?", "o": ["30% of 80", "40% of 60", "They are equal", "Cannot tell"], "a": "They are equal", "e": "30% of 80 = 24. 40% of 60 = 24. They are exactly equal!"}, {"id": "mgs3_21", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many lines of symmetry does a regular hexagon have?", "o": ["2", "4", "6", "8"], "a": "6", "e": "A regular hexagon has 6 lines of symmetry — one through each pair of opposite vertices and one through each pair of opposite edges."}, {"id": "mgs3_22", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a 3D shape with one circular face and one curved surface coming to a point?", "o": ["Cylinder", "Cone", "Sphere", "Pyramid"], "a": "Cone", "e": "A cone has a circular base and a curved surface rising to a point (apex)."}, {"id": "mgs3_23", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A rectangle has length 8 cm and width 3 cm. What is its area?", "o": ["11 cm²", "22 cm²", "24 cm²", "32 cm²"], "a": "24 cm²", "e": "Area of rectangle = length × width = 8 × 3 = 24 cm²."}, {"id": "mgs3_24", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many faces does a triangular prism have?", "o": ["3", "4", "5", "6"], "a": "5", "e": "A triangular prism has 2 triangular faces and 3 rectangular faces = 5 faces total."}, {"id": "mgs3_25", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "Which quadrilateral has exactly one pair of parallel sides?", "o": ["Parallelogram", "Rectangle", "Rhombus", "Trapezium"], "a": "Trapezium", "e": "A trapezium has exactly one pair of parallel sides. A parallelogram has two pairs."}, {"id": "mgs3_26", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What are the coordinates of a point 3 right and 4 up from the origin?", "o": ["(4,3)", "(3,4)", "(−3,4)", "(3,−4)"], "a": "(3,4)", "e": "Coordinates are (x,y). 3 right = x=3, 4 up = y=4. So (3,4)."}, {"id": "mgs3_27", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many vertices does a cube have?", "o": ["4", "6", "8", "12"], "a": "8", "e": "A cube has 8 corners (vertices). 4 on the top face, 4 on the bottom."}, {"id": "mgs3_28", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a polygon with 8 sides?", "o": ["Hexagon", "Heptagon", "Octagon", "Nonagon"], "a": "Octagon", "e": "Octo = 8. A stop sign is an octagon."}, {"id": "mgs3_29", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A square has sides of 7 cm. What is its perimeter?", "o": ["14 cm", "21 cm", "28 cm", "49 cm"], "a": "28 cm", "e": "Perimeter of square = 4 × side = 4 × 7 = 28 cm."}, {"id": "mgs3_30", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "Which of these shapes has no line of symmetry?", "o": ["Isosceles triangle", "Scalene triangle", "Equilateral triangle", "Square"], "a": "Scalene triangle", "e": "A scalene triangle has all different sides and angles — no lines of symmetry."}, {"id": "mgs3_31", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the sum of angles in any triangle?", "o": ["90°", "180°", "270°", "360°"], "a": "180°", "e": "The three angles of any triangle always add up to 180°."}, {"id": "mgs3_32", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many edges does a cuboid have?", "o": ["6", "8", "12", "16"], "a": "12", "e": "A cuboid has 12 edges: 4 on top, 4 on bottom, 4 vertical."}, {"id": "mgs3_33", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A shape has 4 equal sides and 4 right angles. What is it?", "o": ["Rectangle", "Rhombus", "Square", "Trapezium"], "a": "Square", "e": "4 equal sides AND 4 right angles = square. A rhombus has equal sides but not necessarily right angles."}, {"id": "mgs3_34", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a 3D shape with two identical circular faces connected by a curved surface?", "o": ["Cone", "Cylinder", "Prism", "Sphere"], "a": "Cylinder", "e": "A cylinder has two circular faces (top and bottom) joined by a curved surface."}, {"id": "mgs3_35", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "Point A is at (2,3). It is reflected in the y-axis. Where does it move to?", "o": ["(−2,3)", "(2,−3)", "(3,2)", "(−2,−3)"], "a": "(−2,3)", "e": "Reflecting in the y-axis flips the x-coordinate: (2,3) → (−2,3)."}, {"id": "mgs3_36", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many lines of symmetry does a regular pentagon have?", "o": ["3", "4", "5", "6"], "a": "5", "e": "A regular pentagon has 5 lines of symmetry — one through each vertex to the opposite midpoint."}, {"id": "mgs3_37", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "A parallelogram has opposite sides equal and parallel. How many lines of symmetry does it have?", "o": ["0", "1", "2", "4"], "a": "0", "e": "A parallelogram (without right angles) has no lines of symmetry — it only has rotational symmetry."}, {"id": "mgs3_38", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What type of angle is 135°?", "o": ["Acute", "Obtuse", "Reflex", "Right"], "a": "Obtuse", "e": "Obtuse angles are between 90° and 180°. 135° is obtuse."}, {"id": "mgs3_39", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "How many faces does a square-based pyramid have?", "o": ["4", "5", "6", "8"], "a": "5", "e": "1 square base + 4 triangular faces = 5 faces."}, {"id": "mgs3_40", "s": "maths", "t": "Geometry – Shapes", "l": 3, "q": "What is the name of a quadrilateral with two pairs of adjacent sides equal but no right angles?", "o": ["Parallelogram", "Rectangle", "Kite", "Rhombus"], "a": "Kite", "e": "A kite has two pairs of adjacent (next-to-each-other) equal sides."}, {"id": "mang3_21", "s": "maths", "t": "Angles", "l": 3, "q": "Angles on a straight line add up to how many degrees?", "o": ["90°", "180°", "270°", "360°"], "a": "180°", "e": "A straight line = 180°. Any angles sitting on it must add up to 180°."}, {"id": "mang3_22", "s": "maths", "t": "Angles", "l": 3, "q": "What is the missing angle on a straight line if the other angle is 65°?", "o": ["25°", "105°", "115°", "125°"], "a": "115°", "e": "180° − 65° = 115°."}, {"id": "mang3_23", "s": "maths", "t": "Angles", "l": 3, "q": "Angles around a point add up to how many degrees?", "o": ["90°", "180°", "270°", "360°"], "a": "360°", "e": "A full turn is 360°. All angles around a point add to 360°."}, {"id": "mang3_24", "s": "maths", "t": "Angles", "l": 3, "q": "A triangle has angles of 47° and 63°. What is the third angle?", "o": ["60°", "70°", "80°", "90°"], "a": "70°", "e": "47 + 63 = 110. 180 − 110 = 70°."}, {"id": "mang3_25", "s": "maths", "t": "Angles", "l": 3, "q": "What type of angle is less than 90°?", "o": ["Acute", "Obtuse", "Reflex", "Right"], "a": "Acute", "e": "Acute angles are less than 90°."}, {"id": "mang3_26", "s": "maths", "t": "Angles", "l": 3, "q": "What is the size of each angle in an equilateral triangle?", "o": ["45°", "60°", "72°", "90°"], "a": "60°", "e": "An equilateral triangle has equal angles. 180° ÷ 3 = 60°."}, {"id": "mang3_27", "s": "maths", "t": "Angles", "l": 3, "q": "Two angles are vertically opposite. One is 48°. What is the other?", "o": ["42°", "48°", "132°", "312°"], "a": "48°", "e": "Vertically opposite angles are always equal."}, {"id": "mang3_28", "s": "maths", "t": "Angles", "l": 3, "q": "What is a reflex angle?", "o": ["Exactly 90°", "Between 90° and 180°", "Exactly 180°", "Between 180° and 360°"], "a": "Between 180° and 360°", "e": "A reflex angle is greater than 180° but less than 360°."}, {"id": "mang3_29", "s": "maths", "t": "Angles", "l": 3, "q": "The angles in a quadrilateral add up to how many degrees?", "o": ["180°", "270°", "360°", "540°"], "a": "360°", "e": "A quadrilateral can be split into 2 triangles: 2 × 180° = 360°."}, {"id": "mang3_30", "s": "maths", "t": "Angles", "l": 3, "q": "An angle is 230°. What type of angle is it?", "o": ["Acute", "Obtuse", "Reflex", "Right"], "a": "Reflex", "e": "230° is between 180° and 360°, so it is reflex."}, {"id": "mang3_31", "s": "maths", "t": "Angles", "l": 3, "q": "What is the missing angle if three angles around a point are 120°, 95° and x?", "o": ["125°", "135°", "145°", "155°"], "a": "145°", "e": "120 + 95 = 215. 360 − 215 = 145°."}, {"id": "mang3_32", "s": "maths", "t": "Angles", "l": 3, "q": "What is the complement of 34°?", "o": ["46°", "56°", "126°", "146°"], "a": "56°", "e": "Complementary angles add to 90°. 90 − 34 = 56°."}, {"id": "mang3_33", "s": "maths", "t": "Angles", "l": 3, "q": "What is the supplement of 112°?", "o": ["58°", "68°", "78°", "88°"], "a": "68°", "e": "Supplementary angles add to 180°. 180 − 112 = 68°."}, {"id": "mang3_34", "s": "maths", "t": "Angles", "l": 3, "q": "A right angle is divided into two equal parts. What is each part?", "o": ["30°", "45°", "60°", "90°"], "a": "45°", "e": "90° ÷ 2 = 45°."}, {"id": "mang3_35", "s": "maths", "t": "Angles", "l": 3, "q": "In an isosceles triangle, one angle is 100°. What are the other two angles?", "o": ["20° and 60°", "40° and 40°", "50° and 30°", "80° and 0°"], "a": "40° and 40°", "e": "The other two angles are equal (isosceles). 180 − 100 = 80. 80 ÷ 2 = 40°."}, {"id": "mang3_36", "s": "maths", "t": "Angles", "l": 3, "q": "Two straight lines cross. One angle formed is 72°. What is the angle directly opposite?", "o": ["18°", "72°", "108°", "288°"], "a": "72°", "e": "Vertically opposite angles are equal: 72°."}, {"id": "mang3_37", "s": "maths", "t": "Angles", "l": 3, "q": "How many degrees does the minute hand of a clock turn in 15 minutes?", "o": ["45°", "60°", "90°", "120°"], "a": "90°", "e": "A full turn (60 min) = 360°. 15 min = 360° ÷ 4 = 90°."}, {"id": "mang3_38", "s": "maths", "t": "Angles", "l": 3, "q": "A straight line has angles of 3x° and 2x° on it. What is x?", "o": ["18", "20", "30", "36"], "a": "36", "e": "3x + 2x = 180. 5x = 180. x = 36."}, {"id": "mang3_39", "s": "maths", "t": "Angles", "l": 3, "q": "What is the size of each interior angle in a regular quadrilateral (square)?", "o": ["60°", "72°", "90°", "120°"], "a": "90°", "e": "A square has 4 right angles: 360° ÷ 4 = 90°."}, {"id": "mang3_40", "s": "maths", "t": "Angles", "l": 3, "q": "How many degrees does a three-quarter turn equal?", "o": ["90°", "180°", "270°", "360°"], "a": "270°", "e": "Full turn = 360°. Three-quarters of 360 = 270°."}, {"id": "mmu3_21", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many centimetres are in 2.5 metres?", "o": ["25", "200", "250", "2500"], "a": "250", "e": "1 m = 100 cm. 2.5 m = 2.5 × 100 = 250 cm."}, {"id": "mmu3_22", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A film lasts 1 hour 45 minutes. It starts at 14:20. When does it end?", "o": ["15:55", "16:00", "16:05", "16:15"], "a": "16:05", "e": "14:20 + 1 hr = 15:20. 15:20 + 45 min = 16:05."}, {"id": "mmu3_23", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many grams are in 3.2 kg?", "o": ["320", "3,020", "3,200", "32,000"], "a": "3,200", "e": "1 kg = 1,000 g. 3.2 × 1,000 = 3,200 g."}, {"id": "mmu3_24", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Convert 4,500 ml to litres.", "o": ["0.45 l", "4.5 l", "45 l", "450 l"], "a": "4.5 l", "e": "1 l = 1,000 ml. 4,500 ÷ 1,000 = 4.5 l."}, {"id": "mmu3_25", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "What is 3 hours 20 minutes in minutes?", "o": ["180", "200", "220", "320"], "a": "200", "e": "3 hours = 180 min. 180 + 20 = 200 min."}, {"id": "mmu3_26", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A recipe needs 750 g of flour. You have 0.5 kg. How much more do you need?", "o": ["200g", "250g", "350g", "500g"], "a": "250g", "e": "0.5 kg = 500 g. 750 − 500 = 250 g."}, {"id": "mmu3_27", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many mm are in 5.6 cm?", "o": ["0.056", "0.56", "5.6", "56"], "a": "56", "e": "1 cm = 10 mm. 5.6 × 10 = 56 mm."}, {"id": "mmu3_28", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A train departs at 09:47 and arrives at 11:15. How long is the journey?", "o": ["1h 22min", "1h 28min", "1h 32min", "2h 28min"], "a": "1h 28min", "e": "09:47 to 10:47 = 1 hr. 10:47 to 11:15 = 28 min. Total: 1h 28 min."}, {"id": "mmu3_29", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many seconds are in 5 minutes?", "o": ["50", "250", "300", "500"], "a": "300", "e": "1 min = 60 s. 5 × 60 = 300 s."}, {"id": "mmu3_30", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "Convert 8.4 km to metres.", "o": ["84", "840", "8,400", "84,000"], "a": "8,400", "e": "1 km = 1,000 m. 8.4 × 1,000 = 8,400 m."}, {"id": "mmu3_31", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A lorry carries 3 tonnes of gravel. How many kg is that?", "o": ["300", "3,000", "30,000", "300,000"], "a": "3,000", "e": "1 tonne = 1,000 kg. 3 × 1,000 = 3,000 kg."}, {"id": "mmu3_32", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "What time is 3 hours after 22:30?", "o": ["00:30", "01:00", "01:30", "02:30"], "a": "01:30", "e": "22:30 + 3 hrs = 25:30 = 01:30 (next day)."}, {"id": "mmu3_33", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many ml in 2.75 litres?", "o": ["275", "2,075", "2,750", "27,500"], "a": "2,750", "e": "1 l = 1,000 ml. 2.75 × 1,000 = 2,750 ml."}, {"id": "mmu3_34", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A bag weighs 1.35 kg. A second bag weighs 875 g. What is the total weight in grams?", "o": ["1,225g", "2,125g", "2,225g", "2,350g"], "a": "2,225g", "e": "1.35 kg = 1,350 g. 1,350 + 875 = 2,225 g."}, {"id": "mmu3_35", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "What is 135 minutes in hours and minutes?", "o": ["1h 25min", "2h 15min", "2h 25min", "3h 15min"], "a": "2h 15min", "e": "135 ÷ 60 = 2 remainder 15. So 2 hours 15 minutes."}, {"id": "mmu3_36", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A plank of wood is 2 m 35 cm. What is this in cm?", "o": ["235 cm", "225 cm", "305 cm", "2,035 cm"], "a": "235 cm", "e": "2 m = 200 cm. 200 + 35 = 235 cm."}, {"id": "mmu3_37", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "1 inch ≈ 2.5 cm. Approximately how many cm is 6 inches?", "o": ["12 cm", "15 cm", "18 cm", "20 cm"], "a": "15 cm", "e": "6 × 2.5 = 15 cm."}, {"id": "mmu3_38", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A car journey is 240 km. How long does it take at 80 km/h?", "o": ["1h", "2h", "3h", "4h"], "a": "3h", "e": "240 ÷ 80 = 3 hours."}, {"id": "mmu3_39", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "How many days are in 3 weeks and 4 days?", "o": ["21", "22", "24", "25"], "a": "25", "e": "3 weeks = 21 days. 21 + 4 = 25 days."}, {"id": "mmu3_40", "s": "maths", "t": "Measurement & Units", "l": 3, "q": "A pool holds 25,000 litres. A pump removes 1,200 litres per hour. How much is left after 5 hours?", "o": ["18,000l", "19,000l", "19,800l", "20,000l"], "a": "19,000l", "e": "1,200 × 5 = 6,000 l removed. 25,000 − 6,000 = 19,000 l."}, {"id": "mpa3_21", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Find the area of a triangle with base 10 cm and height 6 cm.", "o": ["30 cm²", "60 cm²", "16 cm²", "26 cm²"], "a": "30 cm²", "e": "Area of triangle = ½ × base × height = ½ × 10 × 6 = 30 cm²."}, {"id": "mpa3_22", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle has perimeter 26 cm and length 8 cm. What is its width?", "o": ["3 cm", "5 cm", "10 cm", "18 cm"], "a": "5 cm", "e": "Perimeter = 2(l+w). 26 = 2(8+w). 13 = 8+w. w = 5 cm."}, {"id": "mpa3_23", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the area of a square with side 9 cm?", "o": ["18 cm²", "36 cm²", "72 cm²", "81 cm²"], "a": "81 cm²", "e": "Area = side² = 9 × 9 = 81 cm²."}, {"id": "mpa3_24", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A path around a rectangular garden is 40 m. The garden is 12 m long. How wide is it?", "o": ["8 m", "10 m", "16 m", "20 m"], "a": "8 m", "e": "Perimeter = 2(l+w). 40 = 2(12+w). 20 = 12+w. w = 8 m."}, {"id": "mpa3_25", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A shape is made of two rectangles: one 6×4 cm and one 3×2 cm joined together. What is the total area?", "o": ["24 cm²", "30 cm²", "36 cm²", "60 cm²"], "a": "30 cm²", "e": "6×4=24, 3×2=6. Total: 24+6=30 cm²."}, {"id": "mpa3_26", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the perimeter of a regular pentagon with sides of 7 cm?", "o": ["28 cm", "35 cm", "42 cm", "49 cm"], "a": "35 cm", "e": "5 sides × 7 cm = 35 cm."}, {"id": "mpa3_27", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A triangle has base 8 cm and height 9 cm. What is its area?", "o": ["17 cm²", "36 cm²", "40 cm²", "72 cm²"], "a": "36 cm²", "e": "½ × 8 × 9 = 36 cm²."}, {"id": "mpa3_28", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A room is 5 m × 4 m. Carpet costs £12 per m². How much to carpet the room?", "o": ["£192", "£216", "£240", "£360"], "a": "£240", "e": "Area = 5 × 4 = 20 m². 20 × £12 = £240."}, {"id": "mpa3_29", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the area of a right-angled triangle with legs 6 cm and 8 cm?", "o": ["24 cm²", "48 cm²", "14 cm²", "28 cm²"], "a": "24 cm²", "e": "½ × 6 × 8 = 24 cm²."}, {"id": "mpa3_30", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A square field has area 144 m². What is the length of one side?", "o": ["9 m", "12 m", "14 m", "16 m"], "a": "12 m", "e": "Side = √144 = 12 m."}, {"id": "mpa3_31", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "Find the perimeter of a rectangle 12 cm long and 5 cm wide.", "o": ["17 cm", "34 cm", "60 cm", "120 cm"], "a": "34 cm", "e": "Perimeter = 2(12+5) = 2×17 = 34 cm."}, {"id": "mpa3_32", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A compound shape is an 8×5 rectangle with a 2×2 square cut from one corner. What is the area?", "o": ["36 cm²", "38 cm²", "40 cm²", "44 cm²"], "a": "36 cm²", "e": "8×5=40. Remove 2×2=4. 40−4=36 cm²."}, {"id": "mpa3_33", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "How many 1 cm² tiles are needed to cover a 6 cm × 7 cm surface?", "o": ["13", "36", "42", "48"], "a": "42", "e": "Area = 6 × 7 = 42 cm². One tile per cm²."}, {"id": "mpa3_34", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A triangle has area 40 cm² and base 10 cm. What is its height?", "o": ["4 cm", "6 cm", "8 cm", "10 cm"], "a": "8 cm", "e": "Area = ½ × base × h. 40 = ½ × 10 × h. 40 = 5h. h = 8 cm."}, {"id": "mpa3_35", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the perimeter of an equilateral triangle with sides of 11 cm?", "o": ["22 cm", "33 cm", "44 cm", "121 cm"], "a": "33 cm", "e": "3 × 11 = 33 cm."}, {"id": "mpa3_36", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangular lawn is 15 m × 8 m. Fertiliser covers 10 m² per bag. How many bags are needed?", "o": ["10", "12", "15", "20"], "a": "12", "e": "Area = 15 × 8 = 120 m². 120 ÷ 10 = 12 bags."}, {"id": "mpa3_37", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "What is the area of a parallelogram with base 9 cm and perpendicular height 4 cm?", "o": ["13 cm²", "18 cm²", "36 cm²", "72 cm²"], "a": "36 cm²", "e": "Area of parallelogram = base × perpendicular height = 9 × 4 = 36 cm²."}, {"id": "mpa3_38", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle has area 72 cm² and width 8 cm. What is its length?", "o": ["7 cm", "8 cm", "9 cm", "10 cm"], "a": "9 cm", "e": "Length = Area ÷ Width = 72 ÷ 8 = 9 cm."}, {"id": "mpa3_39", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A rectangle is 10 cm long and 6 cm wide. A square of side 3 cm is added to one end. What is the total area?", "o": ["60 cm²", "63 cm²", "69 cm²", "79 cm²"], "a": "69 cm²", "e": "Rectangle: 10×6=60 cm². Square: 3×3=9 cm². Total: 60+9=69 cm²."}, {"id": "mpa3_40", "s": "maths", "t": "Perimeter & Area", "l": 3, "q": "A square has the same area as a rectangle of 16 cm × 4 cm. What is the side of the square?", "o": ["4 cm", "6 cm", "8 cm", "10 cm"], "a": "8 cm", "e": "Area of rectangle = 64 cm². Side of square = √64 = 8 cm."}, {"id": "mds3_21", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the mean of: 4, 7, 9, 6, 4.", "o": ["4", "5", "6", "7"], "a": "6", "e": "Sum = 4+7+9+6+4=30. Mean = 30÷5=6."}, {"id": "mds3_22", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the median of: 3, 7, 2, 9, 5.", "o": ["5", "6", "7", "9"], "a": "5", "e": "Order: 2,3,5,7,9. Middle value (3rd of 5) = 5."}, {"id": "mds3_23", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the mode of: 4, 7, 4, 9, 4, 7, 2.", "o": ["2", "4", "7", "9"], "a": "4", "e": "4 appears 3 times — more than any other number."}, {"id": "mds3_24", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the range of: 12, 5, 9, 3, 17?", "o": ["9", "12", "14", "17"], "a": "14", "e": "Range = highest − lowest = 17 − 3 = 14."}, {"id": "mds3_25", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A bar chart shows 15 cats, 22 dogs, 8 rabbits. How many pets altogether?", "o": ["37", "40", "43", "45"], "a": "45", "e": "15 + 22 + 8 = 45."}, {"id": "mds3_26", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "The mean of 5 numbers is 8. What is their total?", "o": ["8", "13", "40", "45"], "a": "40", "e": "Mean = total ÷ count. Total = mean × count = 8 × 5 = 40."}, {"id": "mds3_27", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the median of: 11, 4, 8, 15, 7, 3, 10.", "o": ["7", "8", "10", "11"], "a": "8", "e": "Order: 3,4,7,8,10,11,15. Middle (4th of 7) = 8."}, {"id": "mds3_28", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A pictogram uses 🍎 = 4 apples. There are 6 symbols. How many apples?", "o": ["10", "18", "24", "30"], "a": "24", "e": "6 × 4 = 24 apples."}, {"id": "mds3_29", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Which average is most affected by an extremely large value?", "o": ["Mean", "Median", "Mode", "Range"], "a": "Mean", "e": "The mean uses every value in its calculation, so a very large value pulls it up significantly."}, {"id": "mds3_30", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What is the range of: −3, 5, −1, 8, 0?", "o": ["8", "9", "11", "13"], "a": "11", "e": "Range = 8 − (−3) = 8 + 3 = 11."}, {"id": "mds3_31", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A line graph shows sales: Mon 30, Tue 45, Wed 25, Thu 50, Fri 40. Which day had the highest sales?", "o": ["Monday", "Tuesday", "Thursday", "Friday"], "a": "Thursday", "e": "50 is the highest value, on Thursday."}, {"id": "mds3_32", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Five friends score 6, 8, 7, 9, 5 in a test. What is their mean score?", "o": ["6", "7", "8", "9"], "a": "7", "e": "Sum = 6+8+7+9+5=35. Mean = 35÷5=7."}, {"id": "mds3_33", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the mode of: red, blue, red, green, blue, red.", "o": ["blue", "green", "red", "no mode"], "a": "red", "e": "Red appears 3 times — the most frequent."}, {"id": "mds3_34", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A tally chart shows: ✓✓✓✓ ✓✓✓ for cats, ✓✓✓✓ ✓✓✓✓ ✓ for dogs. How many more dogs than cats?", "o": ["2", "4", "6", "8"], "a": "2", "e": "Cats = 7, Dogs = 9. Difference = 9 − 7 = 2."}, {"id": "mds3_35", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "The mean of 3, 5, 7, x is 6. What is x?", "o": ["6", "7", "8", "9"], "a": "9", "e": "Mean=6, so total = 6×4=24. 3+5+7+x=24. 15+x=24. x=9."}, {"id": "mds3_36", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Which type of chart is best for showing how a total is split into parts?", "o": ["Bar chart", "Line graph", "Pie chart", "Tally chart"], "a": "Pie chart", "e": "A pie chart shows proportions of a whole — ideal for showing how a total is divided."}, {"id": "mds3_37", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "Find the median of these even set of numbers: 3, 5, 7, 9.", "o": ["5", "6", "7", "8"], "a": "6", "e": "With an even set, median = mean of two middle values. (5+7)÷2=6."}, {"id": "mds3_38", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A frequency table shows: 1 star:2, 2 stars:5, 3 stars:8, 4 stars:3, 5 stars:2. What is the modal rating?", "o": ["2 stars", "3 stars", "4 stars", "5 stars"], "a": "3 stars", "e": "3 stars has frequency 8 — the highest. This is the mode."}, {"id": "mds3_39", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "What does the range tell you about a data set?", "o": ["The most common value", "The middle value", "The average value", "The spread of values"], "a": "The spread of values", "e": "Range = highest − lowest. It tells you how spread out the data is."}, {"id": "mds3_40", "s": "maths", "t": "Data & Statistics", "l": 3, "q": "A class of 30 students each read a book. The mean number of pages read is 120. How many pages were read in total?", "o": ["120", "1,200", "3,600", "36,000"], "a": "3,600", "e": "Total = mean × number of students = 120 × 30 = 3,600."}, {"id": "mps3_21", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A number is multiplied by 6 and then 15 is subtracted. The result is 57. What is the number?", "o": ["9", "10", "12", "13"], "a": "12", "e": "Reverse: 57+15=72. 72÷6=12."}, {"id": "mps3_22", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A bag has red and blue balls. There are 3 times as many red as blue. There are 24 red. How many blue?", "o": ["6", "7", "8", "9"], "a": "8", "e": "24 ÷ 3 = 8 blue balls."}, {"id": "mps3_23", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Two numbers add up to 50. One is 14 more than the other. What are the two numbers?", "o": ["16 and 34", "18 and 32", "17 and 33", "22 and 28"], "a": "18 and 32", "e": "Let smaller = x. x + (x+14) = 50. 2x+14=50. 2x=36. x=18. Numbers: 18 and 32."}, {"id": "mps3_24", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A cinema has 240 seats arranged in 12 equal rows. How many seats in each row?", "o": ["18", "20", "22", "24"], "a": "20", "e": "240 ÷ 12 = 20 seats per row."}, {"id": "mps3_25", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Apples cost 35p each. I buy 8 and pay with £3. How much change do I get?", "o": ["10p", "20p", "30p", "40p"], "a": "20p", "e": "8 × 35p = 280p = £2.80. £3.00 − £2.80 = 20p."}, {"id": "mps3_26", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A square garden has perimeter 52 m. What is its area?", "o": ["104 m²", "144 m²", "169 m²", "208 m²"], "a": "169 m²", "e": "Side = 52÷4=13 m. Area = 13²=169 m²."}, {"id": "mps3_27", "s": "maths", "t": "Problem Solving", "l": 3, "q": "I think of a number, double it, add 7 and the result is 23. What is the number?", "o": ["6", "7", "8", "9"], "a": "8", "e": "Reverse: 23−7=16. 16÷2=8."}, {"id": "mps3_28", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A school trip costs £15 per pupil. 28 pupils go. What is the total cost?", "o": ["£370", "£390", "£410", "£420"], "a": "£420", "e": "28 × £15 = £420."}, {"id": "mps3_29", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Three consecutive numbers add up to 48. What are they?", "o": ["14, 15, 16", "15, 16, 17", "16, 17, 15", "13, 16, 19"], "a": "15, 16, 17", "e": "Let n, n+1, n+2: 3n+3=48, 3n=45, n=15. Numbers: 15, 16, 17."}, {"id": "mps3_30", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A train travels at 80 km/h. How far does it travel in 2½ hours?", "o": ["160 km", "180 km", "200 km", "240 km"], "a": "200 km", "e": "80 × 2.5 = 200 km."}, {"id": "mps3_31", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Stamps come in books of 12. A post office needs 150 stamps. How many books and how many stamps are left over?", "o": ["12 books, 6 left", "12 books, 3 left", "11 books, 3 left", "13 books, 0 left"], "a": "12 books, 6 left", "e": "150 ÷ 12 = 12 remainder 6. 12 full books, 6 extra stamps."}, {"id": "mps3_32", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A recipe for 4 people uses 300 g of rice. How much for 10 people?", "o": ["600 g", "700 g", "750 g", "800 g"], "a": "750 g", "e": "300÷4=75 g per person. 75×10=750 g."}, {"id": "mps3_33", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A shop has 360 bottles. They are packed in boxes of 8. How many full boxes?", "o": ["40", "42", "44", "45"], "a": "45", "e": "360 ÷ 8 = 45."}, {"id": "mps3_34", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Two buses leave the station at 08:00. Bus A runs every 15 min, Bus B every 20 min. When do they next leave together?", "o": ["08:45", "09:00", "09:15", "09:30"], "a": "09:00", "e": "LCM of 15 and 20 = 60 min. 08:00 + 60 min = 09:00."}, {"id": "mps3_35", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A rectangle is twice as long as it is wide. Its perimeter is 48 cm. What is its area?", "o": ["64 cm²", "96 cm²", "128 cm²", "192 cm²"], "a": "128 cm²", "e": "Let width=w, length=2w. 2(w+2w)=48. 6w=48. w=8. Length=16. Area=8×16=128 cm²."}, {"id": "mps3_36", "s": "maths", "t": "Problem Solving", "l": 3, "q": "In a class, ⅓ of pupils walk to school, ½ cycle and the rest come by car. If there are 30 pupils, how many come by car?", "o": ["3", "4", "5", "6"], "a": "5", "e": "Walk: 10, Cycle: 15. Car: 30−10−15=5."}, {"id": "mps3_37", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A number squared equals 144. What is the number?", "o": ["11", "12", "13", "14"], "a": "12", "e": "12 × 12 = 144."}, {"id": "mps3_38", "s": "maths", "t": "Problem Solving", "l": 3, "q": "Books cost £7.50 each. Pens cost £1.25 each. I buy 3 books and 4 pens. How much do I spend?", "o": ["£25.50", "£26.50", "£27.50", "£28.50"], "a": "£27.50", "e": "3×7.50=22.50. 4×1.25=5.00. Total=27.50."}, {"id": "mps3_39", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A water tank is ¾ full and contains 150 litres. 30 litres are added. How full is the tank now?", "o": ["4/5", "17/20", "9/10", "19/20"], "a": "9/10", "e": "Full capacity = 150÷(3/4) = 200 l. After: 180 l. 180/200 = 9/10."}, {"id": "mps3_40", "s": "maths", "t": "Problem Solving", "l": 3, "q": "A wall is 3 m high and 5 m wide. One tin of paint covers 6 m². How many tins are needed?", "o": ["2", "3", "4", "5"], "a": "3", "e": "Area = 3×5=15 m². 15÷6=2.5. Round up: 3 tins."}, {"id": "eg3_21", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence uses the correct form of the verb?", "o": ["We was going to the park", "We were going to the park", "We is going to the park", "We be going to the park"], "a": "We were going to the park", "e": "'We' takes 'were' in the past tense, not 'was'. 'Was' is used with I/he/she/it."}, {"id": "eg3_22", "s": "english", "t": "Grammar", "l": 3, "q": "What type of word is 'quickly' in: She ran quickly?", "o": ["Adjective", "Adverb", "Noun", "Verb"], "a": "Adverb", "e": "'Quickly' describes how she ran. Adverbs describe verbs (and adjectives and other adverbs)."}, {"id": "eg3_23", "s": "english", "t": "Grammar", "l": 3, "q": "Which is a proper noun?", "o": ["city", "river", "London", "mountain"], "a": "London", "e": "Proper nouns are specific names and always start with a capital letter."}, {"id": "eg3_24", "s": "english", "t": "Grammar", "l": 3, "q": "Choose the correct sentence.", "o": ["The boys runned home quickly", "The boys run home quickly", "The boys have ran home quickly", "The boys ran home quickly"], "a": "The boys ran home quickly", "e": "'Ran' is the correct simple past form of 'run'. 'Runned' is not a word."}, {"id": "eg3_25", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is a preposition?", "o": ["jump", "happy", "through", "quickly"], "a": "through", "e": "Prepositions show position or direction: through, under, above, beside."}, {"id": "eg3_26", "s": "english", "t": "Grammar", "l": 3, "q": "What is the plural of 'leaf'?", "o": ["Leafs", "Leaves", "Leafes", "Leaf"], "a": "Leaves", "e": "Words ending in 'f' usually change to 'ves' in the plural: leaf→leaves, wolf→wolves."}, {"id": "eg3_27", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence is in the future tense?", "o": ["She walked to school", "She walks to school", "She will walk to school", "She has walked to school"], "a": "She will walk to school", "e": "Future tense uses 'will' or 'shall' before the verb."}, {"id": "eg3_28", "s": "english", "t": "Grammar", "l": 3, "q": "Which word is a conjunction?", "o": ["but", "red", "slowly", "bird"], "a": "but", "e": "Conjunctions join clauses or sentences together: but, and, because, although, while."}, {"id": "eg3_29", "s": "english", "t": "Grammar", "l": 3, "q": "'The cat sat on the mat.' What part of speech is 'on'?", "o": ["Adjective", "Adverb", "Conjunction", "Preposition"], "a": "Preposition", "e": "'On' shows the relationship between 'sat' and 'the mat'. It is a preposition."}, {"id": "eg3_30", "s": "english", "t": "Grammar", "l": 3, "q": "Which verb form is correct: 'I have ___ my dinner.'?", "o": ["ate", "eat", "eaten", "eated"], "a": "eaten", "e": "With 'have', use the past participle: eaten (not ate, which is simple past)."}, {"id": "eg3_31", "s": "english", "t": "Grammar", "l": 3, "q": "What is the object in: 'The dog chased the ball'?", "o": ["The dog", "chased", "the ball", "dog"], "a": "the ball", "e": "The object receives the action. The dog (subject) chased what? The ball (object)."}, {"id": "eg3_32", "s": "english", "t": "Grammar", "l": 3, "q": "Which of these is a collective noun?", "o": ["flock", "run", "happy", "carefully"], "a": "flock", "e": "A collective noun names a group: flock (of birds), herd (of cattle), pack (of wolves)."}, {"id": "eg3_33", "s": "english", "t": "Grammar", "l": 3, "q": "What tense is 'She has been swimming'?", "o": ["Simple past", "Simple present", "Present perfect continuous", "Future"], "a": "Present perfect continuous", "e": "'Has been swimming' = present perfect continuous. It started in the past and is still happening."}, {"id": "eg3_34", "s": "english", "t": "Grammar", "l": 3, "q": "Choose the correct pronoun: '___ and I went to the shop.' (referring to Tom)", "o": ["Him", "His", "Me", "He"], "a": "He", "e": "'He and I went to the shop.' Test by removing 'and I': 'He went' sounds right; 'Him went' does not."}, {"id": "eg3_35", "s": "english", "t": "Grammar", "l": 3, "q": "What is the superlative form of 'good'?", "o": ["Gooder", "Goodest", "Better", "Best"], "a": "Best", "e": "Good → better → best. These are irregular comparatives/superlatives."}, {"id": "eg3_36", "s": "english", "t": "Grammar", "l": 3, "q": "Which sentence uses the passive voice?", "o": ["The chef cooked the meal", "The meal was cooked by the chef", "The chef had cooked the meal", "Cooking the meal, the chef smiled"], "a": "The meal was cooked by the chef", "e": "Passive voice: the subject receives the action. 'The meal' (subject) 'was cooked' (passive verb)."}, {"id": "eg3_37", "s": "english", "t": "Grammar", "l": 3, "q": "What is the plural of 'mouse'?", "o": ["Mouses", "Mousies", "Mice", "Mouse"], "a": "Mice", "e": "Mouse is an irregular plural: mouse → mice (like louse → lice)."}, {"id": "eg3_38", "s": "english", "t": "Grammar", "l": 3, "q": "Which word in the sentence is an adjective? 'The enormous wave crashed on the shore.'", "o": ["enormous", "crashed", "shore", "wave"], "a": "enormous", "e": "'Enormous' describes the noun 'wave'. Adjectives describe nouns."}, {"id": "eg3_39", "s": "english", "t": "Grammar", "l": 3, "q": "What does the subjunctive mood express in 'If I were you, I would leave'?", "o": ["A definite fact", "A command", "An imaginary or hypothetical situation", "A question"], "a": "An imaginary or hypothetical situation", "e": "The subjunctive ('were' instead of 'was') is used for hypothetical/imaginary situations."}, {"id": "eg3_40", "s": "english", "t": "Grammar", "l": 3, "q": "Which of these is an abstract noun?", "o": ["table", "dog", "freedom", "cloud"], "a": "freedom", "e": "Abstract nouns cannot be touched or seen. Freedom, courage, joy are abstract nouns."}, {"id": "ep3_21", "s": "english", "t": "Punctuation", "l": 3, "q": "Where does the comma go? 'After the storm the town was quiet.'", "o": ["After 'the", "After 'storm", "After 'town", "After 'was"], "a": "After 'storm'", "e": "After an introductory phrase or clause, use a comma. 'After the storm,' the town was quiet."}, {"id": "ep3_22", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses an apostrophe correctly?", "o": ["The cat's are purring", "Its raining outside", "The girl's book is red", "The dogs tail wagged"], "a": "The girl's book is red", "e": "Apostrophe shows possession: the book belonging to the girl = the girl's book."}, {"id": "ep3_23", "s": "english", "t": "Punctuation", "l": 3, "q": "What punctuation ends an exclamatory sentence?", "o": ["Full stop", "Comma", "Exclamation mark", "Question mark"], "a": "Exclamation mark", "e": "Exclamatory sentences show strong emotion and end with an exclamation mark (!)."}, {"id": "ep3_24", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence punctuates dialogue correctly?", "o": ["Come here' she said.", "Come here", " she said.", "Come here!' she said", "Come here", "she said."], "a": "'Come here,' she said.", "e": "In dialogue, a comma goes after the speech before the closing speech mark, then lower case 'she'."}, {"id": "ep3_25", "s": "english", "t": "Punctuation", "l": 3, "q": "What is a semicolon used for?", "o": ["To end a sentence", "To introduce a list", "To link two closely related main clauses", "To show possession"], "a": "To link two closely related main clauses", "e": "A semicolon (;) connects two independent clauses that are closely related: 'It was dark; she lit a candle.'"}, {"id": "ep3_26", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses brackets correctly?", "o": ["The capital (of France) is Paris", "The capital of (France) is Paris", "(The capital of France is Paris)", "The capital of France is (Paris)"], "a": "The capital (of France) is Paris", "e": "Brackets add extra information that could be removed without changing the main meaning."}, {"id": "ep3_27", "s": "english", "t": "Punctuation", "l": 3, "q": "'The dogs barks were loud.' What is missing?", "o": ["A comma", "An apostrophe after dog", "A full stop", "An exclamation mark"], "a": "An apostrophe after dog", "e": "Possessive: the barks belonging to the dog → the dog's barks."}, {"id": "ep3_28", "s": "english", "t": "Punctuation", "l": 3, "q": "Which correctly uses a colon?", "o": ["I like: swimming and running", "She said: she was tired", "I need three things: bread, milk and eggs", "The dog: barked loudly"], "a": "I need three things: bread, milk and eggs", "e": "A colon introduces a list or an explanation. It must follow a complete clause."}, {"id": "ep3_29", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence is punctuated correctly?", "o": ["Where are you going?", "Where are you going.", "Where are you going!", "Where, are you going?"], "a": "Where are you going?", "e": "A direct question ends with a question mark."}, {"id": "ep3_30", "s": "english", "t": "Punctuation", "l": 3, "q": "What does an ellipsis (...) most commonly show?", "o": ["A list", "A pause or trailing thought", "Strong emotion", "Possession"], "a": "A pause or trailing thought", "e": "An ellipsis shows a pause, a trailing off or something omitted from a quotation."}, {"id": "ep3_31", "s": "english", "t": "Punctuation", "l": 3, "q": "'Its a lovely day.' What is wrong?", "o": ["Missing capital", "Missing comma", "Its should be It's", "Missing full stop"], "a": "Its should be It\\\\\\\\", "e": "'It\\\\\\\\"}, {"id": "ep3_32", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses a dash correctly?", "o": ["The cat — a tabby — sat on the mat", "The cat-a tabby sat on the mat", "The cat, a tabby — sat on the mat", "The cat — a tabby sat on the mat"], "a": "The cat — a tabby — sat on the mat", "e": "Paired dashes act like brackets, adding extra information. Both dashes are needed."}, {"id": "ep3_33", "s": "english", "t": "Punctuation", "l": 3, "q": "Where does the apostrophe go in 'the books belonging to the children'?", "o": ["childrens", "children's", "childrens", "children's"], "a": "children's", "e": "'Children' is already plural (irregular), so add apostrophe + s: children's."}, {"id": "ep3_34", "s": "english", "t": "Punctuation", "l": 3, "q": "Which correctly punctuates a list?", "o": ["I bought apples, bread, milk, and eggs.", "I bought: apples bread milk and eggs.", "I bought apples bread, milk and, eggs.", "I bought, apples, bread, milk and eggs."], "a": "I bought apples, bread, milk, and eggs.", "e": "Items in a list are separated by commas. The comma before 'and' is an Oxford comma."}, {"id": "ep3_35", "s": "english", "t": "Punctuation", "l": 3, "q": "What does inverted commas (speech marks) around a word suggest?", "o": ["It is very important", "It is a title", "The writer questions or distances themselves from the word", "It is a foreign word"], "a": "The writer questions or distances themselves from the word", "e": "When speech marks appear around a non-dialogue word, they imply doubt or irony about it."}, {"id": "ep3_36", "s": "english", "t": "Punctuation", "l": 3, "q": "Which is the correct contraction for 'they are'?", "o": ["theys", "their", "they", ","], "a": "they're", "e": "'They're' = they are. Don't confuse with 'their' (belonging) or 'there' (place)."}, {"id": "ep3_37", "s": "english", "t": "Punctuation", "l": 3, "q": "'The girls bag was lost.' There are __ missing.", "o": ["One apostrophe", "Two apostrophes", "A comma", "A question mark"], "a": "One apostrophe", "e": "Possessive: the bag belonging to the girl → the girl's bag."}, {"id": "ep3_38", "s": "english", "t": "Punctuation", "l": 3, "q": "Which sentence uses a hyphen correctly?", "o": ["Well done the team", "It was a well-known fact", "The team-won", "She was well known"], "a": "It was a well-known fact", "e": "Hyphens join compound adjectives before a noun: 'well-known fact'. Not needed after verbs: 'she was well known'."}, {"id": "ep3_39", "s": "english", "t": "Punctuation", "l": 3, "q": "A subordinate clause is separated from the main clause by what?", "o": ["A full stop", "A semicolon", "A comma", "A colon"], "a": "A comma", "e": "A subordinate clause (when it comes first) is separated from the main clause by a comma: 'Although it was raining, we went out.'"}, {"id": "ep3_40", "s": "english", "t": "Punctuation", "l": 3, "q": "'The teachers books were marked.' How many teachers owned the books?", "o": ["One", "More than one", "Cannot tell", "None"], "a": "More than one", "e": "'Teachers' is plural. If one teacher: 'teacher\\\\\\\\"}, {"id": "erc3_21", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What does 'infer' mean in reading comprehension?", "o": ["Copy information directly from the text", "Work out meaning from clues in the text", "Look up words in a dictionary", "Summarise the whole text"], "a": "Work out meaning from clues in the text", "e": "Inference means reading between the lines — using clues to work out what is not directly stated."}, {"id": "erc3_22", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A character 'gripped the door handle, her knuckles white.' What does this suggest?", "o": ["She was cold", "She was excited", "She was nervous or frightened", "She was angry"], "a": "She was nervous or frightened", "e": "'Knuckles white' from gripping suggests tension, fear or anxiety."}, {"id": "erc3_23", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is the purpose of a text that begins: 'Did you know that sharks have been on Earth for 400 million years?'", "o": ["To entertain with a story", "To persuade you to swim", "To inform or interest the reader", "To give instructions"], "a": "To inform or interest the reader", "e": "The rhetorical question is designed to hook the reader into an informative or explanatory text."}, {"id": "erc3_24", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "The word 'deserted' in a text is closest in meaning to:", "o": ["Busy", "Abandoned", "Dangerous", "Beautiful"], "a": "Abandoned", "e": "Deserted means empty of people — abandoned or left behind."}, {"id": "erc3_25", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Which technique does an author use to build tension?", "o": ["Short, punchy sentences", "Long descriptive paragraphs", "Numbered lists", "Formal headings"], "a": "Short, punchy sentences", "e": "Short sentences quicken the pace and create urgency, building tension in the reader."}, {"id": "erc3_26", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A story says: 'The old man shuffled in, hunched over his stick.' What does this tell us?", "o": ["He is elderly and possibly frail", "He is young and strong", "He is in a hurry", "He is frightened"], "a": "He is elderly and possibly frail", "e": "'Shuffled', 'hunched' and 'stick' all suggest old age and physical frailty — shown, not told."}, {"id": "erc3_27", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is the difference between a fact and an opinion in a text?", "o": ["Facts use adjectives; opinions use nouns", "Facts can be proved; opinions are personal views", "Facts are interesting; opinions are boring", "Facts are short; opinions are long"], "a": "Facts can be proved; opinions are personal views", "e": "A fact is verifiable. An opinion is someone's belief or judgement and may vary from person to person."}, {"id": "erc3_28", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "'The thunder roared like an angry lion.' This is an example of:", "o": ["Alliteration", "Metaphor", "Personification", "Simile"], "a": "Simile", "e": "A simile compares two things using 'like' or 'as': thunder roared like an angry lion."}, {"id": "erc3_29", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A newspaper headline reads: 'Government Plans Could DESTROY Local Businesses.' What technique is being used?", "o": ["Alliteration", "Emotive language", "Repetition", "Rhetorical question"], "a": "Emotive language", "e": "The word 'DESTROY' (capitalised) is deliberately dramatic to provoke an emotional response."}, {"id": "erc3_30", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is a rhetorical question?", "o": ["A question with a surprising answer", "A question that does not expect an answer", "A question asked by the main character", "A question at the end of a chapter"], "a": "A question that does not expect an answer", "e": "Rhetorical questions are used for effect, to make the reader think — not to get a literal answer."}, {"id": "erc3_31", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "In a non-fiction text, what is the purpose of subheadings?", "o": ["To make the text look attractive", "To help the reader navigate and find information", "To show the author", ","], "a": "To help the reader navigate and find information", "e": "Subheadings act as signposts, showing the reader where to find specific information."}, {"id": "erc3_32", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "'The wind whispered through the trees.' What technique is this?", "o": ["Alliteration", "Hyperbole", "Personification", "Simile"], "a": "Personification", "e": "Personification gives human qualities to non-human things. Wind cannot whisper — but this creates atmosphere."}, {"id": "erc3_33", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Which word signals a contrast is coming?", "o": ["Furthermore", "Similarly", "However", "Therefore"], "a": "However", "e": "'However' signals that what follows will contrast or contradict what came before."}, {"id": "erc3_34", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A character in a story avoids all eye contact and speaks quietly. What can we infer?", "o": ["They are very confident", "They are shy or uncomfortable", "They are deaf", "They are lying"], "a": "They are shy or uncomfortable", "e": "These are classic signals of shyness or social discomfort — inference from behaviour."}, {"id": "erc3_35", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What does 'theme' mean in a story?", "o": ["The place the story is set", "The name of the main character", "The central message or idea explored", "The order events happen in"], "a": "The central message or idea explored", "e": "A theme is the big idea behind a story, such as friendship, courage, or justice."}, {"id": "erc3_36", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "Which word signals that the text is about to give an example?", "o": ["However", "Nevertheless", "For instance", "Although"], "a": "For instance", "e": "'For instance' (and 'for example') signal that a specific example is about to follow."}, {"id": "erc3_37", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "'I have told you a million times!' This is an example of:", "o": ["A simile", "Alliteration", "Hyperbole", "Personification"], "a": "Hyperbole", "e": "Hyperbole is deliberate exaggeration for effect. Nobody has literally been told something a million times."}, {"id": "erc3_38", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "What is an autobiography?", "o": ["A book about a famous person written by someone else", "A story about an imaginary person", "An account of a person", ","], "a": "An account of a person's own life written by themselves", "e": "Auto = self. Biography = life story. Autobiography = your own life story."}, {"id": "erc3_39", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "A poem ends each stanza with the same line. What is this technique called?", "o": ["Alliteration", "A refrain", "Rhyme scheme", "Enjambment"], "a": "A refrain", "e": "A refrain is a line or phrase repeated at intervals, usually at the end of each stanza."}, {"id": "erc3_40", "s": "english", "t": "Reading Comprehension", "l": 3, "q": "If a text is written in the first person, which pronoun will appear most?", "o": ["He", "She", "They", "I"], "a": "I", "e": "First person uses 'I', 'me', 'my', 'we'. It places the narrator inside the story."}, {"id": "ess3_21", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which of these is a complex sentence?", "o": ["The dog barked", "The dog barked and the cat ran", "Although it was raining, we played outside", "We played outside"], "a": "Although it was raining, we played outside", "e": "A complex sentence has a main clause and at least one subordinate clause joined by a subordinating conjunction."}, {"id": "ess3_22", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What type of clause can stand alone as a sentence?", "o": ["Relative clause", "Subordinate clause", "Main clause", "Dependent clause"], "a": "Main clause", "e": "A main clause makes complete sense on its own. A subordinate clause depends on the main clause."}, {"id": "ess3_23", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which word introduces a relative clause?", "o": ["because", "although", "which", "when"], "a": "which", "e": "Relative clauses are introduced by relative pronouns: who, which, that, whose, whom."}, {"id": "ess3_24", "s": "english", "t": "Sentence Structure", "l": 3, "q": "'She left early. She caught the train.' Combine using a conjunction.", "o": ["She left early, so she caught the train", "She left early if she caught the train", "She left early unless she caught the train", "She left early, yet she caught the train"], "a": "She left early, so she caught the train", "e": "'So' shows consequence — she left early and as a result caught the train."}, {"id": "ess3_25", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is the function of a fronted adverbial?", "o": ["To name the subject", "To describe the noun", "To add detail about when, where or how — placed at the start", "To ask a question"], "a": "To add detail about when, where or how — placed at the start", "e": "A fronted adverbial is placed before the main clause: 'Silently, the spy crept forward.'"}, {"id": "ess3_26", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence contains a subordinate clause?", "o": ["The dog barked loudly", "Run!", "I left because I was bored", "She sang and danced"], "a": "I left because I was bored", "e": "'Because I was bored' is a subordinate clause — it cannot stand alone and depends on 'I left'."}, {"id": "ess3_27", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is a compound sentence?", "o": ["One main clause only", "A main clause with a subordinate clause", "Two or more main clauses joined by a coordinating conjunction", "A sentence with no verb"], "a": "Two or more main clauses joined by a coordinating conjunction", "e": "Compound sentences join two main clauses with FANBOYS conjunctions: for, and, nor, but, or, yet, so."}, {"id": "ess3_28", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Identify the relative clause: 'The house, which was very old, fell down.'", "o": ["The house fell down", "The house which was very old", "which was very old", "which was very old fell down"], "a": "which was very old", "e": "The relative clause adds information about 'the house'. It is introduced by 'which' and set off by commas."}, {"id": "ess3_29", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which is an imperative sentence?", "o": ["She went to the shop", "Did you go to the shop?", "Go to the shop!", "She would go to the shop"], "a": "Go to the shop!", "e": "An imperative sentence gives a command or instruction. It starts with a verb."}, {"id": "ess3_30", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is the effect of using a one-word sentence like 'Silence.' in a story?", "o": ["It shows the character is speaking", "It creates drama and emphasis", "It introduces a list", "It asks a question"], "a": "It creates drama and emphasis", "e": "A very short or one-word sentence stands out. It slows the reader and creates impact."}, {"id": "ess3_31", "s": "english", "t": "Sentence Structure", "l": 3, "q": "'Exhausted by the long climb, he sat down.' What technique is this?", "o": ["Fronted adverbial", "Relative clause", "Rhetorical question", "Compound sentence"], "a": "Fronted adverbial", "e": "The participial phrase 'Exhausted by the long climb' is a fronted adverbial adding context before the main clause."}, {"id": "ess3_32", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which conjunction is subordinating?", "o": ["and", "but", "or", "although"], "a": "although", "e": "Subordinating conjunctions introduce subordinate clauses: although, because, when, if, since, unless."}, {"id": "ess3_33", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is a participle clause?", "o": ["A clause starting with a verb ending in -ing or -ed", "giving extra information", "A clause that asks a question", "A list of items", "A clause using 'that' or 'which"], "a": "A clause starting with a verb ending in -ing or -ed, giving extra information", "e": "Example: 'Running fast, she won the race.' The -ing clause gives extra detail."}, {"id": "ess3_34", "s": "english", "t": "Sentence Structure", "l": 3, "q": "'She is clever, kind and talented.' What is the punctuation rule here?", "o": ["Commas separate items in a list", "A semicolon must be used", "No punctuation needed", "Colons separate the adjectives"], "a": "Commas separate items in a list", "e": "When listing adjectives or items, separate them with commas. The last item before 'and' may or may not have a comma."}, {"id": "ess3_35", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which of the following is a passive sentence?", "o": ["The cat chased the mouse", "The mouse chased the cat", "The mouse was chased by the cat", "The cat and mouse ran together"], "a": "The mouse was chased by the cat", "e": "In passive voice, the subject receives the action: 'the mouse was chased'."}, {"id": "ess3_36", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is the subject of this sentence? 'The grey clouds gathered overhead.'", "o": ["grey", "gathered", "clouds", "overhead"], "a": "clouds", "e": "The subject is what the sentence is about — what is gathering? The clouds."}, {"id": "ess3_37", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which technique creates pace and tension in action writing?", "o": ["Long, complex sentences", "Lists of adjectives", "Short, simple sentences", "Passive voice"], "a": "Short, simple sentences", "e": "Short sentences quicken pace. They mimic urgency and action — perfect for tense moments."}, {"id": "ess3_38", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Add an appropriate fronted adverbial: '___, the detective examined the footprints.'", "o": ["Curious and interesting", "Carefully and methodically", "With great care and precision", "The detective curious"], "a": "With great care and precision", "e": "'With great care and precision' is a prepositional phrase that works as a fronted adverbial, followed by a comma."}, {"id": "ess3_39", "s": "english", "t": "Sentence Structure", "l": 3, "q": "Which sentence type asks for information?", "o": ["Declarative", "Exclamatory", "Imperative", "Interrogative"], "a": "Interrogative", "e": "Interrogative sentences ask questions. They end with a question mark."}, {"id": "ess3_40", "s": "english", "t": "Sentence Structure", "l": 3, "q": "What is enjambment in poetry?", "o": ["Repeating a word for effect", "When a sentence continues beyond a line break", "Rhyming pairs of lines", "A regular beat in a poem"], "a": "When a sentence continues beyond a line break", "e": "Enjambment is when a sentence or clause does not stop at the end of a line but runs onto the next."}, {"id": "es3_21", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["recieve", "receive", "receve", "reciece"], "a": "receive", "e": "'I before E except after C' — so after C: receive, ceiling, deceit."}, {"id": "es3_22", "s": "english", "t": "Spelling", "l": 3, "q": "Which word is spelled correctly?", "o": ["necessary", "neccesary", "neccessary", "necesary"], "a": "necessary", "e": "Remember: one collar (1 c), two socks (2 s). Necessary."}, {"id": "es3_23", "s": "english", "t": "Spelling", "l": 3, "q": "Choose the correct spelling: 'She ___ the answer.' (past tense of know)", "o": ["knowed", "knew", "known", "knewn"], "a": "knew", "e": "'Knew' is the simple past of know. 'Known' is the past participle (used with have)."}, {"id": "es3_24", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["seperate", "separete", "separate", "seprate"], "a": "separate", "e": "There's 'a rat' in separate: sep-a-rat-e."}, {"id": "es3_25", "s": "english", "t": "Spelling", "l": 3, "q": "Which word means 'able to be believed' and is spelled correctly?", "o": ["credable", "credible", "creduble", "credibel"], "a": "credible", "e": "The suffix is -ible (not -able): credible, responsible, incredible."}, {"id": "es3_26", "s": "english", "t": "Spelling", "l": 3, "q": "Which spelling is correct?", "o": ["occassion", "occasion", "occaision", "ocassion"], "a": "occasion", "e": "Double c, single s: oc-ca-sion."}, {"id": "es3_27", "s": "english", "t": "Spelling", "l": 3, "q": "Which of these is a homophone of 'there'?", "o": ["Their", "Hear", "Where", "Through"], "a": "Their", "e": "'Their' (possession) and 'there' (place) and 'they\\\\\\\\"}, {"id": "es3_28", "s": "english", "t": "Spelling", "l": 3, "q": "What is the correct spelling?", "o": ["independant", "indepenent", "independent", "independant"], "a": "independent", "e": "The suffix is -ent (not -ant): independent, confident, evident."}, {"id": "es3_29", "s": "english", "t": "Spelling", "l": 3, "q": "Which word is spelled correctly?", "o": ["harass", "harrass", "harras", "haras"], "a": "harass", "e": "One r, double s: harass."}, {"id": "es3_30", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["definately", "definitaly", "definitely", "definatly"], "a": "definitely", "e": "Think: definite + ly = definitely. 'Finite' is in the middle."}, {"id": "es3_31", "s": "english", "t": "Spelling", "l": 3, "q": "Which word uses the suffix -tion correctly?", "o": ["nationalty", "national", "sensation", "sensatious"], "a": "sensation", "e": "The -tion suffix creates nouns: sense → sensation, nation → national uses -al, not -tion."}, {"id": "es3_32", "s": "english", "t": "Spelling", "l": 3, "q": "Which pair are homophones?", "o": ["bare / bear", "car / cart", "make / bake", "slow / slew"], "a": "bare / bear", "e": "Homophones sound the same but mean different things: bare (uncovered), bear (animal or to carry)."}, {"id": "es3_33", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["goverment", "government", "govrenment", "govenment"], "a": "government", "e": "The silent 'n': govern-ment. Govern + ment."}, {"id": "es3_34", "s": "english", "t": "Spelling", "l": 3, "q": "Choose the correct word: 'The weather will ___ us.' (to affect/have an effect on)", "o": ["affect", "effect", "afect", "efect"], "a": "affect", "e": "'Affect' is usually a verb (to affect something). 'Effect' is usually a noun (the effect)."}, {"id": "es3_35", "s": "english", "t": "Spelling", "l": 3, "q": "Which is spelled correctly?", "o": ["mischievous", "mischevious", "mischeivous", "mischievious"], "a": "mischievous", "e": "Mis-chiev-ous. Three syllables only. There is no 'i' after 'ev'."}, {"id": "es3_36", "s": "english", "t": "Spelling", "l": 3, "q": "Which word is the odd one out (different spelling pattern)?", "o": ["nation", "station", "attention", "mansion"], "a": "mansion", "e": "Nation, station, attention use -tion. Mansion uses -sion. Different suffix for the same /shun/ sound."}, {"id": "es3_37", "s": "english", "t": "Spelling", "l": 3, "q": "Which sentence uses the correct word?", "o": ["Their going to the park", "There going to the park", "They're going to the park", "Theyre going to the park"], "a": "They\\\\\\\\", "e": "'They\\\\\\\\"}, {"id": "es3_38", "s": "english", "t": "Spelling", "l": 3, "q": "Which is correct?", "o": ["accomodate", "accommodate", "acomodate", "acommodate"], "a": "accommodate", "e": "Double c AND double m: ac-com-mo-date."}, {"id": "es3_39", "s": "english", "t": "Spelling", "l": 3, "q": "What is the correct past tense of 'practise'?", "o": ["practiced", "practised", "practissed", "practis"], "a": "practised", "e": "Practise (verb) → practised. In British English, practice is the noun; practise is the verb."}, {"id": "es3_40", "s": "english", "t": "Spelling", "l": 3, "q": "Which word is spelled correctly?", "o": ["enviroment", "environment", "enviornment", "enviorment"], "a": "environment", "e": "The tricky bit: envir-on-ment. The 'n' before the 'm': environ-ment."}, {"id": "esa3_21", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is a synonym for 'ancient'?", "o": ["modern", "new", "aged", "young"], "a": "aged", "e": "Ancient means very old. A synonym must mean the same thing: aged."}, {"id": "esa3_22", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'generous'?", "o": ["kind", "giving", "mean", "lavish"], "a": "mean", "e": "Generous means giving freely. The opposite: mean or stingy."}, {"id": "esa3_23", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the synonym for 'transparent':", "o": ["opaque", "foggy", "clear", "dark"], "a": "clear", "e": "Transparent means you can see through it — clear is the closest synonym."}, {"id": "esa3_24", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym of 'timid'?", "o": ["shy", "nervous", "hesitant", "bold"], "a": "bold", "e": "Timid means shy and nervous. The opposite is bold or confident."}, {"id": "esa3_25", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose a synonym for 'exhausted':", "o": ["energetic", "weary", "rested", "active"], "a": "weary", "e": "Exhausted means very tired. Weary is the closest synonym from the options."}, {"id": "esa3_26", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "What is an antonym of 'reluctant'?", "o": ["unwilling", "hesitant", "eager", "cautious"], "a": "eager", "e": "Reluctant means unwilling. The opposite is eager or willing."}, {"id": "esa3_27", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is a synonym for 'cunning'?", "o": ["foolish", "clumsy", "crafty", "honest"], "a": "crafty", "e": "Cunning means clever at tricking. Crafty has the same meaning."}, {"id": "esa3_28", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym of 'magnificent'?", "o": ["splendid", "glorious", "dreadful", "grand"], "a": "dreadful", "e": "Magnificent means wonderful and impressive. The opposite would be terrible or dreadful."}, {"id": "esa3_29", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "What is a synonym for 'villain'?", "o": ["hero", "criminal", "detective", "victim"], "a": "criminal", "e": "A villain is a bad character who commits wrongdoing — a criminal is the closest synonym."}, {"id": "esa3_30", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose a word that is both a synonym of 'big' and 'great':", "o": ["small", "enormous", "slight", "thin"], "a": "enormous", "e": "Enormous means extremely large — a strong synonym for both big and great."}, {"id": "esa3_31", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym of 'reveal'?", "o": ["show", "display", "conceal", "uncover"], "a": "conceal", "e": "Reveal means to show or uncover. The opposite is to conceal or hide."}, {"id": "esa3_32", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose the best synonym for 'brave' from a formal context:", "o": ["scared", "bold", "valiant", "timid"], "a": "valiant", "e": "Valiant is a formal, literary synonym for brave — very fitting for Year 5/6 level."}, {"id": "esa3_33", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which word is an antonym for 'swift'?", "o": ["fast", "rapid", "sluggish", "nimble"], "a": "sluggish", "e": "Swift means fast. The antonym is slow or sluggish."}, {"id": "esa3_34", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose a synonym for 'peculiar':", "o": ["normal", "strange", "ordinary", "plain"], "a": "strange", "e": "Peculiar means strange or unusual. Strange is its closest synonym."}, {"id": "esa3_35", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym for 'vivid'?", "o": ["bright", "striking", "dull", "colourful"], "a": "dull", "e": "Vivid means bright and striking. The opposite is dull or faded."}, {"id": "esa3_36", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "What is a synonym for 'perilous'?", "o": ["safe", "dangerous", "calm", "pleasant"], "a": "dangerous", "e": "Perilous means full of danger — dangerous is the synonym."}, {"id": "esa3_37", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym of 'jubilant'?", "o": ["joyful", "ecstatic", "elated", "miserable"], "a": "miserable", "e": "Jubilant means extremely happy. The opposite is miserable or dejected."}, {"id": "esa3_38", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Choose a synonym for 'serene':", "o": ["turbulent", "peaceful", "stormy", "noisy"], "a": "peaceful", "e": "Serene means calm and peaceful — peaceful is the direct synonym."}, {"id": "esa3_39", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "Which is an antonym of 'abundant'?", "o": ["plentiful", "ample", "scarce", "generous"], "a": "scarce", "e": "Abundant means plentiful. The opposite is scarce — in very short supply."}, {"id": "esa3_40", "s": "english", "t": "Synonyms & Antonyms", "l": 3, "q": "What is a synonym for 'tenacious'?", "o": ["weak", "persistent", "lazy", "timid"], "a": "persistent", "e": "Tenacious means determined and not giving up — persistent means the same thing."}, {"id": "evr3_21", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the odd one out: oak, elm, rose, birch, pine", "o": ["oak", "elm", "rose", "pine"], "a": "rose", "e": "Oak, elm, birch and pine are all trees. A rose is a flowering plant/shrub, not a tree."}, {"id": "evr3_22", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What comes next in the pattern: AZ, BY, CX, DW, ___?", "o": ["EV", "EU", "FV", "EW"], "a": "EV", "e": "First letter goes forward (A,B,C,D,E), second letter goes backward (Z,Y,X,W,V)."}, {"id": "evr3_23", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the analogy: pen is to writer as brush is to ___.", "o": ["paint", "art", "painter", "canvas"], "a": "painter", "e": "A pen is the tool of a writer. A brush is the tool of a painter."}, {"id": "evr3_24", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the analogy: book is to library as painting is to ___.", "o": ["school", "gallery", "museum", "studio"], "a": "gallery", "e": "A book is stored/displayed in a library. A painting is displayed in a gallery."}, {"id": "evr3_25", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What comes next in the pattern: J, F, M, A, M, J, J, A, ___?", "o": ["O", "S", "P", "N"], "a": "S", "e": "These are the first letters of the months: Jan, Feb, Mar, Apr, May, Jun, Jul, Aug, Sep."}, {"id": "evr3_26", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the odd one out: flute, trumpet, violin, clarinet, oboe", "o": ["flute", "trumpet", "violin", "clarinet"], "a": "violin", "e": "Flute, trumpet, clarinet and oboe are all wind instruments. A violin is a string instrument."}, {"id": "evr3_27", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the sequence: 2, 6, 18, 54, ___", "o": ["108", "108", "162", "180"], "a": "162", "e": "Each term is multiplied by 3: 2×3=6, 6×3=18, 18×3=54, 54×3=162."}, {"id": "evr3_28", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the odd one out: January, March, June, July, August", "o": ["January", "March", "June", "July"], "a": "June", "e": "January, March, July and August have 31 days. June has only 30 days."}, {"id": "evr3_29", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the odd one out: triangle, circle, cube, square, pentagon", "o": ["triangle", "circle", "cube", "square"], "a": "cube", "e": "Triangle, circle, square and pentagon are 2D shapes. A cube is a 3D shape."}, {"id": "evr3_30", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the analogy: hot is to cold as light is to ___.", "o": ["bright", "dark", "lamp", "fire"], "a": "dark", "e": "Hot and cold are opposites. Light and dark are opposites."}, {"id": "evr3_31", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the next number: 1, 4, 9, 16, 25, ___", "o": ["30", "35", "36", "49"], "a": "36", "e": "These are square numbers: 1²=1, 2²=4, 3²=9, 4²=16, 5²=25, 6²=36."}, {"id": "evr3_32", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which word does NOT belong? mercury, venus, earth, moon, mars", "o": ["mercury", "venus", "earth", "moon"], "a": "moon", "e": "Mercury, Venus, Earth and Mars are planets. The Moon is Earth's natural satellite, not a planet."}, {"id": "evr3_33", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What is the missing number? 100, 91, 82, 73, ___", "o": ["64", "63", "62", "60"], "a": "64", "e": "Each term decreases by 9: 100, 91, 82, 73, 64."}, {"id": "evr3_34", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "If A=1, B=2, C=3... what does the code 20-5-1-13 spell?", "o": ["TEAM", "STEM", "MEAT", "TAME"], "a": "TEAM", "e": "T=20, E=5, A=1, M=13. TEAM."}, {"id": "evr3_35", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the odd one out: whisper, shout, mutter, colour, mumble", "o": ["whisper", "shout", "mutter", "colour"], "a": "colour", "e": "Whisper, shout, mutter and mumble are all ways of speaking. Colour is not."}, {"id": "evr3_36", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Complete the analogy: glove is to hand as sock is to ___.", "o": ["shoe", "foot", "leg", "heel"], "a": "foot", "e": "A glove covers a hand. A sock covers a foot."}, {"id": "evr3_37", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "What is the missing number? 3, 8, 13, 18, ___, 28", "o": ["20", "21", "22", "23"], "a": "23", "e": "The sequence increases by 5 each time: 3, 8, 13, 18, 23, 28."}, {"id": "evr3_38", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "If the code for CAT is DBU, what is the code for DOG?", "o": ["EPH", "EQH", "CPF", "FQH"], "a": "EPH", "e": "Each letter moves forward one: D→E, O→P, G→H."}, {"id": "evr3_39", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Which word can follow all of these: thunder, rain, snow?", "o": ["coat", "storm", "fall", "drop"], "a": "storm", "e": "Thunderstorm ✓, rainstorm ✓, snowstorm ✓. All work!"}, {"id": "evr3_40", "s": "english", "t": "Verbal Reasoning", "l": 3, "q": "Find the next term: Z, X, V, T, ___", "o": ["R", "S", "P", "Q"], "a": "R", "e": "Each letter skips one: Z(-2)X(-2)V(-2)T(-2)R."}, {"id": "ev3_21", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'consecutive' mean?", "o": ["Random", "Following one after another", "Backwards", "Repeated"], "a": "Following one after another", "e": "Consecutive means following in unbroken order: three consecutive days = Monday, Tuesday, Wednesday."}, {"id": "ev3_22", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'diminish' mean?", "o": ["To grow larger", "To become louder", "To become smaller or less", "To stay the same"], "a": "To become smaller or less", "e": "Diminish means to make or become smaller in size, importance or intensity."}, {"id": "ev3_23", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'formidable' mean?", "o": ["Very funny", "Inspiring fear or respect due to great size or power", "Very friendly", "Easy to defeat"], "a": "Inspiring fear or respect due to great size or power", "e": "Formidable describes something impressively powerful and difficult to deal with."}, {"id": "ev3_24", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'futile' mean?", "o": ["Useful", "Successful", "Pointless — producing no result", "Difficult"], "a": "Pointless — producing no result", "e": "Futile means having no effect whatsoever. A futile effort achieves nothing."}, {"id": "ev3_25", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'inevitable' mean?", "o": ["Unlikely to happen", "Certain to happen", "Possible but rare", "Surprising"], "a": "Certain to happen", "e": "Inevitable means unavoidable — it will definitely happen, no matter what."}, {"id": "ev3_26", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'meticulous' mean?", "o": ["Careless", "Quick", "Very careful and precise about small details", "Disorganised"], "a": "Very careful and precise about small details", "e": "A meticulous person takes great care to get every detail exactly right."}, {"id": "ev3_27", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'ominous' mean?", "o": ["Cheerful", "Giving a feeling that something bad is about to happen", "Surprising", "Colourful"], "a": "Giving a feeling that something bad is about to happen", "e": "Ominous means threatening — it suggests danger or something unpleasant is coming."}, {"id": "ev3_28", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'resilient' mean?", "o": ["Fragile", "Able to recover quickly from difficult situations", "Stubborn", "Slow"], "a": "Able to recover quickly from difficult situations", "e": "A resilient person bounces back from setbacks. Resilience is the ability to recover."}, {"id": "ev3_29", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'sinister' mean?", "o": ["Funny", "Cheerful", "Suggesting evil or harm", "Careless"], "a": "Suggesting evil or harm", "e": "Sinister means threatening or suggesting something wicked or dangerous."}, {"id": "ev3_30", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'stealthy' mean?", "o": ["Loud and clumsy", "Moving quietly to avoid being detected", "Fast and energetic", "Bright and colourful"], "a": "Moving quietly to avoid being detected", "e": "Stealthy means behaving in a cautious, secretive way to avoid being seen or heard."}, {"id": "ev3_31", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'benevolent' mean?", "o": ["Cruel", "Kind and generous", "Strict", "Unhappy"], "a": "Kind and generous", "e": "Benevolent means well-meaning and kindly — a benevolent ruler cares for their people."}, {"id": "ev3_32", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'diligent' mean?", "o": ["Lazy", "Careless", "Hardworking and careful", "Quick but sloppy"], "a": "Hardworking and careful", "e": "Diligent means showing steady, careful effort. A diligent student always does their best work."}, {"id": "ev3_33", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'notorious' mean?", "o": ["Famous for good deeds", "Unknown", "Famous for something bad", "Very ordinary"], "a": "Famous for something bad", "e": "Notorious means famous for a negative reason — a notorious criminal is well known for wrongdoing."}, {"id": "ev3_34", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'plausible' mean?", "o": ["Impossible", "Seeming reasonable or probable", "Definitely true", "Obviously wrong"], "a": "Seeming reasonable or probable", "e": "Plausible means it could believably be true, even if it hasn't been proved."}, {"id": "ev3_35", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'wary' mean?", "o": ["Confident", "Careless", "Feeling excited", "Cautious about possible danger"], "a": "Cautious about possible danger", "e": "Wary means watchful and careful — you are wary of something you think might be risky."}, {"id": "ev3_36", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'accumulate' mean?", "o": ["To throw away", "To gather or build up over time", "To destroy", "To separate"], "a": "To gather or build up over time", "e": "Accumulate means to collect more and more of something gradually over time."}, {"id": "ev3_37", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'deteriorate' mean?", "o": ["To improve", "To become worse over time", "To stay the same", "To grow quickly"], "a": "To become worse over time", "e": "Deteriorate means to get progressively worse — the opposite of improve."}, {"id": "ev3_38", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'perceive' mean?", "o": ["To ignore", "To become aware of something through the senses or mind", "To forget", "To destroy"], "a": "To become aware of something through the senses or mind", "e": "Perceive means to notice, observe or understand something."}, {"id": "ev3_39", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'illuminate' mean?", "o": ["To darken", "To confuse", "To light up or make clear", "To destroy"], "a": "To light up or make clear", "e": "Illuminate means to shed light on something — either literally (lighting a room) or figuratively (explaining something clearly)."}, {"id": "ev3_40", "s": "english", "t": "Vocabulary", "l": 3, "q": "What does 'inquisitive' mean?", "o": ["Uninterested", "Curious and eager to know things", "Frightened", "Rude"], "a": "Curious and eager to know things", "e": "Inquisitive means having a great desire to learn or know things — a naturally curious person."},
{"id": "mf4_21", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 3/4 + 5/8?", "o": ["1 3/8", "1 1/8", "1 5/8", "1 1/4"], "a": "1 3/8", "e": "Convert to eighths: 6/8 + 5/8 = 11/8 = 1 3/8"}, {"id": "mf4_22", "s": "maths", "t": "Fractions", "l": 4, "q": "A recipe needs 2/3 cup of sugar. You make 1 and a half times the recipe. How much sugar do you need?", "o": ["1 cup", "1 1/3 cups", "1 1/6 cups", "2/3 cup"], "a": "1 cup", "e": "2/3 x 3/2 = 6/6 = 1 cup"}, {"id": "mf4_23", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 5/6 minus 3/4?", "o": ["1/12", "2/3", "1/6", "1/3"], "a": "1/12", "e": "LCD is 12: 10/12 - 9/12 = 1/12"}, {"id": "mf4_24", "s": "maths", "t": "Fractions", "l": 4, "q": "3/5 of a class of 40 students passed. How many passed?", "o": ["20", "24", "28", "30"], "a": "24", "e": "3/5 x 40 = 24"}, {"id": "mf4_25", "s": "maths", "t": "Fractions", "l": 4, "q": "Which fraction is equivalent to 18/24?", "o": ["2/3", "3/4", "5/6", "4/5"], "a": "3/4", "e": "18/24 divided by 6/6 = 3/4"}, {"id": "mf4_26", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 2 and 1/4 multiplied by 1 and 1/3?", "o": ["2 5/6", "3", "3 1/4", "2 2/3"], "a": "3", "e": "9/4 x 4/3 = 36/12 = 3"}, {"id": "mf4_27", "s": "maths", "t": "Fractions", "l": 4, "q": "Order from smallest to largest: 3/4, 2/3, 5/6, 7/9", "o": ["2/3, 3/4, 7/9, 5/6", "2/3, 7/9, 3/4, 5/6", "3/4, 2/3, 5/6, 7/9", "5/6, 7/9, 3/4, 2/3"], "a": "2/3, 3/4, 7/9, 5/6", "e": "As 36ths: 24, 27, 28, 30. So 2/3 < 3/4 < 7/9 < 5/6"}, {"id": "mf4_28", "s": "maths", "t": "Fractions", "l": 4, "q": "A tank is 7/8 full. After using 1/4 of the total capacity, what fraction remains?", "o": ["5/8", "3/4", "6/8", "7/12"], "a": "5/8", "e": "7/8 - 2/8 = 5/8"}, {"id": "mf4_29", "s": "maths", "t": "Fractions", "l": 4, "q": "What is 3/7 of 84?", "o": ["32", "36", "40", "42"], "a": "36", "e": "84 / 7 = 12, then 12 x 3 = 36"}, {"id": "mf4_30", "s": "maths", "t": "Fractions", "l": 4, "q": "If 5/9 of a number is 45, what is the number?", "o": ["75", "81", "90", "63"], "a": "81", "e": "45 / 5 x 9 = 9 x 9 = 81"}, {"id": "mmd4_21", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is 47 x 23?", "o": ["1,061", "1,081", "1,108", "1,121"], "a": "1,081", "e": "47x20=940, 47x3=141, total=1,081"}, {"id": "mmd4_22", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "248 divided by 8 equals what?", "o": ["29", "31", "32", "28"], "a": "31", "e": "8x31=248"}, {"id": "mmd4_23", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is the Lowest Common Multiple (LCM) of 6 and 10?", "o": ["20", "30", "60", "16"], "a": "30", "e": "Multiples of 6: 6,12,18,24,30. Multiples of 10: 10,20,30. LCM=30"}, {"id": "mmd4_24", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "A school trip costs 12 pounds per student. If 144 students go, what is the total cost?", "o": ["1,628", "1,728", "1,828", "1,928"], "a": "1,728", "e": "144 x 12 = 1,728"}, {"id": "mmd4_25", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is 36 x 25?", "o": ["800", "850", "900", "950"], "a": "900", "e": "36 x 25 = 36 x 100 / 4 = 3600 / 4 = 900"}, {"id": "mmd4_26", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "How many factors does 48 have?", "o": ["8", "9", "10", "11"], "a": "10", "e": "Factors of 48: 1,2,3,4,6,8,12,16,24,48 — that is 10 factors"}, {"id": "mmd4_27", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "Calculate: 3 x (4 + 6) - 5 x 2", "o": ["15", "20", "25", "10"], "a": "20", "e": "3x10 - 10 = 30 - 10 = 20"}, {"id": "mmd4_28", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is 504 divided by 14?", "o": ["34", "36", "38", "42"], "a": "36", "e": "14 x 36 = 504"}, {"id": "mmd4_29", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "What is the Highest Common Factor (HCF) of 24 and 36?", "o": ["6", "9", "12", "18"], "a": "12", "e": "Factors of 24 and 36 share: 1,2,3,4,6,12. HCF=12"}, {"id": "mmd4_30", "s": "maths", "t": "Multiplication & Division", "l": 4, "q": "18 boxes each contain 24 pencils, shared equally among 12 classes. How many pencils per class?", "o": ["32", "34", "36", "38"], "a": "36", "e": "18x24=432, 432/12=36"}, {"id": "mpv4_21", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 3.47 x 100?", "o": ["34.7", "347", "3470", "0.347"], "a": "347", "e": "Multiply by 100: move decimal 2 places right = 347"}, {"id": "mpv4_22", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Round 6.385 to 2 decimal places.", "o": ["6.38", "6.39", "6.40", "6.4"], "a": "6.39", "e": "Third decimal is 5, so round up: 6.39"}, {"id": "mpv4_23", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "In 4.726, what is the value of the digit 2?", "o": ["2 tenths", "2 hundredths", "2 thousandths", "2 ones"], "a": "2 hundredths", "e": "4.726: tenths=7, hundredths=2, thousandths=6"}, {"id": "mpv4_24", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Order from largest to smallest: 3.07, 3.7, 3.071, 3.17", "o": ["3.7, 3.17, 3.071, 3.07", "3.7, 3.17, 3.07, 3.071", "3.17, 3.7, 3.071, 3.07", "3.071, 3.07, 3.17, 3.7"], "a": "3.7, 3.17, 3.071, 3.07", "e": "3.700 > 3.170 > 3.071 > 3.070"}, {"id": "mpv4_25", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 58,400 divided by 1,000?", "o": ["5.84", "58.4", "584", "0.584"], "a": "58.4", "e": "Dividing by 1,000 moves the decimal 3 places left"}, {"id": "mpv4_26", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Which is the largest: 5/8, 0.6, 63%, or 0.625?", "o": ["5/8", "0.6", "63%", "0.625"], "a": "63%", "e": "63%=0.63, 5/8=0.625, so 0.63 is the largest"}, {"id": "mpv4_27", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is 0.45 x 1,000?", "o": ["4.5", "45", "450", "4500"], "a": "450", "e": "0.45 x 1,000 = 450"}, {"id": "mpv4_28", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "Write 4.08 as a mixed number in its simplest form.", "o": ["408/100", "102/25", "4 and 2/25", "51/12"], "a": "4 and 2/25", "e": "4.08 = 4 and 8/100 = 4 and 2/25"}, {"id": "mpv4_29", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "A number rounded to 1 decimal place gives 7.4. Which could NOT be the original?", "o": ["7.36", "7.44", "7.45", "7.38"], "a": "7.45", "e": "7.45 rounds to 7.5, not 7.4. The rounding range is 7.35 to 7.449"}, {"id": "mpv4_30", "s": "maths", "t": "Place Value & Number", "l": 4, "q": "What is the difference between the largest and smallest 4-digit numbers made from 1, 0, 7, 5?", "o": ["6,174", "6,372", "6,282", "6,174"], "a": "6,174", "e": "Largest: 7,510. Smallest (no leading zero): 1,057. Difference: 7510-1057=6,453"}, {"id": "mas4_21", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "5,638 + 2,947 = ?", "o": ["8,475", "8,485", "8,585", "8,475"], "a": "8,585", "e": "5,638 + 2,947 = 8,585"}, {"id": "mas4_22", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "7,002 - 3,486 = ?", "o": ["3,416", "3,516", "3,526", "3,616"], "a": "3,516", "e": "7,002 - 3,486 = 3,516"}, {"id": "mas4_23", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A shop has 3,450 items. They receive 1,278 new items and sell 967. How many remain?", "o": ["3,661", "3,761", "3,671", "3,581"], "a": "3,761", "e": "3,450 + 1,278 = 4,728; 4,728 - 967 = 3,761"}, {"id": "mas4_24", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "What must be added to 4,387 to make 7,000?", "o": ["2,613", "2,713", "3,613", "2,600"], "a": "2,613", "e": "7,000 - 4,387 = 2,613"}, {"id": "mas4_25", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "12.6 + 8.75 + 3.4 = ?", "o": ["24.75", "24.65", "25.75", "24.85"], "a": "24.75", "e": "12.60 + 8.75 = 21.35; 21.35 + 3.40 = 24.75"}, {"id": "mas4_26", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A library has 5,200 books. They donate 1,300 and receive 450 new ones. How many books remain?", "o": ["3,950", "4,050", "4,350", "4,550"], "a": "4,350", "e": "5,200 - 1,300 + 450 = 4,350"}, {"id": "mas4_27", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "100.00 - 63.75 = ?", "o": ["36.25", "37.25", "36.35", "37.35"], "a": "36.25", "e": "100.00 - 63.75 = 36.25"}, {"id": "mas4_28", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "Three friends collect 2,145; 1,867; and 3,004 stamps. How many altogether?", "o": ["7,016", "7,106", "7,006", "6,916"], "a": "7,016", "e": "2,145 + 1,867 = 4,012; 4,012 + 3,004 = 7,016"}, {"id": "mas4_29", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "9,000 - 4,563 = ?", "o": ["4,337", "4,437", "4,537", "4,367"], "a": "4,437", "e": "9,000 - 4,563 = 4,437"}, {"id": "mas4_30", "s": "maths", "t": "Addition & Subtraction", "l": 4, "q": "A tank holds 8,500 litres. After using 2,375 litres then adding 1,200 litres, how much is in the tank?", "o": ["7,225", "7,325", "7,125", "7,425"], "a": "7,325", "e": "8,500 - 2,375 = 6,125; 6,125 + 1,200 = 7,325"}, {"id": "mdc4_21", "s": "maths", "t": "Decimals", "l": 4, "q": "3.6 x 4.5 = ?", "o": ["15.2", "16.2", "16.8", "15.8"], "a": "16.2", "e": "3.6 x 4 = 14.4; 3.6 x 0.5 = 1.8; total = 16.2"}, {"id": "mdc4_22", "s": "maths", "t": "Decimals", "l": 4, "q": "18.9 divided by 0.3 = ?", "o": ["6.3", "63", "630", "0.63"], "a": "63", "e": "18.9 / 0.3 = 189 / 3 = 63"}, {"id": "mdc4_23", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 0.24 as a percentage?", "o": ["2.4%", "24%", "0.24%", "240%"], "a": "24%", "e": "0.24 x 100 = 24%"}, {"id": "mdc4_24", "s": "maths", "t": "Decimals", "l": 4, "q": "A bottle contains 1.75 litres. You pour out 0.65 litres. How much is left?", "o": ["1.00 l", "1.05 l", "1.10 l", "1.15 l"], "a": "1.10 l", "e": "1.75 - 0.65 = 1.10 litres"}, {"id": "mdc4_25", "s": "maths", "t": "Decimals", "l": 4, "q": "What is 7.2 divided by 0.09?", "o": ["8", "80", "800", "0.8"], "a": "80", "e": "7.2 / 0.09 = 720 / 9 = 80"}, {"id": "mdc4_26", "s": "maths", "t": "Decimals", "l": 4, "q": "Write 0.625 as a fraction in simplest form.", "o": ["625/1000", "5/8", "6/10", "1/2"], "a": "5/8", "e": "0.625 = 625/1000 = 5/8"}, {"id": "mdc4_27", "s": "maths", "t": "Decimals", "l": 4, "q": "4 items cost 14.60 pounds. What does 1 item cost?", "o": ["3.15", "3.50", "3.65", "3.70"], "a": "3.65", "e": "14.60 / 4 = 3.65"}, {"id": "mdc4_28", "s": "maths", "t": "Decimals", "l": 4, "q": "0.8 + 0.06 + 0.007 = ?", "o": ["0.867", "0.876", "0.768", "0.678"], "a": "0.867", "e": "0.800 + 0.060 + 0.007 = 0.867"}, {"id": "mdc4_29", "s": "maths", "t": "Decimals", "l": 4, "q": "A ribbon is 3.2 m long, cut into 8 equal pieces. How long is each piece in cm?", "o": ["4 cm", "40 cm", "400 cm", "0.4 cm"], "a": "40 cm", "e": "3.2 m / 8 = 0.4 m = 40 cm"}, {"id": "mdc4_30", "s": "maths", "t": "Decimals", "l": 4, "q": "Which is greatest: 0.3 squared, 0.09, 0.3, or 3/10?", "o": ["0.3 squared", "0.09", "0.3", "3/10"], "a": "0.3", "e": "0.3 squared = 0.09; 0.3 = 3/10 = 0.30 which is the largest"}, {"id": "mpc4_21", "s": "maths", "t": "Percentages", "l": 4, "q": "Increase 240 pounds by 15%.", "o": ["256", "264", "276", "284"], "a": "276", "e": "15% of 240 = 36; 240 + 36 = 276"}, {"id": "mpc4_22", "s": "maths", "t": "Percentages", "l": 4, "q": "A price drops from 80 pounds to 64 pounds. What is the percentage decrease?", "o": ["16%", "20%", "25%", "18%"], "a": "20%", "e": "Drop = 16; 16/80 x 100 = 20%"}, {"id": "mpc4_23", "s": "maths", "t": "Percentages", "l": 4, "q": "What is 35% of 160?", "o": ["52", "56", "58", "60"], "a": "56", "e": "10% = 16; 35% = 16 x 3.5 = 56"}, {"id": "mpc4_24", "s": "maths", "t": "Percentages", "l": 4, "q": "72 out of 90 students passed. What percentage passed?", "o": ["75%", "78%", "80%", "82%"], "a": "80%", "e": "72/90 x 100 = 80%"}, {"id": "mpc4_25", "s": "maths", "t": "Percentages", "l": 4, "q": "After a 20% increase, a price is 96 pounds. What was the original price?", "o": ["72", "76", "80", "84"], "a": "80", "e": "120% = 96; 1% = 0.80; 100% = 80"}, {"id": "mpc4_26", "s": "maths", "t": "Percentages", "l": 4, "q": "If VAT is 20%, what is the total cost of an item priced at 65 pounds?", "o": ["75", "77", "78", "80"], "a": "78", "e": "20% of 65 = 13; 65 + 13 = 78"}, {"id": "mpc4_27", "s": "maths", "t": "Percentages", "l": 4, "q": "Which is greater: 40% of 90 or 30% of 120?", "o": ["40% of 90", "30% of 120", "They are equal", "Cannot tell"], "a": "They are equal", "e": "40% of 90 = 36; 30% of 120 = 36 — they are equal"}, {"id": "mpc4_28", "s": "maths", "t": "Percentages", "l": 4, "q": "A school has 450 pupils. 54% are girls. How many boys are there?", "o": ["197", "207", "243", "253"], "a": "207", "e": "Girls: 54% of 450 = 243; Boys: 450 - 243 = 207"}, {"id": "mpc4_29", "s": "maths", "t": "Percentages", "l": 4, "q": "What is 12.5% of 400?", "o": ["40", "45", "50", "55"], "a": "50", "e": "12.5% = 1/8; 400 / 8 = 50"}, {"id": "mpc4_30", "s": "maths", "t": "Percentages", "l": 4, "q": "A coat costs 120 pounds. It is reduced by 25% then by a further 10%. What is the final price?", "o": ["78", "81", "84", "86"], "a": "81", "e": "25% off: 90; then 10% off 90 = 81"}, {"id": "mgs4_21", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "How many lines of symmetry does a regular hexagon have?", "o": ["4", "5", "6", "8"], "a": "6", "e": "A regular hexagon has 6 lines of symmetry"}, {"id": "mgs4_22", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "What is the order of rotational symmetry of a regular pentagon?", "o": ["3", "4", "5", "6"], "a": "5", "e": "A regular pentagon maps onto itself 5 times in a full rotation"}, {"id": "mgs4_23", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A shape has 8 vertices, 12 edges, and 6 faces. What is it?", "o": ["Triangular prism", "Cuboid", "Cylinder", "Hexagonal prism"], "a": "Cuboid", "e": "8 vertices, 12 edges, 6 faces matches a cuboid (or cube)"}, {"id": "mgs4_24", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "What is the interior angle of a regular octagon?", "o": ["108 degrees", "120 degrees", "135 degrees", "144 degrees"], "a": "135 degrees", "e": "Sum of interior angles = (8-2)x180 = 1080; each angle = 1080/8 = 135"}, {"id": "mgs4_25", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A triangle has sides 5 cm, 12 cm, and 13 cm. What type is it?", "o": ["Equilateral", "Isosceles", "Right-angled", "Obtuse"], "a": "Right-angled", "e": "5 squared + 12 squared = 25 + 144 = 169 = 13 squared — Pythagorean triple"}, {"id": "mgs4_26", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "Two congruent triangles with base 8 cm and height 5 cm form a parallelogram. What is its area?", "o": ["20 cm squared", "40 cm squared", "80 cm squared", "16 cm squared"], "a": "40 cm squared", "e": "Area of parallelogram = base x height = 8 x 5 = 40 cm squared"}, {"id": "mgs4_27", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A cylinder has radius 3 cm and height 10 cm. What is its volume? (use pi = 3.14)", "o": ["94.2", "188.4", "282.6", "314"], "a": "282.6", "e": "V = pi x r squared x h = 3.14 x 9 x 10 = 282.6 cm cubed"}, {"id": "mgs4_28", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A kite always has which property?", "o": ["All angles equal", "Two lines of symmetry", "One diagonal bisects the other at right angles", "It is a rhombus"], "a": "One diagonal bisects the other at right angles", "e": "A kite always has perpendicular diagonals, with one bisecting the other"}, {"id": "mgs4_29", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A regular polygon has interior angles of 120 degrees. How many sides does it have?", "o": ["4", "5", "6", "7"], "a": "6", "e": "(n-2)x180/n = 120 gives n=6, so it is a regular hexagon"}, {"id": "mgs4_30", "s": "maths", "t": "Geometry – Shapes", "l": 4, "q": "A square with side 10 cm has a circle of diameter 10 cm inside it. What is the area outside the circle? (pi = 3.14)", "o": ["11.5", "21.5", "51.5", "78.5"], "a": "21.5", "e": "Square area=100; Circle area=3.14x25=78.5; Shaded=100-78.5=21.5 cm squared"}, {"id": "man4_21", "s": "maths", "t": "Angles", "l": 4, "q": "Two angles of a triangle are 47 and 83 degrees. What is the third angle?", "o": ["40", "50", "60", "70"], "a": "50", "e": "180 - 47 - 83 = 50 degrees"}, {"id": "man4_22", "s": "maths", "t": "Angles", "l": 4, "q": "What is the sum of exterior angles of any convex polygon?", "o": ["180 degrees", "270 degrees", "360 degrees", "Depends on the polygon"], "a": "360 degrees", "e": "The sum of exterior angles of any convex polygon is always 360 degrees"}, {"id": "man4_23", "s": "maths", "t": "Angles", "l": 4, "q": "An isosceles triangle has a base angle of 65 degrees. What is the apex angle?", "o": ["40", "50", "55", "65"], "a": "50", "e": "Both base angles are 65. Apex = 180 - 65 - 65 = 50 degrees"}, {"id": "man4_24", "s": "maths", "t": "Angles", "l": 4, "q": "Two parallel lines cut by a transversal. One co-interior angle is 112 degrees. What is the other?", "o": ["68", "78", "112", "118"], "a": "68", "e": "Co-interior angles add to 180 degrees: 180 - 112 = 68"}, {"id": "man4_25", "s": "maths", "t": "Angles", "l": 4, "q": "A regular polygon has interior angles of 108 degrees. How many sides does it have?", "o": ["4", "5", "6", "7"], "a": "5", "e": "(n-2)x180/n = 108 gives n = 5 — a regular pentagon"}, {"id": "man4_26", "s": "maths", "t": "Angles", "l": 4, "q": "Angles 3x and 2x + 10 degrees are supplementary. What is x?", "o": ["28", "30", "32", "34"], "a": "34", "e": "3x + 2x + 10 = 180; 5x = 170; x = 34"}, {"id": "man4_27", "s": "maths", "t": "Angles", "l": 4, "q": "In a quadrilateral, three angles are 85, 110, and 95 degrees. What is the fourth?", "o": ["60", "65", "70", "75"], "a": "70", "e": "360 - 85 - 110 - 95 = 70 degrees"}, {"id": "man4_28", "s": "maths", "t": "Angles", "l": 4, "q": "Two straight lines intersect. One angle formed is 35 degrees. What is the vertically opposite angle?", "o": ["35", "55", "145", "180"], "a": "35", "e": "Vertically opposite angles are always equal"}, {"id": "man4_29", "s": "maths", "t": "Angles", "l": 4, "q": "A triangle has angles in the ratio 2:3:4. What are its angles?", "o": ["40, 60, 80", "30, 60, 90", "45, 60, 75", "36, 54, 72"], "a": "40, 60, 80", "e": "9 parts = 180 degrees; 1 part = 20 degrees; angles are 40, 60, and 80"}, {"id": "man4_30", "s": "maths", "t": "Angles", "l": 4, "q": "What is the value of an angle that is twice its supplement?", "o": ["60 degrees", "90 degrees", "120 degrees", "150 degrees"], "a": "120 degrees", "e": "x = 2(180-x); x = 360-2x; 3x=360; x=120 degrees"}, {"id": "mmu4_21", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A car travels at 60 km/h for 2.5 hours. How far does it travel?", "o": ["120 km", "135 km", "150 km", "165 km"], "a": "150 km", "e": "Distance = speed x time = 60 x 2.5 = 150 km"}, {"id": "mmu4_22", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A train departs at 09:47 and arrives at 12:15. How long is the journey?", "o": ["2 h 18 min", "2 h 28 min", "2 h 38 min", "2 h 48 min"], "a": "2 h 28 min", "e": "09:47 to 10:00 = 13 min; 10:00 to 12:15 = 2 h 15 min; total = 2 h 28 min"}, {"id": "mmu4_23", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "1 mile is approximately 1.6 km. How many miles is 56 km?", "o": ["28", "35", "42", "56"], "a": "35", "e": "56 / 1.6 = 35 miles"}, {"id": "mmu4_24", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Express 245 minutes in hours and minutes.", "o": ["3 h 45 min", "4 h 5 min", "4 h 25 min", "4 h 45 min"], "a": "4 h 5 min", "e": "245 / 60 = 4 remainder 5, so 4 hours and 5 minutes"}, {"id": "mmu4_25", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A rectangular room is 6.4 m by 4.5 m. What is its area in square centimetres?", "o": ["28.8", "2,880", "28,800", "288,000"], "a": "288,000", "e": "640 cm x 450 cm = 288,000 sq cm"}, {"id": "mmu4_26", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A recipe uses 750 ml of milk. How many full batches can be made from a 5-litre carton?", "o": ["5", "6", "7", "8"], "a": "6", "e": "5,000 / 750 = 6.66, so 6 full batches"}, {"id": "mmu4_27", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "Convert 3.5 kg to grams.", "o": ["35 g", "350 g", "3,500 g", "35,000 g"], "a": "3,500 g", "e": "1 kg = 1,000 g; 3.5 x 1,000 = 3,500 g"}, {"id": "mmu4_28", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A lorry carries 4.8 tonnes. How many 600 kg loads does it carry? (1 tonne = 1,000 kg)", "o": ["6", "7", "8", "10"], "a": "8", "e": "4,800 / 600 = 8 loads"}, {"id": "mmu4_29", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "How many millilitres are in 4.25 litres?", "o": ["425", "4,250", "42,500", "425,000"], "a": "4,250", "e": "1 litre = 1,000 ml; 4.25 x 1,000 = 4,250 ml"}, {"id": "mmu4_30", "s": "maths", "t": "Measurement & Units", "l": 4, "q": "A journey of 270 km is completed in 3 hours. What is the average speed?", "o": ["70 km/h", "80 km/h", "90 km/h", "100 km/h"], "a": "90 km/h", "e": "Speed = distance / time = 270 / 3 = 90 km/h"}, {"id": "mpa4_21", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A rectangle has perimeter 36 cm and one side is 10 cm. What is its area?", "o": ["80 cm sq", "90 cm sq", "100 cm sq", "160 cm sq"], "a": "80 cm sq", "e": "Other side = (36-20)/2 = 8 cm; Area = 10 x 8 = 80 cm sq"}, {"id": "mpa4_22", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "Find the area of a triangle with base 12 cm and height 9 cm.", "o": ["54 cm sq", "108 cm sq", "72 cm sq", "48 cm sq"], "a": "54 cm sq", "e": "Area = 1/2 x 12 x 9 = 54 cm sq"}, {"id": "mpa4_23", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A circle has radius 7 cm. What is its area? (use pi = 22/7)", "o": ["44", "154", "176", "308"], "a": "154", "e": "A = pi x r squared = 22/7 x 49 = 154 cm sq"}, {"id": "mpa4_24", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A 2 m wide path surrounds a 10 m x 6 m lawn. What is the area of the path?", "o": ["64 sq m", "72 sq m", "80 sq m", "96 sq m"], "a": "80 sq m", "e": "Outer rectangle = 14 x 10 = 140; Inner = 10 x 6 = 60; Path = 140 - 60 = 80 sq m"}, {"id": "mpa4_25", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A parallelogram has base 15 cm and height 8 cm. What is its area?", "o": ["90", "100", "110", "120"], "a": "120", "e": "Area = base x height = 15 x 8 = 120 cm sq"}, {"id": "mpa4_26", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A square has area 169 cm sq. What is its perimeter?", "o": ["48 cm", "52 cm", "56 cm", "64 cm"], "a": "52 cm", "e": "Side = root of 169 = 13 cm; Perimeter = 4 x 13 = 52 cm"}, {"id": "mpa4_27", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "An L-shaped room: overall 8 m x 6 m with a 3 m x 2 m corner cut out. What is the floor area?", "o": ["40 sq m", "42 sq m", "44 sq m", "48 sq m"], "a": "42 sq m", "e": "8x6 = 48; minus 3x2 = 6; 48 - 6 = 42 sq m"}, {"id": "mpa4_28", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A circle has circumference 44 cm. What is its diameter? (pi = 22/7)", "o": ["7 cm", "14 cm", "22 cm", "28 cm"], "a": "14 cm", "e": "C = pi x d; 44 = 22/7 x d; d = 44 x 7/22 = 14 cm"}, {"id": "mpa4_29", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "A trapezium has parallel sides of 7 cm and 11 cm, and height 6 cm. What is its area?", "o": ["48 cm sq", "54 cm sq", "60 cm sq", "66 cm sq"], "a": "54 cm sq", "e": "Area = 1/2 x (7+11) x 6 = 1/2 x 18 x 6 = 54 cm sq"}, {"id": "mpa4_30", "s": "maths", "t": "Perimeter & Area", "l": 4, "q": "What is the area of a rhombus with diagonals of 10 cm and 8 cm?", "o": ["18 sq cm", "40 sq cm", "80 sq cm", "20 sq cm"], "a": "40 sq cm", "e": "Area of rhombus = 1/2 x d1 x d2 = 1/2 x 10 x 8 = 40 sq cm"}, {"id": "mds4_21", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Find the mean of: 12, 17, 9, 14, 18.", "o": ["13", "14", "15", "16"], "a": "14", "e": "Sum = 70; Mean = 70 / 5 = 14"}, {"id": "mds4_22", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Find the median of: 5, 3, 8, 1, 9, 2, 7.", "o": ["3", "5", "7", "8"], "a": "5", "e": "Ordered: 1,2,3,5,7,8,9. Middle value is 5"}, {"id": "mds4_23", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "The range of 5 numbers is 12 and the smallest is 7. What is the largest?", "o": ["17", "18", "19", "20"], "a": "19", "e": "Largest = smallest + range = 7 + 12 = 19"}, {"id": "mds4_24", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "The mean of 4 numbers is 15. Three of them are 12, 18, and 14. What is the fourth?", "o": ["14", "16", "18", "20"], "a": "16", "e": "Total = 4x15 = 60; Fourth = 60 - 12 - 18 - 14 = 16"}, {"id": "mds4_25", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Find the mode of: 4, 7, 2, 7, 3, 9, 7, 2, 4.", "o": ["2", "4", "7", "9"], "a": "7", "e": "7 appears 3 times, which is the most frequent"}, {"id": "mds4_26", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A pie chart shows 25% for Maths. In a class of 32, how many chose Maths?", "o": ["6", "7", "8", "9"], "a": "8", "e": "25% of 32 = 8"}, {"id": "mds4_27", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Data set: 4, 6, 6, 8, 10, 10, 12. What is the difference between the mean and median?", "o": ["0", "1", "2", "3"], "a": "0", "e": "Sum=56; Mean=56/7=8; Median (4th value)=8. Difference=0"}, {"id": "mds4_28", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "A bar chart shows: Mon=8, Tue=12, Wed=10, Thu=6, Fri=14. What is the mean?", "o": ["9", "10", "11", "12"], "a": "10", "e": "Sum = 8+12+10+6+14 = 50; Mean = 50 / 5 = 10"}, {"id": "mds4_29", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "Temperatures for a week: 12, 14, 11, 16, 13, 15, 14. What is the range?", "o": ["3", "4", "5", "6"], "a": "5", "e": "Range = highest - lowest = 16 - 11 = 5"}, {"id": "mds4_30", "s": "maths", "t": "Data & Statistics", "l": 4, "q": "In a survey, 2/5 of 60 children preferred football. How many preferred other sports?", "o": ["24", "28", "36", "40"], "a": "36", "e": "Football = 2/5 x 60 = 24; Others = 60 - 24 = 36"}, {"id": "mps4_21", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A number is multiplied by 6, then 14 is subtracted, and the result is 40. What is the number?", "o": ["7", "8", "9", "10"], "a": "9", "e": "Reverse: 40 + 14 = 54; 54 / 6 = 9"}, {"id": "mps4_22", "s": "maths", "t": "Problem Solving", "l": 4, "q": "3 apples and 2 bananas cost 90p. 1 apple costs 20p. How much does 1 banana cost?", "o": ["12p", "15p", "18p", "20p"], "a": "15p", "e": "3 apples = 60p; 90 - 60 = 30p for 2 bananas; 30 / 2 = 15p"}, {"id": "mps4_23", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A train leaves at 8:35 am. The journey takes 2 hours 48 minutes. When does it arrive?", "o": ["11:13 am", "11:23 am", "11:33 am", "11:43 am"], "a": "11:23 am", "e": "8:35 + 2h = 10:35; 10:35 + 48 min = 11:23 am"}, {"id": "mps4_24", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A bag has red and blue balls in ratio 3:5. There are 24 red balls. How many blue?", "o": ["32", "36", "40", "45"], "a": "40", "e": "24 / 3 = 8 per part; 5 x 8 = 40 blue balls"}, {"id": "mps4_25", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Sarah spends 2/5 of her pocket money and saves 6 pounds. How much does she have altogether?", "o": ["8", "10", "12", "15"], "a": "10", "e": "She saves 3/5 = 6; 1/5 = 2; total = 10 pounds"}, {"id": "mps4_26", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A rectangle is 3 times as long as it is wide. Its perimeter is 48 cm. What is its area?", "o": ["96 sq cm", "108 sq cm", "120 sq cm", "128 sq cm"], "a": "108 sq cm", "e": "2(w + 3w) = 48; w=6 cm, l=18 cm; Area = 6x18 = 108 sq cm"}, {"id": "mps4_27", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Two numbers have a sum of 84 and a difference of 12. What is the larger number?", "o": ["42", "46", "48", "52"], "a": "48", "e": "Larger = (84+12)/2 = 96/2 = 48"}, {"id": "mps4_28", "s": "maths", "t": "Problem Solving", "l": 4, "q": "A cinema sells 240 tickets: 1/3 adult, 1/4 child, the rest concession. How many concession tickets?", "o": ["80", "90", "100", "110"], "a": "100", "e": "Adult=80, Child=60; Concession=240-80-60=100"}, {"id": "mps4_29", "s": "maths", "t": "Problem Solving", "l": 4, "q": "If today is Wednesday, what day will it be in 100 days?", "o": ["Monday", "Tuesday", "Wednesday", "Friday"], "a": "Friday", "e": "100 / 7 = 14 remainder 2; Wednesday + 2 days = Friday"}, {"id": "mps4_30", "s": "maths", "t": "Problem Solving", "l": 4, "q": "Pencils cost 15p each, pens cost 40p each. James spends exactly 1.70 pounds on both. How many of each?", "o": ["2 pencils 3 pens", "3 pencils 3 pens", "6 pencils 2 pens", "2 pencils 4 pens"], "a": "6 pencils 2 pens", "e": "6x15 + 2x40 = 90 + 80 = 170p"}, {"id": "evo4_21", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does TENACIOUS mean?", "o": ["Shy and quiet", "Holding firmly to a goal", "Quick to anger", "Easily confused"], "a": "Holding firmly to a goal", "e": "Tenacious means persistent and determined"}, {"id": "evo4_22", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does AMBIGUOUS mean?", "o": ["Clearly stated", "Open to more than one meaning", "Completely wrong", "Extremely large"], "a": "Open to more than one meaning", "e": "Ambiguous means having multiple possible interpretations"}, {"id": "evo4_23", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does ELOQUENT mean?", "o": ["Clumsy and awkward", "Fluent and persuasive in speech", "Loud and boisterous", "Silent"], "a": "Fluent and persuasive in speech", "e": "Eloquent describes skilful, expressive communication"}, {"id": "evo4_24", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which word means to make something worse?", "o": ["Ameliorate", "Exacerbate", "Placate", "Mitigate"], "a": "Exacerbate", "e": "Exacerbate means to intensify or worsen a problem"}, {"id": "evo4_25", "s": "english", "t": "Vocabulary", "l": 4, "q": "FRUGAL most closely means:", "o": ["Generous", "Wasteful", "Careful with money", "Dishonest"], "a": "Careful with money", "e": "Frugal means economical and not wasteful"}, {"id": "evo4_26", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does BENEVOLENT mean?", "o": ["Kind and generous", "Strict and firm", "Angry and hostile", "Withdrawn"], "a": "Kind and generous", "e": "Benevolent means well-meaning and charitable"}, {"id": "evo4_27", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does EPHEMERAL mean?", "o": ["Permanent", "Short-lived", "Enormous", "Powerful"], "a": "Short-lived", "e": "Ephemeral means lasting for only a short time"}, {"id": "evo4_28", "s": "english", "t": "Vocabulary", "l": 4, "q": "PRAGMATIC most closely means:", "o": ["Idealistic", "Dealing with things practically", "Overly emotional", "Theoretical"], "a": "Dealing with things practically", "e": "Pragmatic means sensible and realistic"}, {"id": "evo4_29", "s": "english", "t": "Vocabulary", "l": 4, "q": "What does AUDACIOUS mean?", "o": ["Timid and fearful", "Bold and daring", "Quiet and modest", "Clumsy"], "a": "Bold and daring", "e": "Audacious means showing a willingness to take bold risks"}, {"id": "evo4_30", "s": "english", "t": "Vocabulary", "l": 4, "q": "Which word means to formally charge someone with a crime?", "o": ["Acquit", "Indict", "Pardon", "Absolve"], "a": "Indict", "e": "To indict means to formally charge with a serious crime"}, {"id": "epu4_21", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses a semicolon correctly?", "o": ["I like cats; and dogs.", "She ran quickly; she was late for school.", "He said; hello.", "We went shopping; but it was closed."], "a": "She ran quickly; she was late for school.", "e": "Semicolons join two independent clauses"}, {"id": "epu4_22", "s": "english", "t": "Punctuation", "l": 4, "q": "Where does the apostrophe go in: The childrens playground was muddy.", "o": ["children's playground", "childrens' playground", "childrens playground", "children playground's"], "a": "children's playground", "e": "Children is already plural; add apostrophe + s for possession"}, {"id": "epu4_23", "s": "english", "t": "Punctuation", "l": 4, "q": "Which uses a colon correctly?", "o": ["She loves: swimming.", "There were three problems: noise, mess, and cost.", "He ran: very fast.", "I want: to go home."], "a": "There were three problems: noise, mess, and cost.", "e": "Colons introduce lists or explanations after a complete clause"}, {"id": "epu4_24", "s": "english", "t": "Punctuation", "l": 4, "q": "Choose the correctly punctuated sentence.", "o": ["However she kept going.", "However, she kept going.", "However she kept, going.", "However she, kept going."], "a": "However, she kept going.", "e": "Fronted adverbials like however are followed by a comma"}, {"id": "epu4_25", "s": "english", "t": "Punctuation", "l": 4, "q": "Which is the correct possessive form for multiple bosses?", "o": ["boss's decision", "bosses decision", "bosses' decision", "bos's decision"], "a": "bosses' decision", "e": "For plurals ending in s, add only an apostrophe after the s"}, {"id": "epu4_26", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence correctly uses brackets?", "o": ["She (went to the shop) yesterday.", "The cat (which was stripy) sat on the mat.", "He (run) to school.", "They (will) arrive soon."], "a": "The cat (which was stripy) sat on the mat.", "e": "Brackets add parenthetical information that could be removed without changing the main meaning"}, {"id": "epu4_27", "s": "english", "t": "Punctuation", "l": 4, "q": "What is a comma splice?", "o": ["Using a comma before a conjunction", "Joining two main clauses with only a comma", "Adding a comma after an adverbial", "Using a comma in a list"], "a": "Joining two main clauses with only a comma", "e": "A comma splice incorrectly joins two independent clauses with just a comma"}, {"id": "epu4_28", "s": "english", "t": "Punctuation", "l": 4, "q": "Which sentence uses a dash for emphasis correctly?", "o": ["She ran — to the shops.", "The answer — was wrong.", "It was the best day — of the whole summer.", "He said— hello."], "a": "It was the best day — of the whole summer.", "e": "A dash before additional information adds emphasis and drama"}, {"id": "epu4_29", "s": "english", "t": "Punctuation", "l": 4, "q": "When is an ellipsis used?", "o": ["To end every sentence", "To show trailing off, suspense, or omission", "Instead of a comma", "To start a new paragraph"], "a": "To show trailing off, suspense, or omission", "e": "Ellipsis (...) creates a pause, shows something is left out, or builds suspense"}, {"id": "epu4_30", "s": "english", "t": "Punctuation", "l": 4, "q": "What punctuation is used for a quote within a quote when using double speech marks?", "o": ["Double inverted commas", "Single inverted commas", "Brackets", "Dash"], "a": "Single inverted commas", "e": "Single quotes are used for quotes within quotes when double quotes mark the main speech"}, {"id": "egr4_21", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence is in the passive voice?", "o": ["The dog bit the boy.", "The boy was bitten by the dog.", "The boy ran from the dog.", "The dog chased the boy."], "a": "The boy was bitten by the dog.", "e": "Passive voice: the subject receives the action rather than doing it"}, {"id": "egr4_22", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the subjunctive mood in: If I were you, I would study more.", "o": ["were", "would", "study", "more"], "a": "were", "e": "The subjunctive uses were instead of was for hypothetical situations"}, {"id": "egr4_23", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence contains a relative clause?", "o": ["She ran quickly.", "The book, which was old, fell apart.", "He is very tall.", "We went home."], "a": "The book, which was old, fell apart.", "e": "A relative clause begins with a relative pronoun such as who, which, or that"}, {"id": "egr4_24", "s": "english", "t": "Grammar", "l": 4, "q": "What are words like however, therefore, and consequently called?", "o": ["Prepositions", "Conjunctions", "Conjunctive adverbials", "Relative pronouns"], "a": "Conjunctive adverbials", "e": "These are conjunctive adverbs used to connect and sequence ideas"}, {"id": "egr4_25", "s": "english", "t": "Grammar", "l": 4, "q": "Which contains a modal verb?", "o": ["She runs every day.", "He could have won the race.", "They laughed loudly.", "We ate dinner."], "a": "He could have won the race.", "e": "Could is a modal verb expressing possibility or ability"}, {"id": "egr4_26", "s": "english", "t": "Grammar", "l": 4, "q": "What is the function of the word SWIFTLY in: She ran swiftly.", "o": ["Adjective", "Adverb", "Verb", "Noun"], "a": "Adverb", "e": "Swiftly modifies the verb ran, so it is an adverb"}, {"id": "egr4_27", "s": "english", "t": "Grammar", "l": 4, "q": "Which sentence uses the present perfect tense?", "o": ["She runs every day.", "She ran to the shops.", "She has run five kilometres.", "She was running when it rained."], "a": "She has run five kilometres.", "e": "Present perfect: has/have + past participle, linking past action to present"}, {"id": "egr4_28", "s": "english", "t": "Grammar", "l": 4, "q": "Identify the subordinate clause: Although it was raining, we played outside.", "o": ["Although it was raining", "we played outside", "was raining", "we played"], "a": "Although it was raining", "e": "The subordinate clause depends on the main clause and cannot stand alone"}, {"id": "egr4_29", "s": "english", "t": "Grammar", "l": 4, "q": "Which is an example of direct speech?", "o": ["He said that he was tired.", "She asked where I had been.", "Tom shouted, Watch out!", "They wondered if it would rain."], "a": "Tom shouted, Watch out!", "e": "Direct speech uses the exact words spoken, placed in quotation marks"}, {"id": "egr4_30", "s": "english", "t": "Grammar", "l": 4, "q": "Choose the correct form: The committee (has/have) made its decision.", "o": ["has", "have", "had", "having"], "a": "has", "e": "Collective nouns like committee take singular verbs in British English when acting as one unit"}, {"id": "esp4_21", "s": "english", "t": "Spelling", "l": 4, "q": "Which is the correct spelling?", "o": ["accomodate", "accommodate", "accommadate", "acomodate"], "a": "accommodate", "e": "Accommodate has double c and double m"}, {"id": "esp4_22", "s": "english", "t": "Spelling", "l": 4, "q": "Choose the correctly spelled word:", "o": ["occurance", "occurrence", "ocurrence", "occurrance"], "a": "occurrence", "e": "Occurrence has double c and double r"}, {"id": "esp4_23", "s": "english", "t": "Spelling", "l": 4, "q": "Which word is spelled correctly?", "o": ["necessary", "neccesary", "neccessary", "necesary"], "a": "necessary", "e": "Necessary has one c and double s"}, {"id": "esp4_24", "s": "english", "t": "Spelling", "l": 4, "q": "Spot the correct spelling:", "o": ["seperate", "separate", "separrate", "seprate"], "a": "separate", "e": "Separate: sep-a-rate — there is a rat inside separate!"}, {"id": "esp4_25", "s": "english", "t": "Spelling", "l": 4, "q": "Which is correct?", "o": ["questionaire", "questionnare", "questionnaire", "questionairre"], "a": "questionnaire", "e": "Questionnaire has double n and ends in -aire"}, {"id": "esp4_26", "s": "english", "t": "Spelling", "l": 4, "q": "Choose the correctly spelled word:", "o": ["embarras", "embarass", "embarrass", "embarress"], "a": "embarrass", "e": "Embarrass has double r and double s"}, {"id": "esp4_27", "s": "english", "t": "Spelling", "l": 4, "q": "Which is correct?", "o": ["priviledge", "privelege", "privilege", "privilige"], "a": "privilege", "e": "Privilege: priv-i-lege — no d"}, {"id": "esp4_28", "s": "english", "t": "Spelling", "l": 4, "q": "Spot the correct spelling:", "o": ["concientious", "consciencious", "conscientious", "consientious"], "a": "conscientious", "e": "Conscientious: con-sci-en-tious"}, {"id": "esp4_29", "s": "english", "t": "Spelling", "l": 4, "q": "Which word is spelled correctly?", "o": ["pharoah", "phaoarh", "pharaoh", "pharoah"], "a": "pharaoh", "e": "Pharaoh: P-H-A-R-A-O-H"}, {"id": "esp4_30", "s": "english", "t": "Spelling", "l": 4, "q": "Choose the correct spelling:", "o": ["beleive", "believe", "beleave", "belive"], "a": "believe", "e": "Believe: bel-ie-ve"}, {"id": "evr4_21", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the two words most similar in meaning: JOVIAL, MELANCHOLY, MERRY, SOMBRE, BRIGHT", "o": ["JOVIAL and MELANCHOLY", "JOVIAL and MERRY", "MELANCHOLY and SOMBRE", "MERRY and SOMBRE"], "a": "JOVIAL and MERRY", "e": "Jovial and Merry both mean cheerful and happy"}, {"id": "evr4_22", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which number comes next: 2, 6, 18, 54, ?", "o": ["108", "144", "162", "216"], "a": "162", "e": "Each term is multiplied by 3: 54 x 3 = 162"}, {"id": "evr4_23", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "BARK is to TREE as SKIN is to:", "o": ["Hair", "Body", "Bone", "Animal"], "a": "Animal", "e": "Bark is the outer covering of a tree; skin is the outer covering of an animal"}, {"id": "evr4_24", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word is hidden inside STATEMENT?", "o": ["STEM", "STATE", "TAME", "STEM"], "a": "STATE", "e": "STATE is found at the start of STATEMENT — letters S-T-A-T-E"}, {"id": "evr4_25", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "If PENCIL is coded as QFODKM (each letter moves forward 1), what is PAPER in the same code?", "o": ["QBQFS", "QAQER", "OBODS", "PAPFR"], "a": "QBQFS", "e": "P+1=Q, A+1=B, P+1=Q, E+1=F, R+1=S = QBQFS"}, {"id": "evr4_26", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which word completes both: OVER___ and ___BOARD?", "o": ["CARD", "SEA", "SHIP", "HEAD"], "a": "SEA", "e": "OVERSEAS and SEABOARD"}, {"id": "evr4_27", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Find the odd one out: MAPLE, OAK, DAISY, BIRCH, ELM", "o": ["MAPLE", "OAK", "DAISY", "ELM"], "a": "DAISY", "e": "All others are trees; daisy is a flower"}, {"id": "evr4_28", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Rearrange the letters ENOISC to make a word.", "o": ["NOICES", "COINED", "COSINE", "ICONES"], "a": "COSINE", "e": "ENOISC rearranges to COSINE — a trigonometry term"}, {"id": "evr4_29", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which number is the odd one out: 16, 36, 49, 64, 100?", "o": ["16", "36", "49", "64"], "a": "49", "e": "49 is 7 squared — the only odd number among the square numbers listed"}, {"id": "evr4_30", "s": "english", "t": "Verbal Reasoning", "l": 4, "q": "Which two words are most opposite in meaning: FRUGAL, LAVISH, THRIFTY, CAREFUL?", "o": ["FRUGAL and THRIFTY", "FRUGAL and LAVISH", "THRIFTY and LAVISH", "CAREFUL and LAVISH"], "a": "FRUGAL and LAVISH", "e": "Frugal means economical/careful with money; lavish means extravagant"}, {"id": "esa4_21", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which is a synonym for INDOLENT?", "o": ["Energetic", "Lazy", "Anxious", "Careful"], "a": "Lazy", "e": "Indolent means avoiding activity — lazy"}, {"id": "esa4_22", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "What is an antonym for SCARCITY?", "o": ["Rarity", "Shortage", "Abundance", "Lack"], "a": "Abundance", "e": "Scarcity means shortage; abundance means plenty"}, {"id": "esa4_23", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Choose the synonym for AMIABLE.", "o": ["Hostile", "Friendly", "Careless", "Rude"], "a": "Friendly", "e": "Amiable means pleasant and friendly"}, {"id": "esa4_24", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "What is an antonym for VERBOSE?", "o": ["Wordy", "Concise", "Detailed", "Elaborate"], "a": "Concise", "e": "Verbose means using too many words; concise means brief and clear"}, {"id": "esa4_25", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word is a synonym for TURBULENT?", "o": ["Calm", "Stormy", "Peaceful", "Gentle"], "a": "Stormy", "e": "Turbulent means moving unsteadily or chaotically"}, {"id": "esa4_26", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find an antonym for TRANSPARENT.", "o": ["Clear", "Obvious", "Opaque", "Visible"], "a": "Opaque", "e": "Transparent means see-through; opaque means not transparent"}, {"id": "esa4_27", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which is a synonym for DILIGENT?", "o": ["Careless", "Hardworking", "Lazy", "Reckless"], "a": "Hardworking", "e": "Diligent means careful and hardworking"}, {"id": "esa4_28", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Find the antonym for SERENE.", "o": ["Peaceful", "Tranquil", "Agitated", "Quiet"], "a": "Agitated", "e": "Serene means calm; agitated means restless or disturbed"}, {"id": "esa4_29", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "Which word means the same as REPRIMAND?", "o": ["Praise", "Scold", "Reward", "Ignore"], "a": "Scold", "e": "To reprimand means to express sharp disapproval"}, {"id": "esa4_30", "s": "english", "t": "Synonyms & Antonyms", "l": 4, "q": "What is an antonym for OPTIMISTIC?", "o": ["Hopeful", "Cheerful", "Pessimistic", "Confident"], "a": "Pessimistic", "e": "Optimistic means positive; pessimistic means negative about the future"}, {"id": "ess4_21", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses a fronted adverbial?", "o": ["She ran quickly.", "Quickly, she ran to the door.", "The quick girl ran.", "She was quick."], "a": "Quickly, she ran to the door.", "e": "A fronted adverbial comes before the subject, followed by a comma"}, {"id": "ess4_22", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the sentence type: Although she was tired, she finished the race.", "o": ["Simple", "Compound", "Complex", "Compound-complex"], "a": "Complex", "e": "A complex sentence has one main clause and at least one subordinate clause"}, {"id": "ess4_23", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses an embedded relative clause correctly?", "o": ["The girl, who won the race, smiled.", "The girl who won, the race smiled.", "The girl who won the race, smiled.", "The girl, who won, the race smiled."], "a": "The girl, who won the race, smiled.", "e": "An embedded relative clause is set off by commas and adds extra information"}, {"id": "ess4_24", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is the purpose of (exhausted from the voyage) in: The captain (exhausted from the voyage) gave his final orders.", "o": ["It is the main verb", "It adds extra information about the captain", "It states the main action", "It introduces a new topic"], "a": "It adds extra information about the captain", "e": "Parenthetical phrases add non-essential detail about the subject"}, {"id": "ess4_25", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is a compound-complex sentence?", "o": ["Two simple sentences joined by and", "A sentence with one main clause only", "Two main clauses and at least one subordinate clause", "A sentence with no conjunctions"], "a": "Two main clauses and at least one subordinate clause", "e": "Compound-complex sentences combine compound and complex structures"}, {"id": "ess4_26", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Identify the object in: The scientist discovered a new element.", "o": ["The scientist", "discovered", "a new element", "new"], "a": "a new element", "e": "The object receives the action of the verb — the scientist discovered WHAT? A new element"}, {"id": "ess4_27", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence uses a participle phrase correctly?", "o": ["Running fast, she the race won.", "She won the race, running fast.", "Having trained for weeks, she won the race.", "The race running, she was won."], "a": "Having trained for weeks, she won the race.", "e": "A participle phrase with having shows a completed action before the main one"}, {"id": "ess4_28", "s": "english", "t": "Sentence Structure", "l": 4, "q": "What is the term for a verb form used as a noun, e.g. Swimming is my hobby?", "o": ["Infinitive", "Gerund", "Participle", "Clause"], "a": "Gerund", "e": "A gerund is a verb ending in -ing used as a noun"}, {"id": "ess4_29", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Choose the sentence with correct subject-verb agreement.", "o": ["Neither the boys nor the girl are ready.", "Neither the boys nor the girl is ready.", "Neither the boy nor the girls is ready.", "The boy and girl is ready."], "a": "Neither the boys nor the girl is ready.", "e": "With neither...nor, the verb agrees with the nearest subject (girl = singular = is)"}, {"id": "ess4_30", "s": "english", "t": "Sentence Structure", "l": 4, "q": "Which sentence is written in the second person?", "o": ["I ran to the park.", "She ran to the park.", "You should run to the park.", "They ran to the park."], "a": "You should run to the park.", "e": "Second person uses you — addressing the reader directly"}, {"id": "erc4_21", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Despite the torrential rain, the explorer pressed on, driven by an insatiable curiosity. What does insatiable suggest?", "o": ["She was foolish", "Her desire could not be satisfied", "She was afraid of rain", "She was very cold"], "a": "Her desire could not be satisfied", "e": "Insatiable means impossible to satisfy — showing limitless curiosity"}, {"id": "erc4_22", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "The news spread like wildfire through the village. What technique is used?", "o": ["Personification", "Metaphor", "Simile", "Alliteration"], "a": "Simile", "e": "A simile compares using like or as — spread LIKE wildfire"}, {"id": "erc4_23", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "The abandoned house watched over the village with hollow, dark eyes. What technique is used?", "o": ["Simile", "Alliteration", "Personification", "Hyperbole"], "a": "Personification", "e": "Giving the house human qualities — watching, eyes — is personification"}, {"id": "erc4_24", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "What is the author's purpose in a text that presents both sides of an argument fairly?", "o": ["To entertain", "To persuade to one view", "To inform in a balanced way", "To describe personal experience"], "a": "To inform in a balanced way", "e": "Balanced argument texts present multiple perspectives to inform, not persuade"}, {"id": "erc4_25", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "A shadow moved. She froze. Footsteps. Getting closer. Which technique creates tension?", "o": ["Long flowing sentences", "Short fragmented sentences", "Rhetorical questions", "Alliteration"], "a": "Short fragmented sentences", "e": "Short sentences speed up pace and create tension and suspense"}, {"id": "erc4_26", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "It was, without doubt, the worst day of my life. This is an example of:", "o": ["Third-person narrative", "First-person narrative", "Reported speech", "An imperative"], "a": "First-person narrative", "e": "My life uses first-person perspective"}, {"id": "erc4_27", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "The detective catalogued every detail of the room. What does catalogued imply about the detective?", "o": ["Was very busy", "Systematically recorded information", "Was nervous", "Liked shopping"], "a": "Systematically recorded information", "e": "Cataloguing means organising systematically — showing the detective is methodical"}, {"id": "erc4_28", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "When an author reveals thoughts to the reader that other characters do not know, this is called:", "o": ["Dramatic irony", "A flashback", "A cliffhanger", "An allegory"], "a": "Dramatic irony", "e": "Dramatic irony is when the audience knows something characters do not"}, {"id": "erc4_29", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "Could anything be more magnificent than the sunrise over the mountains? This is a:", "o": ["Statement", "Rhetorical question", "Command", "Exclamation"], "a": "Rhetorical question", "e": "A rhetorical question is asked for effect — no answer is expected"}, {"id": "erc4_30", "s": "english", "t": "Reading Comprehension", "l": 4, "q": "A writer uses the word crimson instead of red. What effect does this create?", "o": ["Makes it less vivid", "Creates a more precise and evocative image", "Makes it harder to understand", "Has no effect"], "a": "Creates a more precise and evocative image", "e": "Specific word choices like crimson create richer, more precise imagery than generic words"}
]`);
